            <Divider key={`${group.label}-divider`} />,
          ])}
        </Menu>
      )}

      {/* Mobile Drawer */}
      <Drawer
        anchor="left"
        open={mobileMenuOpen}
        onClose={closeMobileMenu}
        sx={{
          '& .MuiDrawer-paper': {
            width: isMobile ? '280px' : '320px',
            backgroundColor: 'background.paper',
          },
        }}
      >
        <Box sx={{ p: 2, borderBottom: 1, borderColor: 'divider' }}>
          <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
            <Typography variant="h6" sx={{ fontWeight: 'bold' }}>
              Navigation
            </Typography>
            <IconButton onClick={closeMobileMenu}>
              <CloseIcon />
            </IconButton>
          </Box>
          {tenant && (
            <Chip
              label={tenant.name}
              size="small"
              color="primary"
              sx={{ mt: 1 }}
            />
          )}
        </Box>

        <Box sx={{ overflow: 'auto', flexGrow: 1 }}>
          {renderNavigationItems()}
        </Box>
      </Drawer>
    </>
  );
};

import React, { useState, useEffect } from 'react';
import {
  Box,
  Typography,
  Paper,
  Switch,
  FormControlLabel,
  TextField,
  Button,
  Grid,
  Chip,
  Divider,
  Alert,
  CircularProgress,
  Select,
  MenuItem,
  FormControl,
  InputLabel,
} from '@mui/material';
import { TimePicker } from '@mui/x-date-pickers/TimePicker';
import { LocalizationProvider } from '@mui/x-date-pickers/LocalizationProvider';
import { AdapterDateFns } from '@mui/x-date-pickers/AdapterDateFns';
import { useNotificationAPI, UserNotificationPreferences } from '../hooks/useNotificationAPI';

interface NotificationPreferencesProps {
  userId: string;
  onPreferencesUpdated?: (preferences: UserNotificationPreferences) => void;
}

export const NotificationPreferences: React.FC<NotificationPreferencesProps> = ({
  userId,
  onPreferencesUpdated
}) => {
  const [preferences, setPreferences] = useState<UserNotificationPreferences | null>(null);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState(false);

  const { getUserPreferences, updateUserPreferences } = useNotificationAPI();

  const loadPreferences = React.useCallback(async () => {
    try {
      setLoading(true);
      const data = await getUserPreferences(userId);
      setPreferences(data);
      setError(null);
    } catch (err) {
      setError('Failed to load notification preferences');
      import('../utils/devLogger').then(({ devError }) => devError('Error loading preferences:', err)).catch(() => {});
    } finally {
      setLoading(false);
    }
  }, [userId, getUserPreferences]);

  useEffect(() => {
    loadPreferences();
  }, [loadPreferences]);

  const handleSave = async () => {
    if (!preferences) return;

      try {
        setSaving(true);
        setError(null);
        await updateUserPreferences(userId, {
          ...preferences,
        });
        setSuccess(true);
        onPreferencesUpdated?.(preferences);

        // Hide success message after 3 seconds
        setTimeout(() => setSuccess(false), 3000);
      } catch (err) {
        setError('Failed to save notification preferences');
        import('../utils/devLogger').then(({ devError }) => devError('Error saving preferences:', err)).catch(() => {});
      } finally {
        setSaving(false);
      }
  };

  const handleChannelToggle = (channel: string, enabled: boolean) => {
    if (!preferences) return;

    setPreferences({
      ...preferences,
      [channel]: enabled,
      channel_preferences: {
        ...preferences.channel_preferences,
        [channel]: enabled,
      },
    });
  };

  const handleTypePreferenceChange = (type: string, enabled: boolean) => {
    if (!preferences) return;

    setPreferences({
      ...preferences,
      type_preferences: {
        ...preferences.type_preferences,
        [type]: enabled,
      },
    });
  };

  const handleFrequencyChange = (type: string, frequency: string) => {
    if (!preferences) return;

    setPreferences({
      ...preferences,
      frequency_preferences: {
        ...preferences.frequency_preferences,
        [type]: frequency,
      },
    });
  };

  const handleQuietHoursChange = (field: 'start' | 'end', time: Date | null) => {
    if (!preferences || !time) return;

    const timeString = time.toTimeString().slice(0, 5); // HH:MM format

    setPreferences({
      ...preferences,
      [field === 'start' ? 'quiet_hours_start' : 'quiet_hours_end']: timeString,
    });
  };

  if (loading) {
    return (
      <Box sx={{ display: 'flex', justifyContent: 'center', p: 4 }}>
        <CircularProgress />
      </Box>
    );
  }

  if (!preferences) {
    return (
      <Alert severity="error">
        Failed to load notification preferences. Please try again.
      </Alert>
    );
  }

  return (
    <LocalizationProvider dateAdapter={AdapterDateFns}>
      <Paper sx={{ p: 3, maxWidth: 800, mx: 'auto' }}>
        <Typography variant="h5" gutterBottom>
          Notification Preferences
        </Typography>
        <Typography variant="body2" color="text.secondary" sx={{ mb: 3 }}>
          Customize how and when you receive notifications
        </Typography>

        {error && (
          <Alert severity="error" sx={{ mb: 2 }}>
            {error}
          </Alert>
        )}

        {success && (
          <Alert severity="success" sx={{ mb: 2 }}>
            Preferences saved successfully!
          </Alert>
        )}

        <Grid container spacing={3}>
          {/* Channel Preferences */}
          <Grid item xs={12}>
            <Typography variant="h6" gutterBottom>
              Notification Channels
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
              Choose which channels you want to receive notifications through
            </Typography>

            <Box sx={{ display: 'flex', flexDirection: 'column', gap: 2 }}>
              <FormControlLabel
                control={
                  <Switch
                    checked={preferences.email_enabled}
                    onChange={(e) => handleChannelToggle('email_enabled', e.target.checked)}
                  />
                }
                label="Email Notifications"
              />

              <FormControlLabel
                control={
                  <Switch
                    checked={preferences.sms_enabled}
                    onChange={(e) => handleChannelToggle('sms_enabled', e.target.checked)}
                  />
                }
                label="SMS Notifications"
              />

              <FormControlLabel
                control={
                  <Switch
                    checked={preferences.push_enabled}
                    onChange={(e) => handleChannelToggle('push_enabled', e.target.checked)}
                  />
                }
                label="Push Notifications"
              />

              <FormControlLabel
                control={
                  <Switch
                    checked={preferences.in_app_enabled}
                    onChange={(e) => handleChannelToggle('in_app_enabled', e.target.checked)}
                  />
                }
                label="In-App Notifications"
              />
            </Box>
          </Grid>

          <Grid item xs={12}>
            <Divider />
          </Grid>

          {/* Quiet Hours */}
          <Grid item xs={12}>
            <Typography variant="h6" gutterBottom>
              Quiet Hours
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
              Set times when you don't want to receive notifications
            </Typography>

            <Box sx={{ display: 'flex', gap: 2, alignItems: 'center' }}>
              <TimePicker
                label="Start Time"
                value={preferences.quiet_hours_start ? new Date(`1970-01-01T${preferences.quiet_hours_start}`) : null}
                onChange={(time) => handleQuietHoursChange('start', time)}
                slotProps={{
                  textField: {
                    helperText: 'Start of quiet hours',
                  },
                }}
              />

              <Typography>to</Typography>

              <TimePicker
                label="End Time"
                value={preferences.quiet_hours_end ? new Date(`1970-01-01T${preferences.quiet_hours_end}`) : null}
                onChange={(time) => handleQuietHoursChange('end', time)}
                slotProps={{
                  textField: {
                    helperText: 'End of quiet hours',
                  },
                }}
              />
            </Box>
          </Grid>

          <Grid item xs={12}>
            <Divider />
          </Grid>

          {/* Notification Types */}
          <Grid item xs={12}>
            <Typography variant="h6" gutterBottom>
              Notification Types
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
              Choose which types of notifications you want to receive
            </Typography>

            <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 2 }}>
              {Object.entries(preferences.type_preferences).map(([type, enabled]) => (
                <FormControlLabel
                  key={type}
                  control={
                    <Switch
                      checked={enabled}
                      onChange={(e) => handleTypePreferenceChange(type, e.target.checked)}
                    />
                  }
                  label={type.charAt(0).toUpperCase() + type.slice(1).replace('_', ' ')}
                />
              ))}
            </Box>
          </Grid>

          <Grid item xs={12}>
            <Divider />
          </Grid>

          {/* Frequency Preferences */}
          <Grid item xs={12}>
            <Typography variant="h6" gutterBottom>
              Notification Frequency
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
              Set how often you want to receive different types of notifications
            </Typography>

            <Box sx={{ display: 'flex', flexDirection: 'column', gap: 2 }}>
              {Object.entries(preferences.frequency_preferences).map(([type, frequency]) => (
                <Box key={type} sx={{ display: 'flex', alignItems: 'center', gap: 2 }}>
                  <Typography sx={{ minWidth: 120 }}>
                    {type.charAt(0).toUpperCase() + type.slice(1).replace('_', ' ')}:
                  </Typography>
                  <FormControl size="small" sx={{ minWidth: 120 }}>
                    <Select
                      value={frequency}
                      onChange={(e) => handleFrequencyChange(type, e.target.value)}
                    >
                      <MenuItem value="immediate">Immediate</MenuItem>
                      <MenuItem value="hourly">Hourly</MenuItem>
                      <MenuItem value="daily">Daily</MenuItem>
                      <MenuItem value="weekly">Weekly</MenuItem>
                      <MenuItem value="never">Never</MenuItem>
                    </Select>
                  </FormControl>
                </Box>
              ))}
            </Box>
          </Grid>

          <Grid item xs={12}>
            <Divider />
          </Grid>

          {/* Timezone */}
          <Grid item xs={12} sm={6}>
            <TextField
              fullWidth
              label="Timezone"
              value={preferences.timezone}
              onChange={(e) => setPreferences({ ...preferences, timezone: e.target.value })}
              helperText="Your timezone for scheduling notifications"
            />
          </Grid>

          {/* Save Button */}
          <Grid item xs={12}>
            <Box sx={{ display: 'flex', justifyContent: 'flex-end', gap: 2 }}>
              <Button
                variant="outlined"
                onClick={loadPreferences}
                disabled={loading}
              >
                Reset
              </Button>
              <Button
                variant="contained"
                onClick={handleSave}
                disabled={saving}
              >
                {saving ? <CircularProgress size={20} /> : 'Save Preferences'}
              </Button>
            </Box>
          </Grid>
        </Grid>
      </Paper>
    </LocalizationProvider>
  );
};

import { useEffect, useState } from 'react';
import { Box, Button, Tooltip, IconButton } from '@mui/material';
import EditIcon from '@mui/icons-material/Edit';
import DeleteIcon from '@mui/icons-material/Delete';
import CheckCircleIcon from '@mui/icons-material/CheckCircle';
import WarningAmberIcon from '@mui/icons-material/WarningAmber';
import type { Product, TenantInstance } from '../types';

interface ProductGridProps {
  instance: TenantInstance;
  products: Array<Record<string, any>>; // small shape prepared by parent
  selectedProductId: string | null;
  onSelectProduct: (id: string | null) => void;
  onAddProduct: (instance: TenantInstance) => void;
  onEditProduct: (product: Product) => void;
  onDeleteProduct: (productId: string) => void;
}

const ProductGrid: React.FC<ProductGridProps> = (props) => {
  const { instance: _instance, products, selectedProductId, onSelectProduct, onAddProduct, onEditProduct, onDeleteProduct } = props;
  const [DataGridModule, setDataGridModule] = useState<unknown>(null);

  useEffect(() => {
    let mounted = true;
    import('@mui/x-data-grid').then((mod) => {
      if (mounted) setDataGridModule(mod);
    });
    return () => { mounted = false; };
  }, []);

  const injectedLoading = `
    .product-grid-loading{ height:100%; display:flex; align-items:center; justify-content:center }
  `;

  if (!DataGridModule) {
    return <><style dangerouslySetInnerHTML={{ __html: injectedLoading }} /><div className="product-grid-loading">Loading products...</div></>;
  }

  const DataGrid = (DataGridModule as any)?.DataGrid as React.ComponentType<any> | undefined;

  if (!DataGrid) return <><style dangerouslySetInnerHTML={{ __html: injectedLoading }} /><div className="product-grid-loading">Loading products...</div></>;

  const rows = products.map(p => ({
    id: p.id != null && typeof p.id !== 'object' ? String(p.id) : '',
    name: p.alpha_product?.product_name,
    code: p.alpha_product?.product_code,
    version: p.version,
    status: p.alpha_product?.is_active ? 'Active' : 'Inactive',
    fullProduct: p
  }));

  const columns = [
  { field: 'code', headerName: 'Product Code', flex: 1, renderCell: (params: any) => (<Tooltip title={params.row.name}><Box component="span" sx={{ width: '100%' }}>{params.value}</Box></Tooltip>) },
    { field: 'version', headerName: 'Version', width: 100 },
    { field: 'status', headerName: 'Status', width: 120, renderCell: (params: any) => (
      <Tooltip title={params.value}>
        <Box component="span">
          {params.value === 'Active' ? <CheckCircleIcon color="success" /> : <WarningAmberIcon color="warning" />}
        </Box>
      </Tooltip>
    ) },
    { field: 'actions', headerName: 'Actions', width: 140, renderCell: (params: any) => (
      <Box sx={{ display: 'flex', gap: 1 }}>
        <Tooltip title="Edit">
          <IconButton size="small" onClick={() => onEditProduct(params.row.fullProduct)}>
            <EditIcon fontSize="small" />
          </IconButton>
        </Tooltip>
        <Tooltip title="Unassign">
          <IconButton size="small" color="error" onClick={() => onDeleteProduct(params.row.id)}>
            <DeleteIcon fontSize="small" />
          </IconButton>
        </Tooltip>
      </Box>
    )},
  ];

  return (
    <Box sx={{ height: '100%', position: 'relative' }}>
      <DataGrid
        rows={rows}
        columns={columns}
        hideFooter
        density="compact"
        rowSelectionModel={selectedProductId ? [selectedProductId] : []}
        onRowSelectionModelChange={(selectionModel: string[] | number[] | readonly string[] | readonly number[]) => {
          const selectedId = Array.isArray(selectionModel) ? selectionModel[0] : undefined;
          const idStr = selectedId == null ? null : String(selectedId);
          onSelectProduct(idStr);
        }}
        checkboxSelection={false}
      />
    </Box>
  );
};

export default ProductGrid;

import React, { useMemo, useState } from 'react';
import yaml from 'js-yaml';
import SqlMonacoEditor from '../SqlMonacoEditor';
import './CoreCustomEditor.css';

type Measure = {
  id: string;
  name: string;
  sql: string;
  unit?: string;
};

type Cube = {
  id: string;
  name: string;
  measures: Measure[];
};

type CustomChange = {
  id: string; // measure id or new id
  action: 'override' | 'remove' | 'add';
  payload?: Partial<Measure>;
};

const sampleCore: Cube = {
  id: 'cube_sales',
  name: 'Sales',
  measures: [
    { id: 'm_revenue', name: 'Revenue', sql: 'SUM(${table}.amount)', unit: 'USD' },
    { id: 'm_orders', name: 'Orders', sql: 'COUNT(${table}.id)' },
    { id: 'm_discount', name: 'Discount', sql: 'SUM(${table}.discount)', unit: 'USD' },
  ],
};

export const CoreCustomEditorPrototype: React.FC = () => {
  const [core] = useState<Cube>(sampleCore);
  const [customChanges, setCustomChanges] = useState<CustomChange[]>([
    // example: override revenue name
    //{ id: 'm_revenue', action: 'override', payload: { name: 'Revenue (net)' } }
  ]);

  const [selectedMeasureId, setSelectedMeasureId] = useState<string | null>(core.measures[0].id);
  const selectedCore = useMemo(() => core.measures.find(m => m.id === selectedMeasureId) || null, [core, selectedMeasureId]);
  const selectedCustom = useMemo(() => customChanges.find(c => c.id === selectedMeasureId) || null, [customChanges, selectedMeasureId]);

  const mergedMeasures = useMemo(() => {
    const map = new Map<string, Measure>();
    core.measures.forEach(m => map.set(m.id, { ...m }));
    customChanges.forEach(c => {
      if (c.action === 'remove') {
        map.delete(c.id);
      } else if (c.action === 'override') {
        const base = map.get(c.id);
        map.set(c.id, { ...(base || { id: c.id, name: c.id, sql: '' }), ...(c.payload || {}) });
      } else if (c.action === 'add' && c.payload) {
        map.set(c.id, { id: c.id, name: (c.payload.name as string) || c.id, sql: (c.payload.sql as string) || '' });
      }
    });
    return Array.from(map.values());
  }, [core, customChanges]);

  const applyOverride = (id: string, patch: Partial<Measure>) => {
    setCustomChanges(prev => {
      const found = prev.find(p => p.id === id && p.action === 'override');
      if (found) {
        return prev.map(p => p.id === id && p.action === 'override' ? { ...p, payload: { ...(p.payload || {}), ...patch } } : p);
      }
      return [...prev, { id, action: 'override', payload: patch }];
    });
  };

  const markRemoved = (id: string) => {
    setCustomChanges(prev => [...prev.filter(p => p.id !== id), { id, action: 'remove' }]);
  };

  const addNewMeasure = () => {
    const id = `m_custom_${Math.random().toString(36).slice(2, 7)}`;
    setCustomChanges(prev => [...prev, { id, action: 'add', payload: { id, name: 'New measure', sql: '', unit: '' } }]);
    setSelectedMeasureId(id);
  };

  const revertChange = (id: string) => {
    setCustomChanges(prev => prev.filter(p => p.id !== id));
  };

  // For the diff view, compute YAML for core and custom
  const coreYaml = selectedCore ? yaml.dump(selectedCore) : '';
  const customYaml = (() => {
    if (!selectedMeasureId) return '';
    const change = customChanges.find(c => c.id === selectedMeasureId);
    if (!change) return coreYaml;
    if (change.action === 'remove') return '# REMOVED IN CUSTOM';
    if (change.action === 'add') return yaml.dump(change.payload || {});
    return yaml.dump({ ...(selectedCore || {}), ...(change.payload || {}) });
  })();

  return (
    <div className="proto-root">
      <div className="proto-left">
        <div className="proto-header">Model Tree</div>
        <div className="tree">
          <div className="tree-cube">{core.name}</div>
          <div className="tree-measures">
            {core.measures.map(m => {
              const ch = customChanges.find(c => c.id === m.id);
              const removed = ch?.action === 'remove';
              const overridden = ch?.action === 'override';
              return (
                <div
                  key={m.id}
                  className={`tree-item ${selectedMeasureId === m.id ? 'selected' : ''} ${removed ? 'removed' : ''} ${overridden ? 'overridden' : ''}`}
                  onClick={() => setSelectedMeasureId(m.id)}
                >
                  <span className="item-name">{m.name}</span>
                  <div className="item-badges">
                    {removed ? <span className="badge removed">removed</span> : overridden ? <span className="badge overridden">overridden</span> : <span className="badge core">core</span>}
                  </div>
                </div>
              );
            })}
            {/* custom added measures */}
            {customChanges.filter(c => c.action === 'add').map(c => (
              <div key={c.id} className={`tree-item ${selectedMeasureId === c.id ? 'selected' : ''} custom`} onClick={() => setSelectedMeasureId(c.id)}>
                <span className="item-name">{(c.payload?.name as string) || c.id}</span>
                <div className="item-badges"><span className="badge custom">custom</span></div>
              </div>
            ))}
          </div>
          <div className="tree-actions">
            <button className="btn" onClick={addNewMeasure}>+ New measure</button>
          </div>
        </div>
      </div>

      <div className="proto-center">
        <div className="proto-header">Definition Editor</div>
        {selectedMeasureId ? (
          <MeasureEditor
            core={selectedCore}
            change={selectedCustom || undefined}
            onApply={(patch) => applyOverride(selectedMeasureId, patch)}
            onRemove={() => markRemoved(selectedMeasureId)}
            onRevert={() => revertChange(selectedMeasureId)}
            merged={mergedMeasures.find(m => m.id === selectedMeasureId) || null}
            coreYaml={coreYaml}
            customYaml={customYaml}
          />
        ) : (
          <div className="placeholder">Select a measure to edit</div>
        )}
      </div>

      <div className="proto-right">
        <div className="proto-header">Preview & Lineage</div>
        <div className="preview">
          <h4>Merged Measures</h4>
          <ul>
            {mergedMeasures.map(m => (
              <li key={m.id}>{m.name} <small className="muted">({m.unit || 'no unit'})</small></li>
            ))}
          </ul>

          <h4>Lineage (selected)</h4>
          <div className="lineage">
            {/* Simple illustrative SVG lineage */}
            <svg width="100%" height="120" viewBox="0 0 600 120">
              <circle cx="70" cy="60" r="20" className="node src" />
              <text x="70" y="60" textAnchor="middle" dominantBaseline="middle" className="node-label">table</text>
              <path d="M90 60 L200 60" stroke="#888" strokeWidth={2} fill="none" markerEnd="url(#arrow)" />
              <circle cx="240" cy="60" r="20" className="node core" />
              <text x="240" y="60" textAnchor="middle" dominantBaseline="middle" className="node-label">core</text>
              <path d="M260 60 L380 60" stroke="#888" strokeWidth={2} fill="none" />
              <circle cx="420" cy="60" r="20" className="node custom" />
              <text x="420" y="60" textAnchor="middle" dominantBaseline="middle" className="node-label">custom</text>
              <defs>
                <marker id="arrow" markerWidth="10" markerHeight="6" refX="10" refY="3" orient="auto">
                      <path d="M0,0 L10,3 L0,6" className="arrow-path" />
                </marker>
              </defs>
            </svg>
          </div>
        </div>
      </div>
    </div>
  );
};

const MeasureEditor: React.FC<{
  core: Measure | null;
  change?: CustomChange;
  onApply: (patch: Partial<Measure>) => void;
  onRemove: () => void;
  onRevert: () => void;
  merged: Measure | null;
  coreYaml: string;
  customYaml: string;
}> = ({ core, change, onApply, onRemove, onRevert, merged, coreYaml, customYaml }) => {
  const [tab, setTab] = useState<'form' | 'code' | 'diff'>('form');
  const [formState, setFormState] = useState<Partial<Measure>>({ ...(change?.payload || core || {}) });
  const [errors, setErrors] = useState<string | null>(null);

  const handleApply = () => {
    if (!formState.name) return setErrors('Name is required');
    setErrors(null);
    onApply(formState as Partial<Measure>);
  };

  return (
    <div className="editor-root">
      <div className="editor-tabs">
        <button className={tab === 'form' ? 'active' : ''} onClick={() => setTab('form')}>Form</button>
        <button className={tab === 'code' ? 'active' : ''} onClick={() => setTab('code')}>Code</button>
        <button className={tab === 'diff' ? 'active' : ''} onClick={() => setTab('diff')}>Diff</button>
      </div>

      <div className="editor-body">
        {tab === 'form' && (
          <div className="form">
            <label>Name</label>
            <input placeholder="Enter measure name" value={formState.name || ''} onChange={(e) => setFormState(s => ({ ...s, name: e.target.value }))} />
            <label>SQL</label>
            <SqlMonacoEditor
              value={formState.sql || ''}
              onChange={(value) => setFormState(s => ({ ...s, sql: value }))}
              placeholder="SQL expression"
              height="100px"
            />
            <label>Unit</label>
            <input placeholder="Unit (e.g., USD)" value={formState.unit || ''} onChange={(e) => setFormState(s => ({ ...s, unit: e.target.value }))} />
            {errors && <div className="error">{errors}</div>}
            <div className="editor-actions">
              <button className="btn btn-primary" onClick={handleApply}>Apply override</button>
              <button className="btn btn-ghost" onClick={onRemove}>Mark removed</button>
              <button className="btn" onClick={onRevert}>Revert</button>
            </div>
          </div>
        )}

        {tab === 'code' && (
          <div className="code-view">
            <h5>Custom YAML</h5>
            <pre>{customYaml}</pre>
          </div>
        )}

        {tab === 'diff' && (
          <div className="diff-view">
            <div className="diff-col">
              <h5>Core</h5>
              <pre>{coreYaml}</pre>
            </div>
            <div className="diff-col">
              <h5>Custom</h5>
              <pre>{customYaml}</pre>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

