// Mock data, in a real app this would come from an API
const MOCK_TENANTS = [
  { id: 'tenant-1', name: 'Alpha Corp' },
  { id: 'tenant-2', name: 'Beta Industries' },
  { id: 'tenant-3', name: 'Gamma Global' },
];

interface Whitelist {
  global: string[];
  tenants: Record<string, string[]>;
}

// Mock API functions
const fetchWhitelist = async (): Promise<Whitelist> => {
  devLog('Fetching whitelist...');
  // Simulate API delay
  await new Promise(res => setTimeout(res, 500));
  const stored = localStorage.getItem('ipWhitelist');
  if (stored) {
    return JSON.parse(stored);
  }
  return {
    global: ['192.168.1.1', '10.0.0.0/8', '172.16.*.*'],
    tenants: {
      'tenant-1': ['203.0.113.42'],
    },
  };
};

const saveWhitelist = async (whitelist: Whitelist): Promise<void> => {
  devLog('Saving whitelist...', whitelist);
  // Simulate API delay
  await new Promise(res => setTimeout(res, 500));
  localStorage.setItem('ipWhitelist', JSON.stringify(whitelist));
};

const IpWhitelistPage: React.FC = () => {
  const [whitelist, setWhitelist] = useState<Whitelist>({ global: [], tenants: {} });
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState<string | null>(null);

  const [newGlobalIp, setNewGlobalIp] = useState('');
  const [selectedTenant, setSelectedTenant] = useState('');
  const [newTenantIp, setNewTenantIp] = useState('');

  useEffect(() => {
    const loadData = async () => {
      try {
        setLoading(true);
        const data = await fetchWhitelist();
        setWhitelist(data);
      } catch (e) {
        setError(getErrorMessage(e, 'Failed to load whitelist data.'));
      } finally {
        setLoading(false);
      }
    };
    loadData();
  }, []);

  const handleSave = async () => {
    try {
      setSaving(true);
      setError(null);
      setSuccess(null);
      await saveWhitelist(whitelist);
      setSuccess('Whitelist saved successfully!');
    } catch (e) {
      setError(getErrorMessage(e, 'Failed to save whitelist.'));
    } finally {
      setSaving(false);
    }
  };

  const addIp = (scope: 'global' | 'tenant', ip: string) => {
    if (!ip.trim()) return;

    if (scope === 'global') {
      if (whitelist.global.includes(ip)) return;
      setWhitelist(prev => ({ ...prev, global: [...prev.global, ip] }));
      setNewGlobalIp('');
    } else {
      if (!selectedTenant) return;
      const tenantIps = whitelist.tenants[selectedTenant] || [];
      if (tenantIps.includes(ip)) return;
      setWhitelist(prev => ({
        ...prev,
        tenants: {
          ...prev.tenants,
          [selectedTenant]: [...tenantIps, ip],
        },
      }));
      setNewTenantIp('');
    }
  };

  const removeIp = (scope: 'global' | 'tenant', ip: string) => {
    if (scope === 'global') {
      setWhitelist(prev => ({ ...prev, global: prev.global.filter(i => i !== ip) }));
    } else {
      if (!selectedTenant) return;
      setWhitelist(prev => ({
        ...prev,
        tenants: {
          ...prev.tenants,
          [selectedTenant]: (prev.tenants[selectedTenant] || []).filter(i => i !== ip),
        },
      }));
    }
  };

  if (loading) {
    return <CircularProgress />;
  }

  return (
    <Box sx={{ p: 3 }}>
      <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 2 }}>
        <Box>
          <Typography variant="h4" gutterBottom>
            IP Whitelist Management
          </Typography>
          <Typography color="text.secondary">
            Configure global and tenant-specific IP address whitelists. Wildcards like `*` are supported (e.g., `192.168.1.*`).
          </Typography>
        </Box>
        <Button variant="contained" onClick={handleSave} disabled={saving}>
          {saving ? 'Saving...' : 'Save Changes'}
        </Button>
      </Box>

      {error && <Alert severity="error" sx={{ mb: 2 }}>{error}</Alert>}
      {success && <Alert severity="success" sx={{ mb: 2 }}>{success}</Alert>}

      <Grid container spacing={3}>
        <Grid item xs={12} md={6}>
          <Paper sx={{ p: 2, height: '100%' }}>
            <Typography variant="h6" gutterBottom>Global Whitelist</Typography>
            <Box sx={{ display: 'flex', gap: 1, mb: 2 }}>
              <TextField
                size="small"
                label="Add Global IP or Range"
                value={newGlobalIp}
                onChange={(e) => setNewGlobalIp(e.target.value)}
                onKeyPress={(e) => e.key === 'Enter' && addIp('global', newGlobalIp)}
                fullWidth
              />
              <Button variant="outlined" onClick={() => addIp('global', newGlobalIp)}><AddIcon /></Button>
            </Box>
            <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 1 }}>
              {whitelist.global.map(ip => (
                <Chip key={ip} label={ip} onDelete={() => removeIp('global', ip)} />
              ))}
            </Box>
          </Paper>
        </Grid>

        <Grid item xs={12} md={6}>
          <Paper sx={{ p: 2, height: '100%' }}>
            <Typography variant="h6" gutterBottom>Tenant-Specific Whitelist</Typography>
            <FormControl fullWidth sx={{ mb: 2 }}>
              <InputLabel id="tenant-select-label">Select Tenant</InputLabel>
              <Select
                labelId="tenant-select-label"
                value={selectedTenant}
                label="Select Tenant"
                onChange={(e) => setSelectedTenant(e.target.value)}
              >
                <MenuItem value=""><em>None</em></MenuItem>
                {MOCK_TENANTS.map(tenant => (
                  <MenuItem key={tenant.id} value={tenant.id}>{tenant.name}</MenuItem>
                ))}
              </Select>
            </FormControl>

            {selectedTenant && (
              <>
                <Divider sx={{ my: 2 }} />
                <Typography variant="subtitle1" gutterBottom>
                  Whitelist for {MOCK_TENANTS.find(t => t.id === selectedTenant)?.name}
                </Typography>
                <Box sx={{ display: 'flex', gap: 1, mb: 2 }}>
                  <TextField
                    size="small"
                    label="Add IP or Range for Tenant"
                    value={newTenantIp}
                    onChange={(e) => setNewTenantIp(e.target.value)}
                    onKeyPress={(e) => e.key === 'Enter' && addIp('tenant', newTenantIp)}
                    fullWidth
                  />
                  <Button variant="outlined" onClick={() => addIp('tenant', newTenantIp)}><AddIcon /></Button>
                </Box>
                <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 1 }}>
                  {(whitelist.tenants[selectedTenant] || []).map(ip => (
                    <Chip key={ip} label={ip} onDelete={() => removeIp('tenant', ip)} />
                  ))}
                </Box>
              </>
            )}
          </Paper>
        </Grid>
      </Grid>
    </Box>
  );
};

