import React from 'react';
import { devLog, devWarn } from '../../utils/devLogger';
import { CodePanel } from './CodePanel';
import CanvasPanel from './CanvasPanel';
import SemanticPalette from './SemanticPalette';
import './SemanticModelEditor.css';
import { ShowCode, SemanticModel } from './types';
import { useGlobalSearch } from '../../contexts/GlobalSearchContext';
import { CoreOption } from './financialCalculations';
import EnhancedTileForm from './EnhancedTileForm';

interface SemanticModelEditorProps {
  semanticModel: any;
  modelName: string;
  showCode: ShowCode | null;
  onToggleCode: (fmt: ShowCode | null) => void;
  generateJSON: () => string;
  generateYAML: () => string;
  generateCustomJSON?: () => string;
  generateCustomYAML?: () => string;
  generateCoreJSON?: () => string;
  generateCoreYAML?: () => string;
  generateMergedModelObject?: () => any;
  codeEditable?: boolean;
  extendsModel?: string | null;
  selectedModel?: any;
  onAdd?: (type: 'dimension' | 'measure' | 'filter' | 'join' | 'extends') => void;
  removeSemanticElement?: (type: "dimensions" | "measures" | "filters" | "joins", id: string) => void;
  toggleElementEdit?: (type: "dimensions" | "measures" | "filters" | "joins", id: string) => void;
  updateSemanticElement?: (type: "dimensions" | "measures" | "filters" | "joins", id: string, updates: any) => void;
  coreOptions?: CoreOption[];
  editMode?: boolean;
  // other props...
}

const SemanticModelEditor: React.FC<SemanticModelEditorProps> = ({
  semanticModel,
  modelName,
  showCode,
  onToggleCode,
  generateJSON,
  generateYAML,
  generateCustomJSON,
  generateCustomYAML,
  generateCoreJSON,
  generateCoreYAML,
  generateMergedModelObject,
  codeEditable = false,
  extendsModel = null,
  selectedModel = null,
  onAdd,
  removeSemanticElement,
  toggleElementEdit,
  updateSemanticElement,
  coreOptions = [],
  editMode = false,
  // other props...
}) => {
  const [_matchIndex, setMatchIndex] = React.useState(0);
  const [_matchCount, setMatchCount] = React.useState(0);
  const { /* searchTerm: ctxTerm, setSearchTerm: ctxSet */ } = useGlobalSearch();
  const [selectedElement, setSelectedElement] = React.useState<any>(null);

  // Draggable palette overlay state/refs
  const wrapperRef = React.useRef<HTMLDivElement | null>(null);
  const overlayRef = React.useRef<HTMLDivElement | null>(null);
  const draggingRef = React.useRef(false);
  const dragOffsetRef = React.useRef<{ dx: number; dy: number }>({ dx: 0, dy: 0 });
  const [palettePos, setPalettePos] = React.useState<{ x: number; y: number }>({ x: 8, y: 8 });

  // Clamp position within wrapper bounds - allow full edge access
  const clampToWrapper = React.useCallback((x: number, y: number) => {
    const wrapper = wrapperRef.current;
    const overlay = overlayRef.current;
    if (!wrapper || !overlay) return { x, y };
    const wr = wrapper.getBoundingClientRect();
    const ow = overlay.offsetWidth || 0;
    const oh = overlay.offsetHeight || 0;
    // Allow palette to go to very edges (no margin restriction)
    const maxX = Math.max(0, wr.width - ow);
    const maxY = Math.max(0, wr.height - oh);
    return { x: Math.min(Math.max(0, x), maxX), y: Math.min(Math.max(0, y), maxY) };
  }, []);

  React.useEffect(() => {
    const onMove = (e: MouseEvent) => {
      if (!draggingRef.current) return;
      const wrap = wrapperRef.current; if (!wrap) return;
      const rect = wrap.getBoundingClientRect();
      const x = e.clientX - rect.left - dragOffsetRef.current.dx;
      const y = e.clientY - rect.top - dragOffsetRef.current.dy;
      const clamped = clampToWrapper(x, y);
      setPalettePos(clamped);
      e.preventDefault();
    };
    const onUp = () => { draggingRef.current = false; document.body.classList.remove('palette-dragging'); };
    window.addEventListener('mousemove', onMove);
    window.addEventListener('mouseup', onUp);
    window.addEventListener('mouseleave', onUp);
    return () => {
      window.removeEventListener('mousemove', onMove);
      window.removeEventListener('mouseup', onUp);
      window.removeEventListener('mouseleave', onUp);
    };
  }, [clampToWrapper]);

  // Re-clamp on resize
  React.useEffect(() => {
    const onResize = () => setPalettePos((p) => clampToWrapper(p.x, p.y));
    window.addEventListener('resize', onResize);
    return () => window.removeEventListener('resize', onResize);
  }, [clampToWrapper]);

  const startDrag = (e: React.MouseEvent) => {
    const wrap = wrapperRef.current; const overlay = overlayRef.current;
    if (!wrap || !overlay) return;
    const wrapRect = wrap.getBoundingClientRect();
    const overlayRect = overlay.getBoundingClientRect();
    draggingRef.current = true;
    document.body.classList.add('palette-dragging');
    dragOffsetRef.current = {
      dx: e.clientX - overlayRect.left,
      dy: e.clientY - overlayRect.top,
    };
    // Ensure cursor doesn't select text while dragging
    e.preventDefault();
  };

  const _dispatchNavigate = (direction: number) => {
    window.dispatchEvent(new CustomEvent('semlayer.navigateMatch', { detail: { direction } }));
  };

  // Focus the canvas when the selected model changes (core or custom)
  React.useEffect(() => {
    try {
      window.dispatchEvent(new CustomEvent('semlayer.focusCanvas'));
    } catch {
      // no-op
    }
  }, [selectedModel?.model_key, selectedModel?.name]);

  // Auto-select the first item in the canvas when a model loads so the form is populated
  React.useEffect(() => {
    if (!semanticModel) return;
    try {
      const dims = semanticModel.dimensions || [];
      const meas = semanticModel.measures || [];
      const filts = semanticModel.filters || [];
      const joins = (semanticModel.joins || []);
      const preAggs = (semanticModel as any).pre_aggregations || [];
      const first = dims[0] || meas[0] || filts[0] || joins[0] || preAggs[0] || null;
      if (first) setSelectedElement(first);
    } catch {}
  }, [semanticModel?.name, semanticModel?.dimensions, semanticModel?.measures, semanticModel?.filters, (semanticModel as any)?.joins, (semanticModel as any)?.pre_aggregations]);

  // Debug: log generated code and tile counts when selection changes
  React.useEffect(() => {
    if (!selectedModel) return;
    try {
      const key = (selectedModel as any)?.model_key || (selectedModel as any)?.name || 'unknown';
      const isCustom = Boolean((selectedModel as any)?.is_custom);
      const json = isCustom
        ? (generateCustomJSON ? generateCustomJSON() : generateJSON())
        : generateJSON();
      const yaml = isCustom
        ? (generateCustomYAML ? generateCustomYAML() : generateYAML())
        : generateYAML();
  // Print full code for troubleshooting via dev logger
  devLog('[SemanticModelEditor] Selected model:', { key, isCustom, extendsModel });
  devLog('[SemanticModelEditor] Generated JSON for model', key, '\n', json);
  devLog('[SemanticModelEditor] Generated YAML for model', key, '\n', yaml);
    } catch (e) {
      devWarn('[SemanticModelEditor] Failed to generate code for selected model', e);
    }
    try {
      const d = (semanticModel?.dimensions || []).length;
      const m = (semanticModel?.measures || []).length;
      const f = (semanticModel?.filters || []).length;
      const j = ((semanticModel?.joins || [])).length;
  devLog('[SemanticModelEditor] Tile counts => dimensions:', d, 'measures:', m, 'filters:', f, 'joins:', j);
    } catch {}
  }, [selectedModel?.model_key, selectedModel?.name]);
  return (
  <div className={"semantic-model-editor " + (!editMode ? 'no-palette ' : '') + (showCode ? 'code-mode' : '') + (editMode ? 'edit-mode' : '')}>
      {/* Palette, Canvas, Form, and Code Panels go here */}

      {!showCode && (
        <div className="canvas-overlay-wrapper" ref={wrapperRef}>
          {editMode && selectedModel?.is_custom && (
            <div
              className="palette-overlay has-position"
              role="region"
              aria-label="Modeling palette"
              ref={overlayRef}
              data-left={palettePos.x}
              data-top={palettePos.y}
            >
              <div
                className="palette-drag-handle"
                role="button"
                aria-label="Move palette"
                title="Drag to move palette"
                tabIndex={0}
                onMouseDown={startDrag}
              />
              <SemanticPalette
                onAdd={onAdd || (() => {})}
                horizontal={true}
                enableDrag={false}
                canAddExtends={!!(editMode && selectedModel?.is_custom && !extendsModel)}
              />
            </div>
          )}
          <div className="canvas-form-container">
            <div className="canvas-section">
              <CanvasPanel
                semanticModel={semanticModel as SemanticModel}
                coreOptions={coreOptions}
                extendsModel={extendsModel}
                editMode={editMode}
                removeSemanticElement={removeSemanticElement || (()=>{})}
                toggleElementEdit={toggleElementEdit || (()=>{})}
                updateSemanticElement={updateSemanticElement || (()=>{})}
                onElementSelect={setSelectedElement}
              />
            </div>
            <div className="form-section">
              <div className="form-section-header">
                <h3>Element Details</h3>
              </div>
              <div className="form-section-content">
                {selectedElement ? (
                  <EnhancedTileForm
                    element={selectedElement}
                    type={(selectedElement?.type as any) || (selectedElement?.aggregationType ? 'measure' : selectedElement?.sourceColumn ? 'dimension' : 'filter')}
                    isCore={!selectedElement.is_custom}
                    isOverride={false}
                    isNew={false}
                    coreOptions={coreOptions}
                    modelName={semanticModel.name}
                    onUpdate={(updates) => {
                      // Handle updates based on element type
                      const elementType = selectedElement?.aggregationType ? 'measure' : selectedElement?.sourceColumn ? 'dimension' : selectedElement?.type || 'filter';
                      updateSemanticElement?.(elementType, selectedElement.id, updates);
                    }}
                    onSave={() => {
                      // Close the form or handle save
                      setSelectedElement(null);
                    }}
                    onCancel={() => setSelectedElement(null)}
                    onClose={() => setSelectedElement(null)}
                    readOnly={!editMode}
                  />
                ) : extendsModel ? (
                  <div className="extends-info">
                    <h4>Extends: {extendsModel}</h4>
                    <p>This model extends the base model "{extendsModel}". The extended model provides additional customizations on top of the base functionality.</p>
                  </div>
                ) : (
                  <div className="form-placeholder">
                    Select an element to view and edit its details here.
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
      )}
      {showCode && (
        <>
          <CodePanel
            showCode={showCode}
            modelName={modelName}
            onToggleFormat={onToggleCode}
            generateJSON={generateJSON}
            generateYAML={generateYAML}
            generateCustomJSON={generateCustomJSON}
            generateCustomYAML={generateCustomYAML}
            generateCoreJSON={generateCoreJSON}
            generateCoreYAML={generateCoreYAML}
            generateMergedModelObject={generateMergedModelObject}
            codeEditable={codeEditable}
            extendsModel={extendsModel}
            semanticModel={semanticModel}
            selectedModel={selectedModel}
            setMatchIndex={setMatchIndex}
            setMatchCount={setMatchCount}
          />
        </>
      )}
    </div>
  );
};

export default SemanticModelEditor;

import React, { useState, useMemo } from 'react';
import { IconPlus, IconDatabase, IconFilter, IconChartBar, IconPlugConnected, IconStack3 } from '@tabler/icons-react';
import { useDrag } from 'react-dnd';
import PaletteItem from './PaletteItem';
import './SemanticPalette.css';
import './SemanticPaletteHorizontal.css';
import styles from './SemanticPalette.module.css';

interface SemanticPaletteProps {
  onAdd: (type: 'dimension' | 'measure' | 'filter' | 'join' | 'extends') => void;
  horizontal?: boolean;
  enableDrag?: boolean; // keep drag temporarily (optional)
  canAddExtends?: boolean; // when true, show an Extends action
}

interface SimpleElement {
  type: 'dimension' | 'measure' | 'filter' | 'join' | 'pre_aggregation';
  label: string;
  description: string;
  icon: React.ReactNode;
}

const ELEMENTS: SimpleElement[] = [
  { type: 'dimension', label: 'Dimension', description: 'Add a new dimension or override core', icon: <IconDatabase size={16} /> },
  { type: 'measure', label: 'Measure', description: 'Add a new measure or override core', icon: <IconChartBar size={16} /> },
  { type: 'filter', label: 'Filter', description: 'Add a new filter or override core', icon: <IconFilter size={16} /> },
  { type: 'join', label: 'Join', description: 'Define a join (future)', icon: <IconPlugConnected size={16} /> },
  { type: 'pre_aggregation', label: 'Pre-Aggregation', description: 'View configured pre-aggregations', icon: <IconStack3 size={16} /> }
];

const SemanticPalette: React.FC<SemanticPaletteProps> = ({ onAdd, horizontal = true, enableDrag = false, canAddExtends = false }) => {
  const [tooltip, setTooltip] = useState<{ show: boolean; x: number; y: number; label?: string; description?: string }>({ show: false, x: 0, y: 0, label: undefined, description: undefined });

  // Filter elements based on search term
  const filteredElements = useMemo(() => {
    return ELEMENTS;
  }, []);

  const handleTooltipShow = (label: string, description: string, rect: DOMRect) => {
    setTooltip({ show: true, x: rect.left + rect.width / 2, y: rect.top - 10, label, description });
  };
  const handleTooltipHide = () => setTooltip({ show: false, x: 0, y: 0 });

  return (
    <>
      <div className={`semantic-palette minimal ${horizontal ? 'horizontal' : ''}`}>
        <div className="palette-toolbar simple colored">
          <div className="toolbar-items simple colored">
            {canAddExtends && (
              <button
                key="extends"
                className={`palette-icon-btn colored extends`}
                type="button"
                onClick={() => onAdd('extends')}
                onMouseEnter={(e) => { handleTooltipShow('Extends', 'Set the base model this model extends', (e.currentTarget as HTMLElement).getBoundingClientRect()); }}
                onMouseLeave={() => handleTooltipHide()}
                aria-label="Extends"
                title="Extends"
              >
                <IconPlus size={16} />
                {!horizontal && <span className="label">Extends</span>}
                {horizontal && <span className="sr-only">Extends</span>}
              </button>
            )}
            {filteredElements.map(el => (
              el.type === 'pre_aggregation' ? (
                <button
                  key={el.type}
                  className={`palette-icon-btn colored pre_aggregation`}
                  type="button"
                  onMouseEnter={(e) => { handleTooltipShow(el.label, el.description, (e.currentTarget as HTMLElement).getBoundingClientRect()); }}
                  onMouseLeave={() => handleTooltipHide()}
                  aria-label="Pre-Aggregation"
                  title="Pre-Aggregation"
                >
                  {el.icon}
                  {!horizontal && <span className="label">{el.label}</span>}
                  {horizontal && <span className="sr-only">{el.label}</span>}
                </button>
              ) : (
                <PaletteItem
                  key={el.type}
                  typeName={el.type as any}
                  label={el.label}
                  description={el.description}
                  icon={el.icon}
                  onAdd={onAdd}
                  horizontal={horizontal}
                  enableDrag={enableDrag}
                  onTooltipShow={handleTooltipShow}
                  onTooltipHide={handleTooltipHide}
                />
              )
            ))}
          </div>
        </div>
      </div>
      {tooltip.show && (
        <div className={`palette-tooltip ${styles.paletteTooltip}`} data-left={tooltip.x} data-top={tooltip.y}>
          <div className={styles.tooltipTitle}>{tooltip.label}</div>
          {tooltip.description && <div className={styles.tooltipDesc}>{tooltip.description}</div>}
        </div>
      )}
    </>
  );
};

export default SemanticPalette;

