describe('WorkspaceMain header search', () => {
  test('calls setSearchTerm when search input changes and badge is interactive', async () => {
    const setSearchTerm = vi.fn();
    render(<WorkspaceMain {...baseProps} setSearchTerm={setSearchTerm} filteredCompat={[1,2,3]} />);
    const input = screen.getByPlaceholderText('Search catalog');
    const user = userEvent.setup();
  await user.type(input, 'abc');
  // userEvent types char-by-char; component is controlled so onChange receives chars — join calls
  const calls = setSearchTerm.mock.calls.map(c => String(c[0]));
  expect(calls.join('')).toBe('abc');
    // stats badge should show length of filteredCompat and be clickable
    const badge = screen.getByRole('button', { name: /Compatibility issues/i });
    expect(badge.textContent).toBe('3');
  const handler = vi.fn();
  window.addEventListener('compatibility.badge.click', handler as any);
  await user.click(badge);
  expect(handler).toHaveBeenCalled();
  // panel should appear
  expect(screen.getByTestId('compat-panel')).toBeInTheDocument();
  // close it
  await user.click(screen.getByLabelText('Close compatibility panel'));
  expect(screen.queryByTestId('compat-panel')).toBeNull();
  window.removeEventListener('compatibility.badge.click', handler as any);
  });
});

import React from 'react';
import { render, screen, fireEvent, waitFor } from '@testing-library/react';
import { vi, describe, it, expect } from 'vitest';
import { MantineProvider } from '@mantine/core';
import axios from 'axios';
import ScanResultsModal from '../../components/ScanResultsModal';

vi.mock('axios');

const mockAxios = axios as unknown as { post: any };
// jsdom (used by Vitest) doesn't implement matchMedia; Mantine calls it. Provide a lightweight polyfill.
if (typeof window !== 'undefined' && !window.matchMedia) {
  (window as any).matchMedia = (query: string) => ({
    matches: false,
    media: query,
    onchange: null,
    addEventListener: () => {},
    removeEventListener: () => {},
    addListener: () => {},
    removeListener: () => {},
    dispatchEvent: () => false,
  });
}

describe('ScanResultsModal', () => {
  it('renders results and retries a failed datasource', async () => {
    const results = [
      { datasource_id: 'ds1', name: 'DS One', success: true },
      { datasource_id: 'ds2', name: 'DS Two', success: false, error: 'boom' },
    ];

    const onRetry = vi.fn(async (id) => {
      // simulate axios returning updated results for the retried id
      mockAxios.post = vi.fn().mockResolvedValueOnce({ data: { results: [ { datasource_id: 'ds1', success: true }, { datasource_id: 'ds2', success: true } ] } });
    });

    render(
      <MantineProvider theme={{}}>
        <ScanResultsModal opened={true} onClose={() => {}} results={results as any} onRetry={onRetry as any} />
      </MantineProvider>
    );

    expect(screen.getByText('DS One')).toBeTruthy();
    expect(screen.getByText('DS Two')).toBeTruthy();
    expect(screen.getByText('boom')).toBeTruthy();

    const retryBtn = screen.getByText('Retry');
    fireEvent.click(retryBtn);

    await waitFor(() => expect(onRetry).toHaveBeenCalledWith('ds2'));
  });
});

import React, { useState, useEffect } from 'react';
import { devError } from '../../utils/devLogger';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from '@/components/ui/dialog';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { AlertTriangle, CheckCircle, XCircle, Clock, Filter, RefreshCw, Settings } from 'lucide-react';
import { AnomalyDetectionConfig } from './AnomalyDetectionConfig';
import { AnomalyDetectionResult, PoPAnomaly } from '@/types';
import { Download, TrendingUp, History, Zap } from 'lucide-react';

interface AnomalySummary {
  domain: string;
  category: string;
  severity: string;
  anomaly_type: string;
  anomaly_count: number;
  latest_detection: string;
  affected_metrics: string[];
}

interface PoPMetricWithLatest {
  id: string;
  name: string;
  display_name: string;
  domain: string;
  category: string;
  current_value?: number;
  previous_value?: number;
  delta?: number;
  percent_change?: number;
  period_start: string;
  period_end: string;
  last_computed_at: string;
  has_anomalies: boolean;
  anomaly_count: number;
}

interface AnomalyDashboardProps {
  anomalySummary: AnomalySummary[];
  metrics: PoPMetricWithLatest[];
  onRefresh: () => void;
}

interface AnomalyDetail extends PoPAnomaly {}

export const AnomalyDashboard: React.FC<AnomalyDashboardProps> = ({
  anomalySummary,
  metrics,
  onRefresh
}) => {
  const [anomalies, setAnomalies] = useState<AnomalyDetail[]>([]);
  const [loading, setLoading] = useState(false);
  const [severityFilter, setSeverityFilter] = useState('');
  const [statusFilter, setStatusFilter] = useState('');
  const [selectedAnomaly, setSelectedAnomaly] = useState<AnomalyDetail | null>(null);
  const [showResolveDialog, setShowResolveDialog] = useState(false);
  const [showDetectionConfig, setShowDetectionConfig] = useState(false);
  const [selectedMetricForDetection, setSelectedMetricForDetection] = useState<string>('');
  const [detectionResults, setDetectionResults] = useState<AnomalyDetectionResult | null>(null);
  const [showBulkOperations, setShowBulkOperations] = useState(false);
  const [selectedMetricsForBulk, setSelectedMetricsForBulk] = useState<string[]>([]);
  const [exportLoading, setExportLoading] = useState(false);
  const [showTrends, setShowTrends] = useState(false);
  const [trendsData, setTrendsData] = useState<any[]>([]);
  const [showExport, setShowExport] = useState(false);
  const [exportFormat, setExportFormat] = useState('csv');
  const [exportStartDate, setExportStartDate] = useState('');
  const [exportEndDate, setExportEndDate] = useState('');

  useEffect(() => {
    fetchAnomalies();
  }, []);

  const fetchAnomalies = async () => {
    setLoading(true);
    try {
      const response = await fetch('/api/pop/anomalies');
      if (!response.ok) throw new Error('Failed to fetch anomalies');

      const data = await response.json();
      setAnomalies(data.anomalies || []);
    } catch (error) {
      devError('Error fetching anomalies:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleBulkAnomalyDetection = async () => {
    if (selectedMetricsForBulk.length === 0) {
      alert('Please select metrics for bulk detection');
      return;
    }

    try {
      const response = await fetch('/api/pop/bulk-detect-anomalies', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          metric_ids: selectedMetricsForBulk,
          config: {
            method: 'z_score',
            sensitivity: 0.8,
            window_size: 30,
            min_data_points: 7,
            custom_parameters: { zscore_threshold: 2.5 }
          }
        }),
      });

      if (!response.ok) throw new Error('Failed to run bulk anomaly detection');

      const result = await response.json();
      alert(`Bulk detection completed! Processed ${result.metrics_processed} metrics, found ${result.total_anomalies} anomalies`);
      onRefresh();
      fetchAnomalies();
      setShowBulkOperations(false);
    } catch (error) {
      devError('Error running bulk anomaly detection:', error);
      alert('Failed to run bulk anomaly detection');
    }
  };

  const handleDetectionComplete = (result: AnomalyDetectionResult) => {
    setDetectionResults(result);
    // Add new anomalies to the existing list
    setAnomalies(prev => [...prev, ...result.anomalies]);
    setShowDetectionConfig(false);
    onRefresh();
    fetchAnomalies();
  };

  const handleOpenDetectionConfig = (metricId: string) => {
    setSelectedMetricForDetection(metricId);
    setShowDetectionConfig(true);
  };

  const handleExportAnomalies = async (format: string) => {
    setExportLoading(true);
    try {
      const params = new URLSearchParams();
      params.append('format', format);
      if (severityFilter) params.append('severity', severityFilter);
      if (statusFilter) params.append('status', statusFilter);
      if (exportStartDate) params.append('start_date', exportStartDate);
      if (exportEndDate) params.append('end_date', exportEndDate);

      const response = await fetch(`/api/pop/export-anomalies?${params}`);
      if (!response.ok) throw new Error('Failed to export anomalies');

      const blob = await response.blob();
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `anomalies_export.${format}`;
      document.body.appendChild(a);
      a.click();
      window.URL.revokeObjectURL(url);
      document.body.removeChild(a);
      setShowExport(false);
    } catch (error) {
      devError('Error exporting anomalies:', error);
      alert('Failed to export anomalies');
    } finally {
      setExportLoading(false);
    }
  };

  const handleFetchTrends = async () => {
    try {
      const response = await fetch('/api/pop/anomaly-trends?days=30');
      if (!response.ok) throw new Error('Failed to fetch trends');

      const data = await response.json();
      setTrendsData(data.trends || []);
      setShowTrends(true);
    } catch (error) {
      devError('Error fetching trends:', error);
      alert('Failed to fetch anomaly trends');
    }
  };

  const handleResolveAnomaly = async (anomalyId: string, resolutionNotes: string) => {
    try {
      const response = await fetch(`/api/pop/anomalies/${anomalyId}/resolve`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          resolution_notes: resolutionNotes,
          resolved_by: 'current_user' // TODO: Get from auth context
        }),
      });

      if (!response.ok) throw new Error('Failed to resolve anomaly');

      fetchAnomalies();
      setShowResolveDialog(false);
      setSelectedAnomaly(null);
    } catch (error) {
      devError('Error resolving anomaly:', error);
      alert('Failed to resolve anomaly');
    }
  };

  const filteredAnomalies = anomalies.filter(anomaly => {
    if (severityFilter && anomaly.severity !== severityFilter) return false;
    if (statusFilter && anomaly.status !== statusFilter) return false;
    return true;
  });

  const getSeverityColor = (severity: string) => {
    switch (severity) {
      case 'high': return 'text-red-600 bg-red-50 border-red-200';
      case 'medium': return 'text-orange-600 bg-orange-50 border-orange-200';
      case 'low': return 'text-yellow-600 bg-yellow-50 border-yellow-200';
      default: return 'text-gray-600 bg-gray-50 border-gray-200';
    }
  };

  const getStatusIcon = (status: string) => {
    switch (status) {
      case 'resolved': return <CheckCircle className="w-4 h-4 text-green-500" />;
      case 'open': return <AlertTriangle className="w-4 h-4 text-red-500" />;
      case 'investigating': return <Clock className="w-4 h-4 text-blue-500" />;
      default: return <XCircle className="w-4 h-4 text-gray-500" />;
    }
  };

  const formatValue = (value?: number) => {
    if (value === undefined || value === null) return 'N/A';
    return value.toLocaleString(undefined, { maximumFractionDigits: 2 });
  };

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-bold text-gray-900">Anomaly Dashboard</h2>
          <p className="text-gray-600">Monitor and manage detected anomalies</p>
        </div>
        <div className="flex items-center space-x-2">
          <Button onClick={fetchAnomalies} variant="outline" disabled={loading}>
            <RefreshCw className={`w-4 h-4 mr-2 ${loading ? 'animate-spin' : ''}`} />
            Refresh
          </Button>
          <Button onClick={handleBulkAnomalyDetection}>
            <Zap className="w-4 h-4 mr-2" />
            Bulk Detection
          </Button>
          <Button
            variant="outline"
            onClick={() => setShowBulkOperations(true)}
          >
            <TrendingUp className="w-4 h-4 mr-2" />
            Bulk Operations
          </Button>
          <Button
            variant="outline"
            onClick={handleFetchTrends}
          >
            <History className="w-4 h-4 mr-2" />
            Trends
          </Button>
          <Button
            variant="outline"
            onClick={() => setShowExport(true)}
            disabled={exportLoading}
          >
            <Download className="w-4 h-4 mr-2" />
            Export
          </Button>
          <Button
            variant="outline"
            onClick={() => setShowDetectionConfig(true)}
          >
            <Settings className="w-4 h-4 mr-2" />
            Advanced Detection
          </Button>
        </div>
      </div>

      {/* Summary Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Total Anomalies</CardTitle>
            <AlertTriangle className="h-4 w-4 text-red-500" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold text-red-600">{anomalies.length}</div>
            <p className="text-xs text-muted-foreground">
              Across all metrics
            </p>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Open Anomalies</CardTitle>
            <Clock className="h-4 w-4 text-orange-500" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold text-orange-600">
              {anomalies.filter(a => a.status === 'open').length}
            </div>
            <p className="text-xs text-muted-foreground">
              Require attention
            </p>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Resolved Today</CardTitle>
            <CheckCircle className="h-4 w-4 text-green-500" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold text-green-600">
              {anomalies.filter(a =>
                a.status === 'resolved' &&
                new Date(a.resolved_at || '').toDateString() === new Date().toDateString()
              ).length}
            </div>
            <p className="text-xs text-muted-foreground">
              Today's resolutions
            </p>
          </CardContent>
        </Card>
      </div>

      {/* Detection Results */}
      {detectionResults && (
        <Card className="border-green-200 bg-green-50">
          <CardHeader>
            <CardTitle className="text-green-800">Detection Results</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="flex items-center justify-between">
              <div>
                <p className="text-green-700">
                  Found {detectionResults.count} anomalies using {detectionResults.method_used}
                </p>
                <p className="text-sm text-green-600">
                  Detection completed at {new Date(detectionResults.detection_time).toLocaleString()}
                </p>
              </div>
              <Button
                variant="outline"
                size="sm"
                onClick={() => setDetectionResults(null)}
              >
                Dismiss
              </Button>
            </div>
          </CardContent>
        </Card>
      )}

      {/* Anomaly Summary by Domain/Category */}
      <Card>
        <CardHeader>
          <CardTitle>Anomaly Summary</CardTitle>
        </CardHeader>
        <CardContent>
          <div className="space-y-4">
            {anomalySummary.map((summary, index) => (
              <div key={index} className="flex items-center justify-between p-4 border rounded-lg">
                <div>
                  <p className="font-medium">{summary.domain} • {summary.category}</p>
                  <p className="text-sm text-gray-500">
                    {summary.anomaly_type} • Latest: {new Date(summary.latest_detection).toLocaleDateString()}
                  </p>
                </div>
                <div className="flex items-center space-x-4">
                  <Badge className={getSeverityColor(summary.severity)}>
                    {summary.severity}
                  </Badge>
                  <div className="text-right">
                    <div className="text-lg font-bold">{summary.anomaly_count}</div>
                    <div className="text-sm text-gray-500">anomalies</div>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </CardContent>
      </Card>

      {/* Filters */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center">
            <Filter className="w-4 h-4 mr-2" />
            Filters
          </CardTitle>
        </CardHeader>
        <CardContent>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <Select value={severityFilter} onValueChange={setSeverityFilter}>
              <SelectTrigger>
                <SelectValue placeholder="All Severities" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="">All Severities</SelectItem>
                <SelectItem value="high">High</SelectItem>
                <SelectItem value="medium">Medium</SelectItem>
                <SelectItem value="low">Low</SelectItem>
              </SelectContent>
            </Select>

            <Select value={statusFilter} onValueChange={setStatusFilter}>
              <SelectTrigger>
                <SelectValue placeholder="All Statuses" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="">All Statuses</SelectItem>
                <SelectItem value="open">Open</SelectItem>
                <SelectItem value="investigating">Investigating</SelectItem>
                <SelectItem value="resolved">Resolved</SelectItem>
              </SelectContent>
            </Select>

            <Button
              variant="outline"
              onClick={() => {
                setSeverityFilter('');
                setStatusFilter('');
              }}
            >
              Clear Filters
            </Button>
          </div>
        </CardContent>
      </Card>

      {/* Anomalies Table */}
      <Card>
        <CardHeader>
          <CardTitle>
            Anomalies ({filteredAnomalies.length} of {anomalies.length})
          </CardTitle>
        </CardHeader>
        <CardContent>
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead>Metric</TableHead>
                <TableHead>Type</TableHead>
                <TableHead>Detection Method</TableHead>
                <TableHead>Severity</TableHead>
                <TableHead>Confidence</TableHead>
                <TableHead>Expected vs Actual</TableHead>
                <TableHead>Detected</TableHead>
                <TableHead>Status</TableHead>
                <TableHead>Actions</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {filteredAnomalies.map((anomaly) => {
                const metric = metrics.find(m => m.id === anomaly.metric_id);
                return (
                  <TableRow key={anomaly.id}>
                    <TableCell>
                      <div>
                        <div className="font-medium">{metric?.display_name || 'Unknown'}</div>
                        <div className="text-sm text-gray-500">{metric?.domain} • {metric?.category}</div>
                      </div>
                    </TableCell>
                    <TableCell>
                      <Badge variant="outline">{anomaly.anomaly_type}</Badge>
                    </TableCell>
                    <TableCell>
                      <Badge variant="secondary" className="text-xs">
                        {anomaly.detection_method.replace(/_/g, ' ')}
                      </Badge>
                    </TableCell>
                    <TableCell>
                      <Badge className={getSeverityColor(anomaly.severity)}>
                        {anomaly.severity}
                      </Badge>
                    </TableCell>
                    <TableCell>
                      {anomaly.confidence ? (
                        <div className="text-sm">
                          {(anomaly.confidence * 100).toFixed(1)}%
                        </div>
                      ) : (
                        <span className="text-gray-400">N/A</span>
                      )}
                    </TableCell>
                    <TableCell>
                      <div className="text-sm">
                        <div>Expected: {formatValue(anomaly.expected_value)}</div>
                        <div>Actual: {formatValue(anomaly.actual_value)}</div>
                      </div>
                    </TableCell>
                    <TableCell>
                      <div className="text-sm text-gray-500">
                        {new Date(anomaly.detected_at).toLocaleDateString()}
                      </div>
                    </TableCell>
                    <TableCell>
                      <div className="flex items-center">
                        {getStatusIcon(anomaly.status)}
                        <span className="ml-2 capitalize">{anomaly.status}</span>
                      </div>
                    </TableCell>
                    <TableCell>
                      <div className="flex items-center space-x-2">
                        <Button
                          size="sm"
                          variant="outline"
                          onClick={() => setSelectedAnomaly(anomaly)}
                        >
                          View
                        </Button>
                        {anomaly.status === 'open' && (
                          <Button
                            size="sm"
                            onClick={() => {
                              setSelectedAnomaly(anomaly);
                              setShowResolveDialog(true);
                            }}
                          >
                            Resolve
                          </Button>
                        )}
                      </div>
                    </TableCell>
                  </TableRow>
                );
              })}
            </TableBody>
          </Table>
        </CardContent>
      </Card>

      {/* Anomaly Detail Dialog */}
      {selectedAnomaly && !showResolveDialog && (
        <Dialog open={!!selectedAnomaly} onOpenChange={() => setSelectedAnomaly(null)}>
          <DialogContent className="max-w-2xl">
            <DialogHeader>
              <DialogTitle>Anomaly Details</DialogTitle>
            </DialogHeader>
            <div className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <h4 className="font-medium mb-2">Anomaly Information</h4>
                  <dl className="space-y-1 text-sm">
                    <div><dt className="inline font-medium">Type:</dt> <dd className="inline ml-2">{selectedAnomaly.anomaly_type}</dd></div>
                    <div><dt className="inline font-medium">Severity:</dt> <dd className="inline ml-2">
                      <Badge className={getSeverityColor(selectedAnomaly.severity)}>
                        {selectedAnomaly.severity}
                      </Badge>
                    </dd></div>
                    <div><dt className="inline font-medium">Status:</dt> <dd className="inline ml-2 capitalize">{selectedAnomaly.status}</dd></div>
                    <div><dt className="inline font-medium">Detection Method:</dt> <dd className="inline ml-2">{selectedAnomaly.detection_method.replace(/_/g, ' ')}</dd></div>
                    <div><dt className="inline font-medium">Detected At:</dt> <dd className="inline ml-2">{new Date(selectedAnomaly.detected_at).toLocaleString()}</dd></div>
                  </dl>
                </div>
                <div>
                  <h4 className="font-medium mb-2">Values</h4>
                  <dl className="space-y-1 text-sm">
                    <div><dt className="inline font-medium">Expected:</dt> <dd className="inline ml-2 font-mono">{formatValue(selectedAnomaly.expected_value)}</dd></div>
                    <div><dt className="inline font-medium">Actual:</dt> <dd className="inline ml-2 font-mono">{formatValue(selectedAnomaly.actual_value)}</dd></div>
                    <div><dt className="inline font-medium">Z-Score:</dt> <dd className="inline ml-2 font-mono">{selectedAnomaly.z_score?.toFixed(2) || 'N/A'}</dd></div>
                    <div><dt className="inline font-medium">Confidence:</dt> <dd className="inline ml-2">{selectedAnomaly.confidence ? `${(selectedAnomaly.confidence * 100).toFixed(1)}%` : 'N/A'}</dd></div>
                  </dl>
                </div>
                <div>
                  <h4 className="font-medium mb-2">Detection Parameters</h4>
                  <dl className="space-y-1 text-sm">
