import React, { useState, useEffect } from 'react';
import { Select, Button, Card, Tag, Space, message } from 'antd';
import { FilterOutlined, UserOutlined, DollarOutlined, ClockCircleOutlined } from '@ant-design/icons';
import styles from './CohortFilterSelector.module.css';

const { Option } = Select;

interface Cohort {
  name: string;
  description: string;
  type: 'behavioral' | 'domain' | 'temporal';
  sql: string;
  source: string;
  estimated_size: string;
}

interface CohortValue {
  value: string;
  metadata: any;
  label: string;
}

interface CohortFilterSelectorProps {
  onCohortSelect: (cohort: Cohort, values: string[]) => void;
  selectedCohort?: Cohort;
  selectedValues?: string[];
}

const CohortFilterSelector: React.FC<CohortFilterSelectorProps> = ({
  onCohortSelect,
  selectedCohort,
  selectedValues = []
}) => {
  const [cohorts, setCohorts] = useState<Cohort[]>([]);
  const [availableValues, setAvailableValues] = useState<CohortValue[]>([]);
  const [loading, setLoading] = useState(false);
  const [valuesLoading, setValuesLoading] = useState(false);

  useEffect(() => {
    fetchCohorts();
  }, []);

  const fetchCohorts = async () => {
    setLoading(true);
    try {
      const response = await fetch('/api/cohorts');
      const data = await response.json();
      setCohorts(data.cohorts);
    } catch (error) {
      message.error('Failed to fetch cohorts');
    } finally {
      setLoading(false);
    }
  };

  const fetchCohortValues = async (cohortName: string) => {
    setValuesLoading(true);
    try {
      const response = await fetch(`/api/cohorts/${cohortName}/values`);
      const data = await response.json();
      setAvailableValues(data.values);
    } catch (error) {
      message.error('Failed to fetch cohort values');
    } finally {
      setValuesLoading(false);
    }
  };

  const handleCohortChange = (cohortName: string) => {
    const cohort = cohorts.find(c => c.name === cohortName);
    if (cohort) {
      setAvailableValues([]);
      fetchCohortValues(cohortName);
      onCohortSelect(cohort, []);
    }
  };

  const handleValuesChange = (values: string[]) => {
    if (selectedCohort) {
      onCohortSelect(selectedCohort, values);
    }
  };

  const getCohortIcon = (type: string) => {
    switch (type) {
      case 'behavioral':
        return <UserOutlined />;
      case 'domain':
        return <DollarOutlined />;
      case 'temporal':
        return <ClockCircleOutlined />;
      default:
        return <FilterOutlined />;
    }
  };

  const getCohortColor = (type: string) => {
    switch (type) {
      case 'behavioral':
        return 'blue';
      case 'domain':
        return 'green';
      case 'temporal':
        return 'orange';
      default:
        return 'default';
    }
  };

  return (
    <Card title="Cohort Filters" size="small" className={styles.cohortFilterSelector}>
      <Space direction="vertical" style={{ width: '100%' }}>
        <div>
          <label>Select Cohort:</label>
          <Select
            className={styles.cohortSelect}
            placeholder="Choose a cohort filter"
            loading={loading}
            onChange={handleCohortChange}
            value={selectedCohort?.name}
          >
            {cohorts.map(cohort => (
              <Option key={cohort.name} value={cohort.name}>
                <Space>
                  {getCohortIcon(cohort.type)}
                  <span>{cohort.name.replace(/_/g, ' ')}</span>
                  <Tag color={getCohortColor(cohort.type)} size="small">
                    {cohort.type}
                  </Tag>
                </Space>
              </Option>
            ))}
          </Select>
        </div>

        {selectedCohort && (
          <div>
            <p className={styles.cohortDescription}>
              {selectedCohort.description}
            </p>
            <p className={styles.cohortMetadata}>
              Source: {selectedCohort.source} | Size: {selectedCohort.estimated_size}
            </p>
          </div>
        )}

        {selectedCohort && availableValues.length > 0 && (
          <div>
            <label>Select Values:</label>
            <Select
              mode="multiple"
              className={styles.valuesSelect}
              placeholder="Choose specific values"
              loading={valuesLoading}
              onChange={handleValuesChange}
              value={selectedValues}
              maxTagCount={3}
            >
              {availableValues.map(value => (
                <Option key={value.value} value={value.value}>
                  {value.label}
                </Option>
              ))}
            </Select>
          </div>
        )}

        {selectedValues.length > 0 && (
          <div>
            <p className={styles.selectedValuesInfo}>
              Selected {selectedValues.length} value(s)
            </p>
          </div>
        )}
      </Space>
    </Card>
  );
};

