import React, { useState, useEffect } from 'react';
import { Card, List, Button, Modal, Form, Input, Select, Tag, Space, message, Avatar, Comment, Tooltip, Checkbox } from 'antd';
import { CheckCircleOutlined, CloseCircleOutlined, FlagOutlined, CommentOutlined, UserOutlined } from '@ant-design/icons';
import { formatDistanceToNow } from 'date-fns';
import styles from './StewardApprovalPanel.module.css';

const { TextArea } = Input;
const { Option } = Select;

interface PendingApproval {
  node_id: string;
  node_type: string;
  name: string;
  description: string;
  schema_def: string;
  created_at: string;
  review_status: string;
}

interface StewardApprovalPanelProps {
  stewardUser?: string;
  onApprovalAction?: (action: string, nodeId: string, data: any) => void;
}

const StewardApprovalPanel: React.FC<StewardApprovalPanelProps> = ({
  stewardUser = 'system',
  onApprovalAction
}) => {
  const [pendingApprovals, setPendingApprovals] = useState<PendingApproval[]>([]);
  const [loading, setLoading] = useState(false);
  const [actionModalVisible, setActionModalVisible] = useState(false);
  const [selectedApproval, setSelectedApproval] = useState<PendingApproval | null>(null);
  const [actionType, setActionType] = useState<'approve' | 'reject' | 'flag' | 'comment'>('comment');
  const [form] = Form.useForm();

  const fetchPendingApprovals = React.useCallback(async () => {
    setLoading(true);
    try {
      const response = await fetch(`/api/steward/approvals?steward=${stewardUser}`);
      const data = await response.json();
      setPendingApprovals(data.pending_approvals);
    } catch (error) {
      message.error('Failed to fetch pending approvals');
    } finally {
      setLoading(false);
    }
  }, [stewardUser]);

  useEffect(() => {
    fetchPendingApprovals();
  }, [fetchPendingApprovals]);

  const handleAction = (approval: PendingApproval, action: 'approve' | 'reject' | 'flag' | 'comment') => {
    setSelectedApproval(approval);
    setActionType(action);
    setActionModalVisible(true);
  };

  const handleActionSubmit = async (values: any) => {
    if (!selectedApproval) return;

    try {
      let endpoint = '';
      let method = 'POST';
      let body: any = {
        steward_user: stewardUser,
        comment: values.comment
      };

      switch (actionType) {
        case 'approve':
          endpoint = `/api/steward/approvals/${selectedApproval.node_id}/approve`;
          body.golden_path = values.golden_path;
          break;
        case 'reject':
          endpoint = `/api/steward/approvals/${selectedApproval.node_id}/reject`;
          break;
        case 'flag':
          endpoint = `/api/steward/approvals/${selectedApproval.node_id}/flag`;
          body.severity = values.severity;
          break;
        case 'comment':
          endpoint = `/api/steward/approvals/${selectedApproval.node_id}/comment`;
          body.action = 'comment';
          break;
      }

      const response = await fetch(endpoint, {
        method,
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(body),
      });

      if (!response.ok) {
        throw new Error('Action failed');
      }

      message.success(`${actionType.charAt(0).toUpperCase() + actionType.slice(1)} action completed`);
      setActionModalVisible(false);
      form.resetFields();
      fetchPendingApprovals();

      if (onApprovalAction) {
        onApprovalAction(actionType, selectedApproval.node_id, body);
      }
    } catch (error) {
      message.error(`Failed to ${actionType} approval`);
    }
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'draft':
        return 'orange';
      case 'pending_review':
        return 'blue';
      default:
        return 'default';
    }
  };

  const getActionButtons = (approval: PendingApproval) => (
    <Space size="small">
      <Tooltip title="Approve">
        <Button
          type="primary"
          size="small"
          icon={<CheckCircleOutlined />}
          onClick={() => handleAction(approval, 'approve')}
        />
      </Tooltip>
      <Tooltip title="Reject">
        <Button
          danger
          size="small"
          icon={<CloseCircleOutlined />}
          onClick={() => handleAction(approval, 'reject')}
        />
      </Tooltip>
      <Tooltip title="Flag for Review">
        <Button
          size="small"
          icon={<FlagOutlined />}
          onClick={() => handleAction(approval, 'flag')}
        />
      </Tooltip>
      <Tooltip title="Add Comment">
        <Button
          size="small"
          icon={<CommentOutlined />}
          onClick={() => handleAction(approval, 'comment')}
        />
      </Tooltip>
    </Space>
  );

  return (
    <>
      <Card
        title={`Steward Approvals (${pendingApprovals.length})`}
        size="small"
        extra={
          <Button size="small" onClick={fetchPendingApprovals}>
            Refresh
          </Button>
        }
      >
        <List
          loading={loading}
          dataSource={pendingApprovals}
          renderItem={(approval) => (
            <List.Item
              key={approval.node_id}
              actions={[getActionButtons(approval)]}
            >
              <List.Item.Meta
                avatar={<Avatar icon={<UserOutlined />} />}
                title={
                  <Space>
                    <span>{approval.name}</span>
                    <Tag color={getStatusColor(approval.review_status)}>
                      {approval.review_status.replace('_', ' ')}
                    </Tag>
                    <Tag size="small">{approval.node_type}</Tag>
                  </Space>
                }
                description={
                  <div>
                    <p className={styles.approvalDescription}>{approval.description}</p>
                    <p className={styles.approvalMeta}>
                      Created {formatDistanceToNow(new Date(approval.created_at), { addSuffix: true })}
                    </p>
                  </div>
                }
              />
            </List.Item>
          )}
        />
      </Card>

      <Modal
        title={`${actionType.charAt(0).toUpperCase() + actionType.slice(1)} Approval`}
        open={actionModalVisible}
        onCancel={() => setActionModalVisible(false)}
        footer={null}
      >
        <Form
          form={form}
          layout="vertical"
          onFinish={handleActionSubmit}
        >
          {selectedApproval && (
            <div className={styles.modalApprovalInfo}>
              <h4>{selectedApproval.name}</h4>
              <p>{selectedApproval.description}</p>
              <Tag>{selectedApproval.node_type}</Tag>
            </div>
          )}

          {actionType === 'approve' && (
            <Form.Item
              name="golden_path"
              label="Add to Golden Path"
              valuePropName="checked"
            >
              <Checkbox>Add this metric to the golden path for future reuse</Checkbox>
            </Form.Item>
          )}

          {actionType === 'flag' && (
            <Form.Item
              name="severity"
              label="Severity"
              rules={[{ required: true, message: 'Please select severity' }]}
            >
              <Select placeholder="Select severity">
                <Option value="low">Low</Option>
                <Option value="medium">Medium</Option>
                <Option value="high">High</Option>
                <Option value="critical">Critical</Option>
              </Select>
            </Form.Item>
          )}

          <Form.Item
            name="comment"
            label={actionType === 'comment' ? 'Comment' : 'Feedback'}
            rules={[{ required: actionType !== 'approve', message: 'Please provide feedback' }]}
          >
            <TextArea
              rows={4}
              placeholder={
                actionType === 'approve' ? 'Optional approval notes...' :
                actionType === 'reject' ? 'Please provide reason for rejection...' :
                actionType === 'flag' ? 'Please describe the issue...' :
                'Add your comment...'
              }
            />
          </Form.Item>

          <Form.Item>
            <Space>
              <Button type="primary" htmlType="submit">
                {actionType.charAt(0).toUpperCase() + actionType.slice(1)}
              </Button>
              <Button onClick={() => setActionModalVisible(false)}>
                Cancel
              </Button>
            </Space>
          </Form.Item>
        </Form>
      </Modal>
    </>
  );
};

export default StewardApprovalPanel;

