  const [showUpdateDialog, setShowUpdateDialog] = useState(false);

  useEffect(() => {
    fetchReviews();
  }, []);

  const fetchReviews = async () => {
    setLoading(true);
    try {
      const response = await fetch('/api/pop/reviews');
      if (!response.ok) throw new Error('Failed to fetch reviews');

      const data = await response.json();
      setReviews(data.reviews || []);
    } catch (error) {
  import('../../utils/devLogger').then(({ devError }) => devError('Error fetching reviews:', error)).catch(() => {});
    } finally {
      setLoading(false);
    }
  };

  const handleCreateReview = async (reviewData: Partial<StewardReview>) => {
    try {
      const response = await fetch('/api/pop/reviews', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(reviewData),
      });

      if (!response.ok) throw new Error('Failed to create review');

      fetchReviews();
      setShowCreateDialog(false);
    } catch (error) {
  import('../../utils/devLogger').then(({ devError }) => devError('Error creating review:', error)).catch(() => {});
      alert('Failed to create review');
