interface AuditEvent {
  id: string;
  timestamp: string;
  event_type: string;
  severity: string;
  user_id: string;
  tenant_id: string;
  resource_type: string;
  resource_id: string;
  action: string;
  ip_address: string;
  success: boolean;
  error_message?: string;
  details: { [key: string]: any };
}

interface AuditSummary {
  total_events: number;
  events_by_type: { [key: string]: number };
  events_by_severity: { [key: string]: number };
  events_by_user: { [key: string]: number };
  recent_events: AuditEvent[];
  time_range: {
    start: string;
    end: string;
  };
}

export const AuditDashboard: React.FC = () => {
  const [activeTab, setActiveTab] = useState(0);
  const [events, setEvents] = useState<AuditEvent[]>([]);
  const [summary, setSummary] = useState<AuditSummary | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [selectedEvent, setSelectedEvent] = useState<AuditEvent | null>(null);
  const [showEventDetails, setShowEventDetails] = useState(false);

  // Filters
  const [filters, setFilters] = useState({
    user_id: '',
    event_type: '',
    severity: '',
    resource_type: '',
    start_date: null as Date | null,
    end_date: null as Date | null,
    success: '',
  });

  const loadAuditData = React.useCallback(async () => {
    try {
      setLoading(true);
      setError(null);

      // Load summary
      const summaryResponse = await fetch('/api/audit/summary');
      if (!summaryResponse.ok) {
        throw { message: 'Failed to load audit summary' };
      }
      const summaryData = await summaryResponse.json();
      setSummary(summaryData);

      // Load events with filters
      const queryParams = new URLSearchParams();
      Object.entries(filters).forEach(([key, value]) => {
        if (value && value !== '') {
          if (value instanceof Date) {
            queryParams.append(key, value.toISOString());
          } else {
            queryParams.append(key, value.toString());
          }
        }
      });

      const eventsResponse = await fetch(`/api/audit/events?${queryParams}`);
      if (!eventsResponse.ok) {
        throw { message: 'Failed to load audit events' };
      }
      const eventsData = await eventsResponse.json();
      setEvents(eventsData.events || []);

    } catch (err: any) {
      setError(err?.message || 'Failed to load audit data');
    } finally {
      setLoading(false);
    }
  }, [filters]);

  useEffect(() => {
    loadAuditData();
  }, [loadAuditData]);

  const handleFilterChange = (field: string, value: any) => {
    setFilters(prev => ({
      ...prev,
      [field]: value,
    }));
  };

  const handleTabChange = (_event: React.SyntheticEvent, newValue: number) => {
    setActiveTab(newValue);
  };

  const handleViewEventDetails = (event: AuditEvent) => {
    setSelectedEvent(event);
    setShowEventDetails(true);
  };

  const handleExportEvents = async () => {
    try {
      const response = await fetch('/api/audit/export', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          filter: filters,
          format: 'csv',
          report_name: `audit_export_${new Date().toISOString().split('T')[0]}`,
        }),
      });

      if (!response.ok) {
        throw { message: 'Export failed' };
      }

      // Trigger download
      const blob = await response.blob();
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `audit_export_${new Date().toISOString().split('T')[0]}.csv`;
      document.body.appendChild(a);
      a.click();
      window.URL.revokeObjectURL(url);
      document.body.removeChild(a);

    } catch (err) {
      setError('Failed to export audit events');
    }
  };

  const getSeverityIcon = (severity: string) => {
    switch (severity) {
      case 'critical':
        return <Error color="error" />;
      case 'high':
        return <Warning color="warning" />;
      case 'medium':
        return <Info color="info" />;
      case 'low':
        return <CheckCircle color="success" />;
      default:
        return <Info />;
    }
  };

  const getSeverityColor = (severity: string) => {
    switch (severity) {
      case 'critical':
        return 'error';
      case 'high':
        return 'warning';
      case 'medium':
        return 'info';
      case 'low':
        return 'success';
      default:
        return 'default';
    }
  };

  const getEventTypeColor = (eventType: string) => {
    if (eventType.includes('login')) return 'primary';
    if (eventType.includes('data')) return 'secondary';
    if (eventType.includes('config')) return 'warning';
    if (eventType.includes('violation')) return 'error';
    return 'default';
  };

  if (loading && !summary) {
    return (
      <Box display="flex" justifyContent="center" alignItems="center" minHeight="400px">
        <CircularProgress />
      </Box>
    );
  }

  return (
    <LocalizationProvider dateAdapter={AdapterDateFns}>
      <Box sx={{ p: 3 }}>
        <Box display="flex" justifyContent="space-between" alignItems="center" mb={3}>
          <Box display="flex" alignItems="center">
            <Security sx={{ mr: 2, fontSize: 32 }} />
            <Typography variant="h4" component="h1">
              Audit Trail & Compliance
            </Typography>
          </Box>
          <Box>
            <Button
              variant="outlined"
              startIcon={<Refresh />}
              onClick={loadAuditData}
              sx={{ mr: 2 }}
            >
              Refresh
            </Button>
            <Button
              variant="contained"
              startIcon={<Download />}
              onClick={handleExportEvents}
            >
              Export
            </Button>
          </Box>
        </Box>

        {error && (
          <Alert severity="error" sx={{ mb: 3 }}>
            {error}
          </Alert>
        )}

        <Tabs value={activeTab} onChange={handleTabChange} sx={{ mb: 3 }}>
          <Tab label="Overview" />
          <Tab label="Audit Events" />
          <Tab label="Compliance Reports" />
        </Tabs>

        {activeTab === 0 && summary && (
          <Grid container spacing={3}>
            {/* Summary Cards */}
            <Grid item xs={12} md={3}>
              <Card>
                <CardContent>
                  <Typography color="textSecondary" gutterBottom>
                    Total Events
                  </Typography>
                  <Typography variant="h4">
                    {summary.total_events.toLocaleString()}
                  </Typography>
                </CardContent>
              </Card>
            </Grid>

            <Grid item xs={12} md={3}>
              <Card>
                <CardContent>
                  <Typography color="textSecondary" gutterBottom>
                    Critical Events
                  </Typography>
                  <Typography variant="h4" color="error">
                    {(summary.events_by_severity?.critical || 0).toLocaleString()}
                  </Typography>
                </CardContent>
              </Card>
            </Grid>

            <Grid item xs={12} md={3}>
              <Card>
                <CardContent>
                  <Typography color="textSecondary" gutterBottom>
                    Data Access Events
                  </Typography>
                  <Typography variant="h4" color="primary">
                    {(summary.events_by_type?.data_access || 0).toLocaleString()}
                  </Typography>
                </CardContent>
              </Card>
            </Grid>

            <Grid item xs={12} md={3}>
              <Card>
                <CardContent>
                  <Typography color="textSecondary" gutterBottom>
                    Failed Operations
                  </Typography>
                  <Typography variant="h4" color="warning">
                    {events.filter(e => !e.success).length.toLocaleString()}
                  </Typography>
                </CardContent>
              </Card>
            </Grid>

            {/* Recent Events */}
            <Grid item xs={12}>
              <Card>
                <CardContent>
                  <Typography variant="h6" gutterBottom>
                    Recent Audit Events
                  </Typography>
                  <TableContainer>
                    <Table size="small">
                      <TableHead>
                        <TableRow>
