interface APIEndpoint {
  id: string;
  path: string;
  method: string;
  description: string;
  category: string;
  service: string;
  version: string;
  status: 'active' | 'deprecated' | 'beta';
  lastUpdated: string;
  businessTerms: string[];
  dependencies: string[];
}

interface BusinessTerm {
  id: string;
  name: string;
  description: string;
  category: string;
  owner: string;
  status: string;
  relatedAPIs: string[];
}

const APICatalogPage: React.FC = () => {
