              <Card sx={{ height: '100%', cursor: 'pointer' }} onClick={() => setSelectedAPI(api)}>
                <CardContent>
                  <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', mb: 2 }}>
                    <Typography variant="h6" component="div">
                      {api.method} {api.path}
