  Link
} from '@mui/material';
import {
  Add as AddIcon,
  Edit as EditIcon,
  Delete as DeleteIcon,
  Search as SearchIcon,
  FilterList as FilterIcon,
  ExpandMore as ExpandMoreIcon,
  ExpandLess as ExpandLessIcon,
  Refresh as RefreshIcon,
  Download as DownloadIcon,
  MoreVert as MoreVertIcon,
  Home as HomeIcon,
  ChevronRight as ChevronRightIcon
} from '@mui/icons-material';
import { IPWhitelistEntry, Tenant, ALL_TENANTS_ID, ALL_TENANTS_DISPLAY_NAME } from '../types/ipWhitelist';
import { useIPWhitelistAPI, useIPWhitelistFilters } from '../hooks/useIPWhitelist';
import IPAddEditDialog from './IPAddEditDialog';
import IPDeleteDialog from './IPDeleteDialog';
import { exportIPWhitelistReport } from '../utils/exportUtils';

interface IPManagementViewProps {
  selectedTenantId?: string;
}

const IPManagementView: React.FC<IPManagementViewProps> = ({ selectedTenantId }) => {
  const [entries, setEntries] = useState<IPWhitelistEntry[]>([]);
  const [tenants, setTenants] = useState<Tenant[]>([]);
  const [page, setPage] = useState(0);
  const [rowsPerPage, setRowsPerPage] = useState(25);
  const [showFilters, setShowFilters] = useState(true); // Default to showing filters
  const [addDialogOpen, setAddDialogOpen] = useState(false);
  const [editDialogOpen, setEditDialogOpen] = useState(false);
  const [deleteDialogOpen, setDeleteDialogOpen] = useState(false);
  const [selectedEntry, setSelectedEntry] = useState<IPWhitelistEntry | null>(null);
  const [exportMenuAnchor, setExportMenuAnchor] = useState<null | HTMLElement>(null);

  const api = useIPWhitelistAPI();
  const { filters, setFilters, filteredEntries } = useIPWhitelistFilters(entries, tenants);

  const loadData = React.useCallback(async () => {
    try {
      const [tenantsData, entriesData] = await Promise.all([
        api.fetchTenants(),
        api.fetchAllIPWhitelist()
      ]);

      setTenants(tenantsData);
      setEntries(entriesData);
    } catch (err) {
      console.error('Failed to load data:', err);
    }
  }, [api]);

  useEffect(() => {
    loadData();
  }, [loadData]);

  const handleAddIP = async (ipData: {
    ipAddress: string;
    label?: string;
    description?: string;
    tenantIds: string[];
    allTenants?: boolean;
  }) => {
    const primaryTenant = ipData.allTenants ? ALL_TENANTS_ID : ipData.tenantIds[0];
    const additionalTenants = ipData.allTenants ? [] : ipData.tenantIds.slice(1);

    await api.addIPWhitelist(
      primaryTenant,
      ipData.ipAddress,
      ipData.label,
      ipData.description,
      additionalTenants,
      { allTenants: ipData.allTenants }
    );

    await loadData();
  };

  const handleEditIP = async (ipData: {
    ipAddress: string;
    label?: string;
    description?: string;
    tenantIds: string[];
    allTenants?: boolean;
  }) => {
    if (!selectedEntry) return;

    // For editing, we need to update tenant assignments
    await api.updateIPAssignments(
      selectedEntry.ipAddress,
      selectedEntry.tenantIds[0] || '',
  ipData.tenantIds,
  { allTenants: ipData.allTenants, prevTenantIds: selectedEntry.tenantIds }
    );

    await loadData();
  };

  const handleDeleteIP = async () => {
    if (!selectedEntry) return;

    // Remove from all tenants (this will delete the entry if no tenants remain)
    const primaryTenant = selectedEntry.tenantIds[0];
    if (primaryTenant) {
      await api.removeIPWhitelist(primaryTenant, selectedEntry.ipAddress, selectedEntry.tenantIds);
    }

    await loadData();
  };

  const handleFilterChange = (key: keyof typeof filters, value: any) => {
    setFilters(prev => ({ ...prev, [key]: value }));
    setPage(0); // Reset to first page when filtering
  };

  const handleSort = (sortBy: typeof filters.sortBy) => {
    const newOrder = filters.sortBy === sortBy && filters.sortOrder === 'asc' ? 'desc' : 'asc';
    setFilters(prev => ({ ...prev, sortBy, sortOrder: newOrder }));
  };

  const handleExportMenuOpen = (event: React.MouseEvent<HTMLElement>) => {
    setExportMenuAnchor(event.currentTarget);
  };

  const handleExportMenuClose = () => {
    setExportMenuAnchor(null);
  };

  const handleExport = (format: 'csv' | 'json') => {
    exportIPWhitelistReport(filteredEntries, tenants, format);
    handleExportMenuClose();
  };

  const paginatedEntries = filteredEntries.slice(page * rowsPerPage, page * rowsPerPage + rowsPerPage);

  const getTenantNames = (entry: IPWhitelistEntry) => {
    // Prefer explicit allTenants flag from backend; otherwise detect pseudo-id in list
    if ((entry as any).allTenants || entry.tenantIds.includes(ALL_TENANTS_ID)) {
      return [ALL_TENANTS_DISPLAY_NAME];
    }
    return entry.tenantIds.map(id => tenants.find(t => t.id === id)?.displayName || id);
  };

  const renderFilterControls = () => (
    <Collapse in={showFilters}>
      <Box sx={{ p: 2, bgcolor: 'grey.50', borderRadius: 1, mb: 2 }}>
        <Box sx={{ display: 'flex', gap: 2, flexWrap: 'wrap', alignItems: 'center' }}>
          <TextField
            size="small"
            placeholder="Search IP, label, or tenant..."
            value={filters.search}
            onChange={(e) => handleFilterChange('search', e.target.value)}
            InputProps={{
              startAdornment: <SearchIcon sx={{ mr: 1, color: 'action.active' }} />
            }}
            sx={{ minWidth: 250 }}
          />

          <FormControl size="small" sx={{ minWidth: 150 }}>
            <InputLabel>Tenant</InputLabel>
            <Select
              value={filters.tenantFilter}
              onChange={(e) => handleFilterChange('tenantFilter', e.target.value)}
              label="Tenant"
            >
              <MenuItem value="">All Tenants</MenuItem>
              {tenants.map(tenant => (
                <MenuItem key={tenant.id} value={tenant.id}>
                  {tenant.displayName}
                </MenuItem>
              ))}
            </Select>
          </FormControl>

          <FormControl size="small" sx={{ minWidth: 120 }}>
            <InputLabel>Status</InputLabel>
            <Select
              value={filters.statusFilter}
              onChange={(e) => handleFilterChange('statusFilter', e.target.value)}
              label="Status"
            >
              <MenuItem value="all">All</MenuItem>
              <MenuItem value="active">Active</MenuItem>
              <MenuItem value="inactive">Inactive</MenuItem>
            </Select>
          </FormControl>

          <Button
            variant="outlined"
            size="small"
            onClick={() => setFilters({
              search: '',
              tenantFilter: '',
              statusFilter: 'all',
              sortBy: 'ipAddress',
              sortOrder: 'asc'
            })}
          >
            Clear Filters
          </Button>
        </Box>
      </Box>
    </Collapse>
  );

  return (
    <Box>
      <Paper sx={{ p: 3 }}>
        {/* Breadcrumb Navigation */}
        <Box sx={{ mb: 2 }}>
          <Breadcrumbs aria-label="breadcrumb" separator={<ChevronRightIcon fontSize="small" />}>
            <Link
              underline="hover"
              color="inherit"
              href="/fabric"
              sx={{ display: 'flex', alignItems: 'center', gap: 0.5 }}
            >
              <HomeIcon fontSize="small" />
              Fabric
            </Link>
            <Typography color="text.primary" sx={{ display: 'flex', alignItems: 'center', gap: 0.5 }}>
              IP Whitelist Management
            </Typography>
            <Typography color="text.primary" sx={{ fontWeight: 'medium' }}>
              {selectedTenantId ? `Tenant: ${tenants.find(t => t.id === selectedTenantId)?.displayName || selectedTenantId}` : 'All IP Addresses'}
            </Typography>
          </Breadcrumbs>
        </Box>

        {/* Header */}
        <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 3 }}>
          <Box>
            <Typography variant="h5" component="h2">
              IP Address Management
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mt: 0.5 }}>
              {selectedTenantId 
                ? `Managing IP addresses for ${tenants.find(t => t.id === selectedTenantId)?.displayName || 'selected tenant'}`
                : `Managing ${filteredEntries.length} IP address entries across all tenants`
              }
            </Typography>
          </Box>
          <Box sx={{ display: 'flex', gap: 1 }}>
            <Tooltip title="Toggle Filters">
              <IconButton onClick={() => setShowFilters(!showFilters)}>
                {showFilters ? <ExpandLessIcon /> : <FilterIcon />}
              </IconButton>
            </Tooltip>
            <Tooltip title="Refresh">
              <span>
                <IconButton onClick={loadData} disabled={api.loading}>
                  <RefreshIcon />
                </IconButton>
              </span>
            </Tooltip>
            <Tooltip title="Export Data">
              <IconButton onClick={handleExportMenuOpen}>
                <DownloadIcon />
              </IconButton>
            </Tooltip>
            <Button
              variant="contained"
              startIcon={<AddIcon />}
              onClick={() => setAddDialogOpen(true)}
            >
              Add IP Address
            </Button>
          </Box>
        </Box>

        {/* Filters */}
        {renderFilterControls()}

        {/* Error Display */}
        {api.error && (
          <Alert severity="error" sx={{ mb: 2 }} onClose={() => api.setError(null)}>
            {api.error}
          </Alert>
        )}

        {/* Stats - Now Clickable Filters */}
        <Box sx={{ mb: 2, display: 'flex', gap: 2, flexWrap: 'wrap' }}>
          <Chip 
            label={`Total: ${entries.length}`} 
            variant="outlined" 
            onClick={() => setFilters(prev => ({ 
              ...prev, 
              search: '', 
              tenantFilter: 'all' 
            }))}
            clickable
            color={filters.search === '' && filters.tenantFilter === 'all' ? 'primary' : 'default'}
          />
          <Chip 
            label={`Filtered: ${filteredEntries.length}`} 
            variant="outlined" 
            color="info"
          />
          <Chip 
            label={`With Tenants: ${entries.filter(e => e.tenantIds.length > 0).length}`} 
            variant="outlined"
            onClick={() => setFilters(prev => ({ ...prev, tenantFilter: 'assigned' }))}
            clickable
            color={filters.tenantFilter === 'assigned' ? 'primary' : 'default'}
          />
          <Chip 
            label={`Unassigned: ${entries.filter(e => e.tenantIds.length === 0).length}`} 
            variant="outlined"
            onClick={() => setFilters(prev => ({ ...prev, tenantFilter: 'unassigned' }))}
            clickable
            color={filters.tenantFilter === 'unassigned' ? 'primary' : 'default'}
          />
        </Box>

        {/* Table */}
        <TableContainer>
          <Table>
            <TableHead>
              <TableRow>
                <TableCell 
                  sortDirection={filters.sortBy === 'ipAddress' ? filters.sortOrder : false}
                  sx={{ cursor: 'pointer' }}
                  onClick={() => handleSort('ipAddress')}
                >
                  IP Address
                </TableCell>
                <TableCell 
                  sortDirection={filters.sortBy === 'label' ? filters.sortOrder : false}
                  sx={{ cursor: 'pointer' }}
                  onClick={() => handleSort('label')}
                >
                  Label
                </TableCell>
                <TableCell>Description</TableCell>
                <TableCell 
                  sortDirection={filters.sortBy === 'tenantCount' ? filters.sortOrder : false}
                  sx={{ cursor: 'pointer' }}
                  onClick={() => handleSort('tenantCount')}
                >
                  Assigned Tenants
                </TableCell>
                <TableCell>Assignment Status</TableCell>
                <TableCell>Actions</TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {api.loading ? (
                <TableRow>
                  <TableCell colSpan={6} align="center">
                    Loading...
                  </TableCell>
                </TableRow>
              ) : paginatedEntries.length === 0 ? (
                <TableRow>
                  <TableCell colSpan={6} align="center">
                    {filters.search || filters.tenantFilter ? 'No matching IP addresses found' : 'No IP addresses configured'}
                  </TableCell>
                </TableRow>
              ) : (
                paginatedEntries.map((entry, index) => (
                  <TableRow key={index} hover>
                    <TableCell>
                      <Typography variant="body2" fontFamily="monospace">
                        {entry.ipAddress}
                      </Typography>
                    </TableCell>
                    <TableCell>
                      {entry.label || <Typography color="text.secondary">—</Typography>}
                    </TableCell>
                    <TableCell>
                      {entry.description ? (
                        <Tooltip title={entry.description}>
                          <Typography 
                            variant="body2" 
                            sx={{ 
                              maxWidth: 200, 
                              overflow: 'hidden', 
                              textOverflow: 'ellipsis',
                              whiteSpace: 'nowrap'
                            }}
                          >
                            {entry.description}
                          </Typography>
                        </Tooltip>
                      ) : (
                        <Typography color="text.secondary">—</Typography>
                      )}
                    </TableCell>
                    <TableCell>
                      <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 0.5, maxWidth: 300 }}>
                        {getTenantNames(entry).map((name, idx) => (
                          <Chip
                            key={idx}
                            label={name}
                            size="small"
                            color="primary"
                            variant="outlined"
                          />
                        ))}
                        {(entry as any).allTenants && (
                          <></>
                        )}
                        {!((entry as any).allTenants) && entry.tenantIds.length === 0 && (
                          <Chip label="Unassigned" size="small" color="warning" variant="outlined" />
                        )}
                      </Box>
                    </TableCell>
                    <TableCell>
                      <Chip
                        label={(entry as any).allTenants ? 'All Tenants' : (entry.tenantIds.length > 0 ? 'Assigned' : 'Unassigned')}
                        size="small"
                        color={(entry as any).allTenants ? 'info' : (entry.tenantIds.length > 0 ? 'success' : 'warning')}
                        variant="outlined"
                      />
                    </TableCell>
                    <TableCell>
                      <Box sx={{ display: 'flex', gap: 0.5 }}>
                        <Tooltip title="Edit">
                          <span>
                            <IconButton
                              size="small"
                              onClick={() => {
                                setSelectedEntry(entry);
                                setEditDialogOpen(true);
                              }}
                            >
                              <EditIcon fontSize="small" />
                            </IconButton>
                          </span>
                        </Tooltip>
                        <Tooltip title="Delete">
                          <span>
                            <IconButton
                              size="small"
                              color="error"
                              onClick={() => {
                                setSelectedEntry(entry);
                                setDeleteDialogOpen(true);
                              }}
                            >
                              <DeleteIcon fontSize="small" />
                            </IconButton>
                          </span>
                        </Tooltip>
                      </Box>
                    </TableCell>
                  </TableRow>
                ))
              )}
            </TableBody>
          </Table>
        </TableContainer>

        {/* Pagination */}
        <TablePagination
          component="div"
          count={filteredEntries.length}
          page={page}
          onPageChange={(_, newPage) => setPage(newPage)}
          rowsPerPage={rowsPerPage}
          onRowsPerPageChange={(e) => {
            setRowsPerPage(parseInt(e.target.value, 10));
            setPage(0);
          }}
          rowsPerPageOptions={[10, 25, 50, 100]}
        />
      </Paper>

      {/* Dialogs */}
      <IPAddEditDialog
        open={addDialogOpen}
        onClose={() => setAddDialogOpen(false)}
        onSave={handleAddIP}
        tenants={tenants}
        initialTenantId={selectedTenantId}
      />

      <IPAddEditDialog
        open={editDialogOpen}
        onClose={() => {
          setEditDialogOpen(false);
          setSelectedEntry(null);
        }}
        onSave={handleEditIP}
        tenants={tenants}
        editingEntry={selectedEntry}
      />

      <IPDeleteDialog
        open={deleteDialogOpen}
        onClose={() => {
          setDeleteDialogOpen(false);
          setSelectedEntry(null);
        }}
        onConfirm={handleDeleteIP}
        entry={selectedEntry}
        tenants={tenants}
      />

      {/* Export Menu */}
      <Menu
        anchorEl={exportMenuAnchor}
        open={Boolean(exportMenuAnchor)}
        onClose={handleExportMenuClose}
      >
        <MenuItem onClick={() => handleExport('csv')}>
          <ListItemIcon>
            <DownloadIcon fontSize="small" />
          </ListItemIcon>
          <ListItemText>Export as CSV</ListItemText>
        </MenuItem>
        <MenuItem onClick={() => handleExport('json')}>
          <ListItemIcon>
            <DownloadIcon fontSize="small" />
          </ListItemIcon>
          <ListItemText>Export as JSON</ListItemText>
        </MenuItem>
      </Menu>
    </Box>
  );
};

export default IPManagementView;

import React from 'react';
import { Box, Typography, Paper, Chip, List, ListItem, ListItemIcon, ListItemText, Alert } from '@mui/material';
import PeopleIcon from '@mui/icons-material/People';
import ArticleIcon from '@mui/icons-material/Article';
import GppMaybeIcon from '@mui/icons-material/GppMaybe';
import { PolicySimulationResult } from '../../../types';

interface PolicySimulationResultViewerProps {
  result: PolicySimulationResult;
}

const ImpactCard: React.FC<{ title: string; count: number; icon: React.ReactElement }> = ({ title, count, icon }) => (
  <Paper variant="outlined" sx={{ p: 2, display: 'flex', alignItems: 'center', gap: 2 }}>
    {icon}
    <Box>
      <Typography variant="h6">{count}</Typography>
      <Typography variant="body2" color="text.secondary">{title}</Typography>
    </Box>
  </Paper>
);

export default function PolicySimulationResultViewer({ result }: PolicySimulationResultViewerProps) {
  const { affected_claims, affected_users, affected_assets, risk_flags } = result;

  return (
    <Box sx={{ mt: 3 }}>
      <Typography variant="h5" gutterBottom>Simulation Impact</Typography>
      <Box sx={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: 2, mb: 3 }}>
        <ImpactCard title="Affected Users" count={affected_users.length} icon={<PeopleIcon color="primary" />} />
        <ImpactCard title="Affected Assets" count={affected_assets.length} icon={<ArticleIcon color="primary" />} />
      </Box>

      {risk_flags.length > 0 && (
        <Box sx={{ mb: 3 }}>
          <Typography variant="h6" gutterBottom>Risk Summary</Typography>
          <Alert severity="warning" icon={<GppMaybeIcon />}>
            <List dense>
              {risk_flags.map((flag, index) => (
                <ListItem key={index} disableGutters>
                  <ListItemText primary={flag} />
                </ListItem>
              ))}
            </List>
          </Alert>
        </Box>
      )}

      <Box>
        <Typography variant="h6" gutterBottom>Claim Changes</Typography>
        <Paper variant="outlined" sx={{ p: 2, display: 'flex', justifyContent: 'space-around' }}>
          <Chip label={`Added: ${affected_claims.added}`} color="success" />
          <Chip label={`Modified: ${affected_claims.modified}`} color="warning" />
          <Chip label={`Removed: ${affected_claims.removed}`} color="error" />
        </Paper>
      </Box>
    </Box>
  );
}

import React, { useState, useEffect, useMemo } from 'react';
import {
  Box,
  Paper,
  Typography,
  TextField,
  FormControl,
  InputLabel,
  Select,
  MenuItem,
  Button,
  IconButton,
  Chip,
  Card,
  CardContent,
  CardActions,
  Grid,
  Tooltip,
  Alert,
  Collapse,
  List,
  ListItem,
  ListItemText,
  ListItemSecondaryAction,
  Divider,
  Avatar,
  Menu,
  ListItemIcon,
  Breadcrumbs,
  Link
} from '@mui/material';
import {
  Search as SearchIcon,
  FilterList as FilterIcon,
  ExpandMore as ExpandMoreIcon,
  ExpandLess as ExpandLessIcon,
  Refresh as RefreshIcon,
  Business as BusinessIcon,
  Computer as ComputerIcon,
  Add as AddIcon,
  Remove as RemoveIcon,
  Delete as DeleteIcon,
  Download as DownloadIcon,
  MoreVert as MoreVertIcon,
  Home as HomeIcon,
  ChevronRight as ChevronRightIcon
} from '@mui/icons-material';
import { Tenant, TenantIPSummary, IPWhitelistEntry, TenantFilters } from '../types/ipWhitelist';
import EditIcon from '@mui/icons-material/Edit';
import TenantIPDetailModal from './TenantIPDetailModal';
import { useIPWhitelistAPI } from '../hooks/useIPWhitelist';
import IPAddEditDialog from './IPAddEditDialog';
import { exportTenantReport } from '../utils/exportUtils';
import TenantTypeahead from './TenantTypeahead';

const TenantManagementView: React.FC = () => {
  const [tenants, setTenants] = useState<Tenant[]>([]);
  const [tenantIPData, setTenantIPData] = useState<Map<string, IPWhitelistEntry[]>>(new Map());
  const [showFilters, setShowFilters] = useState(true); // Default to showing filters
  const [selectedTenant, setSelectedTenant] = useState<string | null>(null);
  const [addIPDialogOpen, setAddIPDialogOpen] = useState(false);
  const [exportMenuAnchor, setExportMenuAnchor] = useState<null | HTMLElement>(null);
  const [detailOpen, setDetailOpen] = useState(false);
  const [detailTenant, setDetailTenant] = useState<Tenant | null>(null);

  const [filters, setFilters] = useState<TenantFilters>({
    search: '',
    hasIPs: 'all',
    sortBy: 'displayName',
    sortOrder: 'asc',
    selectedTenantIds: []
  });

  const api = useIPWhitelistAPI();

  const loadData = React.useCallback(async () => {
    try {
      const tenantsData = await api.fetchTenants();
      setTenants(tenantsData);

      // Load IP data for each tenant
      const ipDataMap = new Map<string, IPWhitelistEntry[]>();
      await Promise.all(
        tenantsData.map(async (tenant) => {
          try {
            const ips = await api.fetchTenantIPWhitelist(tenant.id);
            ipDataMap.set(tenant.id, ips);
          } catch (err) {
            ipDataMap.set(tenant.id, []);
          }
        })
      );

      setTenantIPData(ipDataMap);
    } catch (err) {
      console.error('Failed to load tenant data:', err);
    }
  }, [api]);

  useEffect(() => {
    loadData();
  }, [loadData]);

  const tenantSummaries = useMemo((): TenantIPSummary[] => {
    return tenants.map(tenant => {
      const ipAddresses = tenantIPData.get(tenant.id) || [];
      return {
        tenant,
        ipAddresses,
        totalIPs: ipAddresses.length,
        activeIPs: ipAddresses.length // Simplified - remove isActive check for now
      };
    });
  }, [tenants, tenantIPData]);

  const filteredTenants = useMemo(() => {
    let filtered = [...tenantSummaries];

    // Tenant selection filter
    if (filters.selectedTenantIds && filters.selectedTenantIds.length > 0) {
      filtered = filtered.filter(summary => 
        filters.selectedTenantIds.includes(summary.tenant.id)
      );
    }

    // Search filter
    if (filters.search) {
      const searchLower = filters.search.toLowerCase();
      filtered = filtered.filter(summary => 
        summary.tenant.displayName.toLowerCase().includes(searchLower) ||
        summary.tenant.displayName?.toLowerCase().includes(searchLower) ||
        summary.tenant.id?.toLowerCase().includes(searchLower) ||
        summary.ipAddresses.some(ip => 
          ip.ipAddress.toLowerCase().includes(searchLower) ||
          (ip.label && ip.label.toLowerCase().includes(searchLower))
        )
      );
    }

    // IP filter
    if (filters.hasIPs !== 'all') {
      filtered = filtered.filter(summary => {
        const hasIPs = summary.totalIPs > 0;
        return filters.hasIPs === 'with-ips' ? hasIPs : !hasIPs;
      });
    }

    // Sort
    filtered.sort((a, b) => {
      let aValue: any, bValue: any;

      switch (filters.sortBy) {
        case 'displayName':
          aValue = a.tenant.displayName;
          bValue = b.tenant.displayName;
          break;
        case 'ipCount':
          aValue = a.totalIPs;
          bValue = b.totalIPs;
          break;
        case 'lastAssigned':
          // For now, sort by IP count as we don't have lastAssigned data
          aValue = a.totalIPs;
          bValue = b.totalIPs;
          break;
        default:
          aValue = a.tenant.displayName;
          bValue = b.tenant.displayName;
      }

      if (typeof aValue === 'string') {
        aValue = aValue.toLowerCase();
        bValue = bValue.toLowerCase();
      }

      const comparison = aValue < bValue ? -1 : aValue > bValue ? 1 : 0;
      return filters.sortOrder === 'asc' ? comparison : -comparison;
    });

    return filtered;
  }, [tenantSummaries, filters]);

  const handleAddIP = async (ipData: {
    ipAddress: string;
    label?: string;
    description?: string;
    tenantIds: string[];
  }) => {
    if (!selectedTenant) return;

    const primaryTenant = ipData.tenantIds[0];
    const additionalTenants = ipData.tenantIds.slice(1);

    await api.addIPWhitelist(
      primaryTenant,
      ipData.ipAddress,
      ipData.label,
      ipData.description,
      additionalTenants
    );

    await loadData();
  };

  const handleRemoveIP = async (tenantId: string, ipAddress: string) => {
    await api.removeIPWhitelist(tenantId, ipAddress);
    await loadData();
  };

  const handleFilterChange = (key: keyof TenantFilters, value: any) => {
    setFilters(prev => ({ ...prev, [key]: value }));
  };

  const handleExportMenuOpen = (event: React.MouseEvent<HTMLElement>) => {
    setExportMenuAnchor(event.currentTarget);
  };

  const handleExportMenuClose = () => {
    setExportMenuAnchor(null);
  };

  const handleExport = (format: 'csv' | 'json') => {
    exportTenantReport(filteredTenants, format);
    handleExportMenuClose();
  };

  const renderFilterControls = () => (
    <Collapse in={showFilters}>
      <Box sx={{ p: 2, bgcolor: 'grey.50', borderRadius: 1, mb: 2 }}>
        <Box sx={{ display: 'flex', gap: 2, flexWrap: 'wrap', alignItems: 'center' }}>
          <Box sx={{ minWidth: 300 }}>
            <TenantTypeahead
              label="Filter by Tenant"
              value={filters.selectedTenantIds || []}
              onChange={(tenantIds) => handleFilterChange('selectedTenantIds', tenantIds)}
              tenants={tenants}
              multiple={true}
              placeholder="Search and filter by specific tenants..."
              size="small"
              allowAllTenants={false}
            />
          </Box>

          <TextField
            size="small"
            placeholder="Search IP addresses, labels..."
            value={filters.search}
            onChange={(e) => handleFilterChange('search', e.target.value)}
            InputProps={{
              startAdornment: <SearchIcon sx={{ mr: 1, color: 'action.active' }} />
            }}
            sx={{ minWidth: 250 }}
          />

          <FormControl size="small" sx={{ minWidth: 150 }}>
            <InputLabel>IP Status</InputLabel>
            <Select
              value={filters.hasIPs}
              onChange={(e) => handleFilterChange('hasIPs', e.target.value)}
              label="IP Status"
            >
              <MenuItem value="all">All Tenants</MenuItem>
              <MenuItem value="with-ips">With IPs</MenuItem>
              <MenuItem value="without-ips">Without IPs</MenuItem>
            </Select>
          </FormControl>

          <FormControl size="small" sx={{ minWidth: 120 }}>
            <InputLabel>Sort By</InputLabel>
            <Select
              value={filters.sortBy}
              onChange={(e) => handleFilterChange('sortBy', e.target.value)}
              label="Sort By"
            >
              <MenuItem value="displayName">Name</MenuItem>
              <MenuItem value="ipCount">IP Count</MenuItem>
              <MenuItem value="lastAssigned">Last Assigned</MenuItem>
            </Select>
          </FormControl>

          <FormControl size="small" sx={{ minWidth: 100 }}>
            <InputLabel>Order</InputLabel>
            <Select
              value={filters.sortOrder}
              onChange={(e) => handleFilterChange('sortOrder', e.target.value)}
              label="Order"
            >
              <MenuItem value="asc">Ascending</MenuItem>
              <MenuItem value="desc">Descending</MenuItem>
            </Select>
          </FormControl>

          <Button
            variant="outlined"
            size="small"
            onClick={() => setFilters({
              search: '',
              hasIPs: 'all',
              sortBy: 'displayName',
              sortOrder: 'asc',
              selectedTenantIds: []
            })}
          >
            Clear Filters
          </Button>
        </Box>
      </Box>
    </Collapse>
  );

  const [expandedTenants, setExpandedTenants] = useState<Record<string, boolean>>({});

  const toggleExpanded = (tenantId: string) => {
    setExpandedTenants(prev => ({ ...prev, [tenantId]: !prev[tenantId] }));
  };

  const renderTenantCard = (summary: TenantIPSummary) => (
    <Card key={summary.tenant.id} sx={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
      <CardContent sx={{ flexGrow: 1 }}>
        <Box sx={{ display: 'flex', alignItems: 'center', mb: 2 }}>
          <Avatar sx={{ bgcolor: 'primary.main', mr: 2 }}>
            <BusinessIcon />
          </Avatar>
          <Box sx={{ flexGrow: 1 }}>
            <Typography variant="h6" component="h3" noWrap>
              {summary.tenant.displayName}
            </Typography>
            {summary.tenant.description && (
              <Typography variant="body2" color="text.secondary">
                {summary.tenant.description}
              </Typography>
            )}
          </Box>
        </Box>

        <Box sx={{ display: 'flex', gap: 1, mb: 2 }}>
          <Chip
            label={`${summary.totalIPs} IPs`}
            size="small"
