    const [selectedTenantIds, setSelectedTenantIds] = useState<string[]>([]);
  const [allWhitelist, setAllWhitelist] = useState<{ ipAddress: string; label?: string | null; tenantIds: string[] }[]>([]);
    const [allWhitelistError, setAllWhitelistError] = useState<string | null>(null);
  const [allSearch, setAllSearch] = useState('');
  const [allOwnerFilter, setAllOwnerFilter] = useState<'all' | 'unassigned' | 'tenant'>('all');
  const [allOwnerTenantId, setAllOwnerTenantId] = useState<string>('');
  const [allSort, setAllSort] = useState<'ipAsc' | 'ipDesc' | 'labelAsc' | 'labelDesc'>('ipAsc');

    // When a conflict is set, automatically fetch owner tenant display names (if missing)
    // and fetch each owner's whitelist entries so the UI shows the conflict immediately.
    useEffect(() => {
      if (!conflict) return;
      (async () => {
        setLoadingConflictOwners(true);
        // If we don't yet know owners, attempt to discover by scanning tenants' whitelists.
        // Otherwise, ensure tenants list includes known owners and fetch their entries.
        let ownerIds = conflict.tenantIds || [];
        if (!ownerIds.length) {
          try {
            const tenantsResp = await fetch('/api/tenants');
            if (tenantsResp.ok) {
              const data = await tenantsResp.json();
              const raw = data.tenants || [];
              const normalized = raw.map((t: any) => ({ id: t.id, displayName: t.display_name || t.displayName || t.name || t.id }));
              setTenants(normalized);
              const discovered: string[] = [];
              const discoveredMap: Record<string, any[]> = {};
              for (const t of normalized) {
                try {
                  const wl = await fetch(`/api/tenants/${t.id}/ip-whitelist`);
                  if (wl.ok) {
                    const dj = await wl.json();
                    const list = dj.whitelist || [];
                    if ((list as any[]).some((e: any) => e.ipAddress === conflict.ipAddress)) {
                      discovered.push(t.id);
                      discoveredMap[t.id] = list;
                    }
                  }
                } catch { /* ignore per-tenant failures */ }
              }
              if (discovered.length) {
                ownerIds = discovered;
                setConflict({ ipAddress: conflict.ipAddress, tenantIds: discovered });
                setConflictOwnerEntries(discoveredMap);
              } else {
                // No owners found or not permitted to view; show empty map to reveal the UI section
                setConflictOwnerEntries({});
              }
            } else {
              setConflictOwnerEntries({});
            }
          } catch {
            setConflictOwnerEntries({});
          } finally {
            setLoadingConflictOwners(false);
          }
          return;
        }

        // We know ownerIds; ensure tenants state contains them and fetch their entries
        const missing = ownerIds.filter(id => !tenants.find(t => t.id === id));
        if (missing.length > 0) {
          try {
            const resp = await fetch('/api/tenants');
            if (resp.ok) {
              const data = await resp.json();
              const raw = data.tenants || [];
              const normalized = raw.map((t: any) => ({ id: t.id, displayName: t.display_name || t.displayName || t.name || t.id }));
              setTenants(normalized);
            }
          } catch { /* ignore */ }
        }

        const map: Record<string, any[]> = {};
        for (const tid of ownerIds) {
          try {
            const resp = await fetch(`/api/tenants/${tid}/ip-whitelist`);
            if (resp.ok) {
              const d = await resp.json();
              map[tid] = d.whitelist || [];
            } else {
              map[tid] = [];
            }
          } catch {
            map[tid] = [];
          }
        }
        setConflictOwnerEntries(map);
        setLoadingConflictOwners(false);
      })();
    }, [conflict, tenants]);

  // moved below fetch* declarations to avoid TS "used before assignment" complaints

  const fetchTenants = useCallback(async () => {
      setTenantsLoaded(false);
      // Try relative path first (works when proxying is configured). If that fails
      // (for example when running Vite dev server without a proxy), fall back to
      // common local gateway/backend URLs so the dropdown still works.
      const candidates = ['/api/tenants', 'http://localhost:8000/api/tenants', 'http://localhost:3000/api/tenants'];
      for (const url of candidates) {
        try {
          const resp = await fetch(url);
          if (!resp.ok) {
            // try next candidate
            continue;
          }
          const data = await resp.json();
          // Normalize tenant objects: backend may return display_name or displayName
          const raw = data.tenants || [];
          const normalized = raw.map((t: any) => ({
            id: t.id,
            displayName: t.display_name || t.displayName || t.name || t.id,
          }));
          setTenants(normalized);
          setTenantsLoaded(true);
          return;
        } catch (err) {
          // try next candidate
          continue;
        }
      }
      // If we fell through all candidates, mark loaded so UI can show fallback
      setTenants([]);
      setTenantsLoaded(true);
  }, []);

  // effects moved below callback declarations

  const fetchWhitelist = useCallback(async () => {
      setLoading(true);
      setError(null);
      try {
        const response = await fetch(`/api/tenants/${tenantId}/ip-whitelist`);
        if (response.ok) {
          const data = await response.json();
          setWhitelist(data.whitelist || []);
        } else {
          setError('Failed to fetch IP whitelist.');
        }
      } catch (err) {
        setError('An error occurred while fetching the IP whitelist.');
      } finally {
        setLoading(false);
      }
  }, [tenantId]);

  const fetchAllWhitelist = useCallback(async () => {
      setAllWhitelistError(null);
      const candidates = ['/api/ip-whitelist', 'http://localhost:8000/api/ip-whitelist', 'http://localhost:3000/api/ip-whitelist'];
      for (const url of candidates) {
        try {
          const resp = await fetch(url);
          if (!resp.ok) continue;
          const data = await resp.json();
          const wl = (data.whitelist || []).map((e: any) => ({
            ipAddress: e.ipAddress,
            label: e.label ?? null,
            tenantIds: Array.isArray(e.tenantIds) ? e.tenantIds : [],
          }));
          setAllWhitelist(wl);
          return;
        } catch {
          // try next
          continue;
        }
      }
      // Fallback: aggregate across all tenants if direct endpoint is unavailable (e.g., gateway not proxying it)
      try {
        // ensure we have tenants in state; if not, fetch them quickly
        let tenantList = tenants;
        if (!tenantList.length) {
          const tr = await fetch('/api/tenants');
          if (tr.ok) {
            const td = await tr.json();
            const raw = td.tenants || [];
            tenantList = raw.map((t: any) => ({ id: t.id, displayName: t.display_name || t.displayName || t.name || t.id }));
            setTenants(tenantList);
          }
        }
        // fetch each tenant's whitelist in parallel and merge
        const results = await Promise.allSettled(
          tenantList.map(t => fetch(`/api/tenants/${t.id}/ip-whitelist`).then(r => r.ok ? r.json() : { whitelist: [] }))
        );
        const byIp: Record<string, { ipAddress: string; label: string | null; tenantIds: Set<string> }> = {};
        results.forEach((res, idx) => {
          if (res.status !== 'fulfilled') return;
          const tid = tenantList[idx]?.id;
          const list = (res.value?.whitelist || []) as any[];
          list.forEach((e: any) => {
            const ip = e.ipAddress || e.ip_address;
            if (!ip) return;
            if (!byIp[ip]) byIp[ip] = { ipAddress: ip, label: e.label ?? null, tenantIds: new Set() };
            if (tid) byIp[ip].tenantIds.add(tid);
          });
        });
        const merged = Object.values(byIp).map(v => ({ ipAddress: v.ipAddress, label: v.label, tenantIds: Array.from(v.tenantIds) }));
        setAllWhitelist(merged);
        if (!merged.length) setAllWhitelistError('No system-wide whitelist entries found.');
      } catch {
        setAllWhitelist([]);
        setAllWhitelistError('Failed to load system-wide whitelist entries.');
      }
    }, [tenants]);

    const filteredSortedAll = useMemo(() => {
      const q = allSearch.trim().toLowerCase();
      let list = allWhitelist.filter(e => {
        const matchesText = !q || e.ipAddress.toLowerCase().includes(q) || (e.label || '').toLowerCase().includes(q);
        let matchesOwner = true;
        if (allOwnerFilter === 'unassigned') matchesOwner = e.tenantIds.length === 0;
        else if (allOwnerFilter === 'tenant') matchesOwner = allOwnerTenantId ? e.tenantIds.includes(allOwnerTenantId) : true;
        return matchesText && matchesOwner;
      });
      list = [...list].sort((a, b) => {
        const ipCmp = a.ipAddress.localeCompare(b.ipAddress, undefined, { numeric: true, sensitivity: 'base' });
        const labelA = (a.label || '').toLowerCase();
        const labelB = (b.label || '').toLowerCase();
        const labelCmp = labelA.localeCompare(labelB);
        switch (allSort) {
          case 'ipAsc': return ipCmp;
          case 'ipDesc': return -ipCmp;
          case 'labelAsc': return labelCmp;
          case 'labelDesc': return -labelCmp;
          default: return ipCmp;
        }
      });
      return list;
    }, [allWhitelist, allSearch, allOwnerFilter, allOwnerTenantId, allSort]);

    const handleAddIpAddress = async () => {
      if (!tenantId) {
        setError('Tenant not available. Please sign in or select a tenant.');
        return;
      }
      if (!ipAddress || !isValidIpOrWildcard(ipAddress)) {
        setError('Please enter a valid IPv4 address or wildcard pattern (e.g. 192.168.*.*).');
        return;
      }
      // Check for exact or overlapping patterns
      if (whitelist.find((i) => ipPatternsOverlap(i.ipAddress, ipAddress) || i.ipAddress === ipAddress)) {
        setError('IP address or pattern overlaps an existing whitelist entry.');
        return;
      }

      setLoading(true);
      setError(null);
      setSuccess(null);

      try {
        const response = await fetch(`/api/tenants/${tenantId}/ip-whitelist`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ ipAddress, label, tenantIds: selectedTenantIds }),
        });

        if (response.ok) {
          setWhitelist([...whitelist, { ipAddress, label: label || null }]);
          setIpAddress('');
          setLabel('');
          setSuccess('IP address added successfully.');
          // refresh system-wide list as well
          fetchAllWhitelist();
        } else {
          // Try to parse structured error with conflicting info
          let errorData: any = null;
          let parsed = false;
          try {
            const cloned = (response as any).clone ? response.clone() : null;
            if (cloned) {
              errorData = await cloned.json();
              parsed = true;
            }
          } catch { /* ignore */ }
          if (!parsed) {
            try {
              errorData = await response.json();
              parsed = true;
            } catch { /* ignore */ }
          }

          if (errorData && errorData.conflicting) {
            const c: any = errorData.conflicting;
            const ownerNames = (c.tenantIds || []).map((id: string) => tenants.find(t => t.id === id)?.displayName || id);
            setError(`IP pattern overlaps existing entry ${c.ipAddress} owned by: ${ownerNames.join(', ')}`);
            setConflict({ ipAddress: c.ipAddress, tenantIds: c.tenantIds || [] });
            setConflictOwnerEntries(null);
          } else {
            // Fallback: attempt to parse plain-text error to extract the conflicting IP
            let textMsg = '';
            try {
              textMsg = await response.text();
            } catch { /* ignore */ }
            const m = textMsg.match(/overlaps an existing whitelist entry:?\s*([0-9.*]+)/i)
              || textMsg.match(/overlaps existing entry\s*([0-9.*]+)/i);
            if (m && m[1]) {
              const conflictIp = m[1];
              setError(textMsg || 'IP address or pattern overlaps an existing whitelist entry.');
              setConflict({ ipAddress: conflictIp, tenantIds: [] });
              setConflictOwnerEntries(null);
            } else {
              setError((errorData && errorData.message) || textMsg || 'Failed to add IP address.');
              setConflict(null);
            }
          }
        }

  // helper functions hoisted above
      } catch (err) {
        setError('An error occurred while adding the IP address.');
      } finally {
        setLoading(false);
      }
    };

    const handleRemoveIpAddress = async (ipToRemove: string) => {
      if (!tenantId) {
        setError('Tenant not available. Please sign in or select a tenant.');
        return;
      }
      setLoading(true);
      setError(null);
      setSuccess(null);

      try {
        const response = await fetch(`/api/tenants/${tenantId}/ip-whitelist`, {
          method: 'DELETE',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ ipAddress: ipToRemove }),
        });

        if (response.ok) {
          setWhitelist(whitelist.filter((ip) => ip.ipAddress !== ipToRemove));
          setSuccess('IP address removed successfully.');
          // refresh system-wide list as well
          fetchAllWhitelist();
        } else {
          const errorData = await response.json();
          setError(errorData.message || 'Failed to remove IP address.');
        }
      } catch (err) {
        setError('An error occurred while removing the IP address.');
      } finally {
        setLoading(false);
      }
    };

    return (
      <Container maxWidth="md">
        <Paper elevation={3} sx={{ p: 4, mt: 4 }}>
          <Typography variant="h4" gutterBottom>
            IP Whitelist Management
          </Typography>
          <Typography variant="subtitle1" gutterBottom>
            Tenant: {(tenant as any)?.display_name || tenantId || 'Not selected'}
          </Typography>

          {error && <Alert severity="error" sx={{ mb: 2 }}>{error}</Alert>}
          {success && <Alert severity="success" sx={{ mb: 2 }}>{success}</Alert>}

          {conflict && (
            <Box sx={{ mb: 2 }}>
              {!conflictOwnerEntries ? (
                <Button
                  variant="outlined"
                  onClick={async () => {
                    setLoadingConflictOwners(true);
                    const map: Record<string, any[]> = {};
                    for (const tid of conflict.tenantIds) {
                      try {
                        const resp = await fetch(`/api/tenants/${tid}/ip-whitelist`);
                        if (resp.ok) {
                          const d = await resp.json();
                          map[tid] = d.whitelist || [];
                        } else {
                          map[tid] = [];
                        }
                      } catch (e) {
                        map[tid] = [];
                      }
                    }
                    setConflictOwnerEntries(map);
                    setLoadingConflictOwners(false);
                  }}
                  disabled={loadingConflictOwners}
                >
                  {loadingConflictOwners ? 'Loading owner entries...' : 'Show owner tenant entries'}
                </Button>
              ) : (
                <Paper variant="outlined" sx={{ p: 2, mt: 1 }}>
                  <Typography variant="subtitle2">Conflicting entry: {conflict.ipAddress}</Typography>
                  {Object.entries(conflictOwnerEntries).map(([tid, entries]) => (
                    <Box key={tid} sx={{ mt: 1 }}>
                      <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                        <Typography variant="caption" sx={{ fontWeight: 600 }}>
                          {tenants.find(t => t.id === tid)?.displayName || tid}
                        </Typography>
                        {isAdmin() && (
                          <>
                              <Button size="small" onClick={() => navigate(`/tenants?focus=${tid}`)}>Open Tenants</Button>
                              <Button size="small" onClick={() => setManageDialog({ open: true, ownerTenantId: tid })}>Manage</Button>
                            <Button size="small" color="error" onClick={async () => {
                              if (!confirm(`Remove assignment of ${conflict.ipAddress} from tenant ${tid}?`)) return;
                              try {
                                const resp = await fetch(`/api/tenants/${tid}/ip-whitelist`, {
                                  method: 'DELETE',
                                  headers: { 'Content-Type': 'application/json' },
                                  body: JSON.stringify({ ipAddress: conflict.ipAddress, tenantIds: [tid] }),
                                });
                                if (resp.ok) {
                                  const d = await (await fetch(`/api/tenants/${tid}/ip-whitelist`)).json();
                                  setConflictOwnerEntries((prev) => ({ ...(prev || {}), [tid]: d.whitelist || [] }));
                                  setSuccess('Assignment removed.');
                                } else {
                                  const e = await resp.json();
                                  setError(e.message || 'Failed to remove assignment.');
                                }
                              } catch (err) {
                                setError('Failed to remove assignment.');
                              }
                            }}>Remove assignment</Button>
                          </>
                        )}
                      </Box>
                      <List dense>
                        {entries.length ? entries.map((e: any) => (
                          <ListItem key={e.ipAddress}>
                            <ListItemText primary={e.ipAddress} secondary={e.label ? `Label: ${e.label}` : null} />
                          </ListItem>
                        )) : (
                          <ListItem>
                            <ListItemText primary="No entries visible or not permitted to view" />
                          </ListItem>
                        )}
                      </List>
                    </Box>
                  ))}
                </Paper>
              )}
            </Box>
          )}

          <Box sx={{ display: 'flex', alignItems: 'center', mb: 2 }}>
            <TextField
              label="New IP Address"
              variant="outlined"
              value={ipAddress}
              onChange={(e) => setIpAddress(e.target.value)}
              sx={{ flexGrow: 1, mr: 2 }}
              disabled={loading}
            />

            <TextField
              label="Label (optional)"
              variant="outlined"
              value={label}
              onChange={(e) => setLabel(e.target.value)}
              sx={{ width: 220, mr: 2 }}
              disabled={loading}
            />

            <Tooltip
              title={!isAdmin ? 'Only admin users may assign IP addresses to tenants. Contact your administrator to request access.' : ''}
              disableHoverListener={isAdmin()}
              disableFocusListener={isAdmin()}
              disableTouchListener={isAdmin()}
            >
            <span>
              <FormControl sx={{ width: 260, mr: 2 }}>
                <InputLabel id="tenant-select-label">Assign Tenants</InputLabel>
                <Select
                  labelId="tenant-select-label"
                  multiple
                  value={selectedTenantIds}
                  onChange={(e) => setSelectedTenantIds(e.target.value as string[])}
                  label="Assign Tenants"
                  renderValue={(selected) => (selected as string[]).map(id => tenants.find(t=>t.id===id)?.displayName||id).join(', ')}
                  disabled={!isAdmin() || (tenantsLoaded && tenants.length === 0)}
                >
                  {tenants.map((t) => (
                    <MenuItem key={t.id} value={t.id}>
                      {t.displayName}
                    </MenuItem>
                  ))}
                </Select>
              </FormControl>
            </span>
            </Tooltip>

            {tenantsLoaded && tenants.length === 0 && (
              <Alert severity="info" sx={{ mr: 2 }}>
                No tenants found. You won't be able to assign the IP address to tenants until at least one tenant exists or the API is reachable.
              </Alert>
            )}

            <Button
              variant="contained"
              color="primary"
              onClick={handleAddIpAddress}
              disabled={loading}
              startIcon={loading ? <CircularProgress size={20} /> : null}
            >
              Add
            </Button>
          </Box>

          {loading && !whitelist.length ? (
            <Box sx={{ display: 'flex', justifyContent: 'center', my: 4 }}>
              <CircularProgress />
            </Box>
          ) : (
            <List>
              {whitelist.map((ip) => (
                <ListItem
                  key={ip.ipAddress}
                  secondaryAction={
                    <IconButton
                      edge="end"
                      aria-label="delete"
                      onClick={() => handleRemoveIpAddress(ip.ipAddress)}
                      disabled={loading}
                    >
                      <DeleteIcon />
                    </IconButton>
                  }
                >
                  <ListItemText primary={ip.ipAddress} secondary={ip.label ? `Label: ${ip.label}` : null} />
                </ListItem>
              ))}
            </List>
          )}
        </Paper>
        <Paper elevation={1} sx={{ p: 3, mt: 3 }}>
          <Typography variant="h6" gutterBottom>
            All Whitelist Entries (system-wide)
          </Typography>
          {allWhitelistError && <Alert severity="warning" sx={{ mb: 2 }}>{allWhitelistError}</Alert>}
          <Box sx={{ display: 'flex', gap: 2, flexWrap: 'wrap', mb: 2 }}>
            <TextField
              label="Search (IP or label)"
              size="small"
              value={allSearch}
              onChange={(e) => setAllSearch(e.target.value)}
              sx={{ minWidth: 240 }}
            />
            <FormControl size="small" sx={{ minWidth: 180 }}>
              <InputLabel id="owner-filter-label">Owner Filter</InputLabel>
              <Select labelId="owner-filter-label" label="Owner Filter" value={allOwnerFilter} onChange={(e) => setAllOwnerFilter(e.target.value as any)}>
                <MenuItem value="all">All</MenuItem>
                <MenuItem value="unassigned">Unassigned only</MenuItem>
                <MenuItem value="tenant">Specific tenant</MenuItem>
              </Select>
            </FormControl>
            {allOwnerFilter === 'tenant' && (
              <FormControl size="small" sx={{ minWidth: 220 }}>
                <InputLabel id="owner-tenant-label">Owner Tenant</InputLabel>
                <Select labelId="owner-tenant-label" label="Owner Tenant" value={allOwnerTenantId} onChange={(e) => setAllOwnerTenantId(e.target.value as string)}>
                  <MenuItem value="">Any</MenuItem>
                  {tenants.map(t => (
                    <MenuItem key={t.id} value={t.id}>{t.displayName}</MenuItem>
                  ))}
                </Select>
              </FormControl>
            )}
            <FormControl size="small" sx={{ minWidth: 170 }}>
              <InputLabel id="all-sort-label">Sort by</InputLabel>
              <Select labelId="all-sort-label" label="Sort by" value={allSort} onChange={(e) => setAllSort(e.target.value as any)}>
                <MenuItem value="ipAsc">IP ↑</MenuItem>
                <MenuItem value="ipDesc">IP ↓</MenuItem>
                <MenuItem value="labelAsc">Label ↑</MenuItem>
                <MenuItem value="labelDesc">Label ↓</MenuItem>
              </Select>
            </FormControl>
          </Box>
          <List dense>
            {filteredSortedAll.length ? filteredSortedAll.map((e) => (
              <ListItem key={`all-${e.ipAddress}`}>
                <ListItemText
                  primary={e.ipAddress}
                  secondary={(() => {
                    const owners = e.tenantIds.length ? mapTenantIdsToNames(e.tenantIds, tenants).join(', ') : 'Unassigned';
                    const labelStr = e.label ? `Label: ${e.label}` : null;
                    return [labelStr, `Owners: ${owners}`].filter(Boolean).join(' — ');
                  })()}
                />
              </ListItem>
            )) : (
              <ListItem><ListItemText primary="No whitelist entries found." /></ListItem>
            )}
          </List>
        </Paper>
        <ManageConflictModal open={manageDialog.open} ownerTenantId={manageDialog.ownerTenantId} onClose={() => setManageDialog({ open: false, ownerTenantId: null })} conflictingIp={conflict?.ipAddress || null} tenants={tenants} />
      </Container>
    );
  };

  export default IpWhitelistPage;

