                'No datasource selected'
              }
            </Typography>
            <TextField
              fullWidth
              size="small"
              placeholder="Search tables..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              sx={{ mt: 2 }}
              InputProps={{
