interface PrivateMarketsExplorerProps {
  userId?: string;
}

export const MobileResponsivePrivateMarketsExplorer: React.FC<PrivateMarketsExplorerProps> = ({ userId }) => {
  const theme = useTheme();
  const isMobile = useMediaQuery(theme.breakpoints.down('md'));
  const isTablet = useMediaQuery(theme.breakpoints.down('lg'));

  const { user, bundle, isLoading, error } = useExplorer();
  const navigate = useNavigate();
  const auth = useAuth();
  const [logoutDialogOpen, setLogoutDialogOpen] = useState(false);
  const [currentView, setCurrentView] = useState<'dashboard' | 'review' | 'analytics'>('dashboard');
  const [drawerOpen, setDrawerOpen] = useState(!isMobile); // Auto-open on desktop, closed on mobile
  const [anchorEl, setAnchorEl] = useState<null | HTMLElement>(null);

  // WebSocket integration for real-time updates
  const { isConnected, connectionStatus, realTimeData, sendMessage: _sendMessage, reconnect } = useWebSocket(
    user?.role || 'lp',
    user?.id || userId
  );

  const handleMenuClick = (event: React.MouseEvent<HTMLElement>) => {
    setAnchorEl(event.currentTarget);
  };

  const handleMenuClose = () => {
    setAnchorEl(null);
  };

  const handleLogout = () => {
    handleMenuClose();
    setLogoutDialogOpen(true);
  };

  const confirmLogout = async () => {
    setLogoutDialogOpen(false);
    try {
      await auth.logout();
    } finally {
      navigate('/login');
    }
  };

  const cancelLogout = () => {
    setLogoutDialogOpen(false);
  };

  const toggleDrawer = () => {
    setDrawerOpen(!drawerOpen);
  };

  const closeDrawer = () => {
    if (isMobile) {
      setDrawerOpen(false);
    }
  };

  const getRoleDisplayName = (role: string) => {
    switch (role) {
      case 'lp': return 'Limited Partner';
      case 'gp': return 'General Partner';
      case 'fof': return 'Fund of Funds';
      case 'steward': return 'Steward';
      default: return role;
    }
  };

  const getRoleIcon = (role: string) => {
    switch (role) {
      case 'lp': return <People />;
      case 'gp': return <Business />;
      case 'fof': return <Analytics />;
      case 'steward': return <Assessment />;
      default: return <AccountCircle />;
    }
  };

  const renderMainContent = () => {
    if (!user || !bundle) {
      return (
        <Box
          display="flex"
          justifyContent="center"
          alignItems="center"
          minHeight={isMobile ? "60vh" : "400px"}
          sx={{ p: isMobile ? 2 : 3 }}
        >
          <CircularProgress size={isMobile ? 40 : 60} />
        </Box>
      );
    }

    switch (currentView) {
      case 'dashboard':
        if (user.role === 'lp') {
          return <MobileResponsiveLPPrivateMarketsDashboard userId={user.id} realTimeData={realTimeData} />;
        } else if (user.role === 'gp') {
          return <MobileResponsiveGPPrivateMarketsDashboard userId={user.id} realTimeData={realTimeData} />;
        } else if (user.role === 'fof') {
          return <MobileResponsiveFoFPrivateMarketsDashboard userId={user.id} realTimeData={realTimeData} />;
        }
        break;

      case 'review':
        if (user.role === 'steward') {
          return <TemplateReviewDashboard domain="private_markets" />;
        }
        break;

      case 'analytics':
        return (
          <Box sx={{ p: isMobile ? 2 : 3 }}>
            <Typography
              variant={isMobile ? "h5" : "h4"}
              sx={{ mb: isMobile ? 2 : 3 }}
            >
              Advanced Analytics
            </Typography>
            <Typography
              variant={isMobile ? "body1" : "h6"}
              sx={{ mb: 2 }}
            >
              Advanced analytics features would be implemented here based on the current bundle.
            </Typography>
          </Box>
        );
    }

    return (
      <Box sx={{
        p: isMobile ? 2 : 3,
        textAlign: 'center',
        minHeight: isMobile ? "60vh" : "400px",
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center'
      }}>
        <Typography
          variant={isMobile ? "body1" : "h6"}
          color="text.secondary"
        >
          No dashboard available for your role
        </Typography>
      </Box>
    );
  };

  if (isLoading) {
    return (
      <Box
        display="flex"
        justifyContent="center"
        alignItems="center"
        minHeight="100vh"
        sx={{ p: isMobile ? 2 : 3 }}
      >
        <CircularProgress size={isMobile ? 40 : 60} />
      </Box>
    );
  }

  if (error) {
    return (
      <Alert
        severity="error"
        sx={{
          m: isMobile ? 2 : 3,
          fontSize: isMobile ? '0.875rem' : '1rem'
        }}
      >
        {error}
      </Alert>
    );
  }

  const drawerWidth = isMobile ? 280 : isTablet ? 320 : 360;

  return (
    <Box sx={{ display: 'flex', minHeight: '100vh', flexDirection: 'column' }}>
      {/* Mobile App Bar */}
      {isMobile && (
        <AppBar
          position="fixed"
          sx={{
            zIndex: theme.zIndex.drawer + 1,
            backgroundColor: 'background.paper',
            color: 'text.primary',
            borderBottom: 1,
            borderColor: 'divider',
          }}
        >
          <Toolbar sx={{ minHeight: '56px', px: 2 }}>
            <IconButton
              edge="start"
              color="inherit"
              aria-label="menu"
              onClick={toggleDrawer}
              sx={{ mr: 1 }}
            >
              <MenuIcon />
            </IconButton>

            <Typography
              variant="h6"
              sx={{
                flexGrow: 1,
                fontWeight: 'bold',
                fontSize: '1.1rem'
              }}
            >
              {bundle ? bundle.name : 'Private Markets'}
            </Typography>

            {/* Connection Status - Mobile */}
            <Tooltip title={`Connection: ${connectionStatus}`}>
              <IconButton
                size="small"
                onClick={reconnect}
                color={isConnected ? 'success' : 'error'}
              >
                {isConnected ? <Wifi /> : <WifiOff />}
              </IconButton>
            </Tooltip>
          </Toolbar>
        </AppBar>
      )}

      {/* Navigation Drawer */}
      <Drawer
        variant={isMobile ? "temporary" : "permanent"}
        open={drawerOpen}
        onClose={closeDrawer}
        sx={{
          width: drawerWidth,
          flexShrink: 0,
          '& .MuiDrawer-paper': {
            width: drawerWidth,
            boxSizing: 'border-box',
            backgroundColor: 'background.paper',
            borderRight: 1,
            borderColor: 'divider',
          },
        }}
        ModalProps={{
          keepMounted: true, // Better mobile performance
        }}
      >
        <Box sx={{
          p: isMobile ? 2 : 3,
          borderBottom: 1,
          borderColor: 'divider',
          backgroundColor: 'background.default'
        }}>
          {/* Close button for mobile */}
          {isMobile && (
            <Box sx={{ display: 'flex', justifyContent: 'flex-end', mb: 1 }}>
              <IconButton onClick={closeDrawer} size="small">
                <CloseIcon />
              </IconButton>
            </Box>
          )}

          <Typography
            variant={isMobile ? "h6" : "h5"}
            sx={{
              mb: 2,
              fontWeight: 'bold',
              fontSize: isMobile ? '1.1rem' : '1.25rem'
            }}
          >
            Private Markets Explorer
          </Typography>

          {user && (
            <Box display="flex" alignItems="center" gap={1} sx={{ mb: 2 }}>
              <Avatar sx={{
                width: isMobile ? 32 : 40,
                height: isMobile ? 32 : 40
              }}>
                {getRoleIcon(user.role)}
              </Avatar>
              <Box sx={{ minWidth: 0, flex: 1 }}>
                <Typography
                  variant="body2"
                  fontWeight="bold"
                  sx={{
                    fontSize: isMobile ? '0.875rem' : '1rem',
                    overflow: 'hidden',
                    textOverflow: 'ellipsis',
                    whiteSpace: 'nowrap'
                  }}
                >
                  {user.name}
                </Typography>
                <Typography
                  variant="caption"
                  color="text.secondary"
                  sx={{
                    fontSize: isMobile ? '0.75rem' : '0.875rem',
                    overflow: 'hidden',
                    textOverflow: 'ellipsis',
                    whiteSpace: 'nowrap'
                  }}
                >
                  {getRoleDisplayName(user.role)}
                </Typography>
              </Box>
            </Box>
          )}

          {/* WebSocket Connection Status */}
          {!isMobile && (
            <Box sx={{
              mt: 2,
              display: 'flex',
              alignItems: 'center',
              gap: 1,
              p: 1,
              borderRadius: 1,
              backgroundColor: isConnected ? 'success.light' : 'error.light',
              opacity: 0.8
            }}>
              <Tooltip title={`Connection: ${connectionStatus}`}>
                <IconButton
                  size="small"
                  onClick={reconnect}
                  color={isConnected ? 'success' : 'error'}
                >
                  {isConnected ? <Wifi /> : <WifiOff />}
                </IconButton>
              </Tooltip>
              <Box sx={{ minWidth: 0, flex: 1 }}>
                <Typography
                  variant="caption"
                  color="text.secondary"
                  sx={{
                    display: 'block',
                    fontWeight: 'bold',
                    fontSize: '0.75rem'
                  }}
                >
                  Live Updates
                </Typography>
                <Typography
                  variant="caption"
                  color={isConnected ? 'success.main' : 'error.main'}
                  sx={{
                    display: 'block',
                    fontWeight: 'bold',
                    fontSize: '0.75rem'
                  }}
                >
                  {isConnected ? 'Connected' : connectionStatus === 'connecting' ? 'Connecting...' : 'Disconnected'}
                </Typography>
              </Box>
              {!isConnected && (
                <IconButton size="small" onClick={reconnect} color="primary">
                  <Refresh />
                </IconButton>
              )}
            </Box>
          )}

          {/* Real-time Data Summary */}
          {Object.keys(realTimeData).length > 0 && (
            <Box sx={{ mt: 1 }}>
              <Typography
                variant="caption"
                color="text.secondary"
                sx={{ fontSize: '0.75rem' }}
              >
                Live updates: {Object.keys(realTimeData).length} funds
              </Typography>
            </Box>
          )}
        </Box>

        <List sx={{ py: 0 }}>
          <ListItem
            button
            selected={currentView === 'dashboard'}
            onClick={() => {
              setCurrentView('dashboard');
              closeDrawer();
            }}
            sx={{
              py: isMobile ? 2 : 1.5,
              px: isMobile ? 3 : 2,
              minHeight: isMobile ? '56px' : '48px',
            }}
          >
            <ListItemIcon sx={{
              minWidth: isMobile ? '40px' : '36px',
              color: currentView === 'dashboard' ? 'primary.main' : 'inherit'
            }}>
              <Dashboard />
            </ListItemIcon>
            <ListItemText
              primary="Dashboard"
              primaryTypographyProps={{
                fontSize: isMobile ? '1rem' : '0.875rem',
                fontWeight: currentView === 'dashboard' ? 'bold' : 'normal',
              }}
            />
          </ListItem>

          {user?.role === 'steward' && (
            <ListItem
              button
              selected={currentView === 'review'}
              onClick={() => {
                setCurrentView('review');
                closeDrawer();
              }}
              sx={{
                py: isMobile ? 2 : 1.5,
                px: isMobile ? 3 : 2,
                minHeight: isMobile ? '56px' : '48px',
              }}
            >
              <ListItemIcon sx={{
                minWidth: isMobile ? '40px' : '36px',
                color: currentView === 'review' ? 'primary.main' : 'inherit'
              }}>
                <Assessment />
              </ListItemIcon>
              <ListItemText
                primary="Template Review"
                primaryTypographyProps={{
                  fontSize: isMobile ? '1rem' : '0.875rem',
                  fontWeight: currentView === 'review' ? 'bold' : 'normal',
                }}
              />
            </ListItem>
          )}

          <ListItem
            button
            selected={currentView === 'analytics'}
            onClick={() => {
              setCurrentView('analytics');
              closeDrawer();
            }}
            sx={{
              py: isMobile ? 2 : 1.5,
              px: isMobile ? 3 : 2,
              minHeight: isMobile ? '56px' : '48px',
            }}
          >
            <ListItemIcon sx={{
              minWidth: isMobile ? '40px' : '36px',
              color: currentView === 'analytics' ? 'primary.main' : 'inherit'
            }}>
              <Compare />
            </ListItemIcon>
            <ListItemText
              primary="Analytics"
              primaryTypographyProps={{
                fontSize: isMobile ? '1rem' : '0.875rem',
                fontWeight: currentView === 'analytics' ? 'bold' : 'normal',
              }}
            />
          </ListItem>
        </List>

        <Divider />

        {/* Bundle Info */}
        <Box sx={{ p: isMobile ? 2 : 3, mt: 'auto' }}>
          <Typography
            variant="subtitle2"
            gutterBottom
            sx={{ fontSize: isMobile ? '0.875rem' : '0.75rem' }}
          >
            Active Bundle
          </Typography>
          {bundle && (
            <Chip
              label={bundle.name}
              size={isMobile ? "small" : "medium"}
              color="primary"
              sx={{
                mb: 1,
                fontSize: isMobile ? '0.75rem' : '0.875rem',
                height: isMobile ? '24px' : '32px'
              }}
            />
          )}

          <Typography
            variant="subtitle2"
            gutterBottom
            sx={{
              mt: 2,
              fontSize: isMobile ? '0.875rem' : '0.75rem'
            }}
          >
            Bundle Version
          </Typography>
          {bundle && (
            <Typography
              variant="caption"
              color="text.secondary"
              sx={{ fontSize: isMobile ? '0.75rem' : '0.875rem' }}
            >
              v{bundle.version}
            </Typography>
          )}
        </Box>
      </Drawer>

      {/* Main Content */}
      <Box
        sx={{
          flexGrow: 1,
          bgcolor: 'grey.50',
          marginTop: isMobile ? '56px' : 0, // Account for fixed app bar on mobile
          minHeight: isMobile ? 'calc(100vh - 56px)' : '100vh',
        }}
      >
        {/* Desktop Top Bar */}
        {!isMobile && (
          <Box
            sx={{
              display: 'flex',
              justifyContent: 'space-between',
              alignItems: 'center',
              p: 3,
              bgcolor: 'white',
              borderBottom: 1,
              borderColor: 'divider'
            }}
          >
            <Typography variant="h4" sx={{ fontWeight: 'bold' }}>
              {bundle ? bundle.name : 'Private Markets'}
            </Typography>

            <Box display="flex" alignItems="center" gap={2}>
              <Button
                variant="outlined"
                startIcon={<Settings />}
                onClick={handleMenuClick}
                size={isTablet ? "small" : "medium"}
              >
                Settings
              </Button>

              <Menu
                anchorEl={anchorEl}
                open={Boolean(anchorEl)}
                onClose={handleMenuClose}
              >
                <MenuItem onClick={handleMenuClose}>
                  <ListItemIcon>
                    <AccountCircle fontSize="small" />
                  </ListItemIcon>
                  Profile
                </MenuItem>
                <MenuItem onClick={handleMenuClose}>
                  <ListItemIcon>
                    <Settings fontSize="small" />
                  </ListItemIcon>
                  Preferences
                </MenuItem>
                <Divider />
                <MenuItem onClick={handleLogout}>
                  <ListItemIcon>
                    <ExitToApp fontSize="small" />
                  </ListItemIcon>
                    Logout
                </MenuItem>
              </Menu>
            </Box>
          </Box>
        )}

        {/* Main Content Area */}
        <Box sx={{
          p: isMobile ? 1 : 0,
          overflow: 'auto',
          height: '100%'
        }}>
          {renderMainContent()}
        </Box>
      </Box>

      {/* Real-time Notifications */}
      <RealTimeNotification
        realTimeData={realTimeData}
        isConnected={isConnected}
      />
      <Dialog open={logoutDialogOpen} onClose={cancelLogout}>
        <DialogTitle>Confirm Logout</DialogTitle>
        <DialogContent>
          <DialogContentText>
            Are you sure you want to log out? This will clear your local session.
          </DialogContentText>
        </DialogContent>
        <DialogActions>
          <Button onClick={cancelLogout}>Cancel</Button>
          <Button onClick={confirmLogout} color="primary" autoFocus>Logout</Button>
        </DialogActions>
      </Dialog>
    </Box>
  );
};

import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../../contexts/AuthContext';
import {
  Box,
  Typography,
  Paper,
  Button,
  Menu,
  MenuItem,
  Avatar,
  Chip,
  Alert,
  CircularProgress,
  Drawer,
  List,
  ListItem,
  ListItemIcon,
  ListItemText,
  Divider,
  IconButton,
  Tooltip,
  useTheme,
  useMediaQuery,
} from '@mui/material';
import {
  AccountCircle,
  Business,
  Assessment,
  Settings,
  ExitToApp,
  Dashboard,
  People,
  Analytics,
  Compare,
  Wifi,
  WifiOff,
  Refresh
} from '@mui/icons-material';
import { Dialog, DialogTitle, DialogContent, DialogContentText, DialogActions } from '@mui/material';
import { LPPrivateMarketsDashboard } from './LPPrivateMarketsDashboard';
import { GPPrivateMarketsDashboard } from './GPPrivateMarketsDashboard';
import { MobileResponsiveLPPrivateMarketsDashboard } from './MobileResponsiveLPPrivateMarketsDashboard';
import { MobileResponsiveGPPrivateMarketsDashboard } from './MobileResponsiveGPPrivateMarketsDashboard';
import { MobileResponsiveFoFPrivateMarketsDashboard } from './MobileResponsiveFoFPrivateMarketsDashboard';
import { TemplateReviewDashboard } from './TemplateReviewDashboard';
import { useExplorer } from './ExplorerContext';
import { useWebSocket } from '../../hooks/useWebSocket';
import { RealTimeNotification } from '../../components/RealTimeNotification';

interface PrivateMarketsExplorerProps {
  userId?: string;
}

export const PrivateMarketsExplorer: React.FC<PrivateMarketsExplorerProps> = ({ userId }) => {
  const { user, bundle, isLoading, error } = useExplorer();
  const theme = useTheme();
  const isMobile = useMediaQuery(theme.breakpoints.down('sm'));
  const navigate = useNavigate();
  const auth = useAuth();
  const [logoutDialogOpen, setLogoutDialogOpen] = useState(false);
  const [currentView, setCurrentView] = useState<'dashboard' | 'review' | 'analytics'>('dashboard');
  const [drawerOpen, setDrawerOpen] = useState(false);
  const [anchorEl, setAnchorEl] = useState<null | HTMLElement>(null);

  // WebSocket integration for real-time updates
  const { isConnected, connectionStatus, realTimeData, sendMessage: _sendMessage, reconnect } = useWebSocket(
    user?.role || 'lp',
    user?.id || userId
  );

  const handleMenuClick = (event: React.MouseEvent<HTMLElement>) => {
    setAnchorEl(event.currentTarget);
  };

  const handleMenuClose = () => {
    setAnchorEl(null);
  };

  const handleLogout = () => {
    // Open confirmation dialog
    handleMenuClose();
    setLogoutDialogOpen(true);
  };

  const confirmLogout = async () => {
    setLogoutDialogOpen(false);
    try {
      await auth.logout();
    } finally {
      navigate('/login');
    }
  };

  const cancelLogout = () => {
    setLogoutDialogOpen(false);
  };

  const getRoleDisplayName = (role: string) => {
    switch (role) {
      case 'lp': return 'Limited Partner';
      case 'gp': return 'General Partner';
      case 'fof': return 'Fund of Funds';
      case 'steward': return 'Steward';
      default: return role;
    }
  };

  const getRoleIcon = (role: string) => {
    switch (role) {
      case 'lp': return <People />;
      case 'gp': return <Business />;
      case 'fof': return <Analytics />;
      case 'steward': return <Assessment />;
      default: return <AccountCircle />;
    }
  };

  const renderMainContent = () => {
    if (!user || !bundle) {
      return (
        <Box display="flex" justifyContent="center" alignItems="center" minHeight="400px">
          <CircularProgress />
        </Box>
      );
    }

    switch (currentView) {
      case 'dashboard':
        if (user.role === 'lp') {
          return isMobile ? (
            <MobileResponsiveLPPrivateMarketsDashboard userId={user.id} realTimeData={realTimeData} />
          ) : (
            <LPPrivateMarketsDashboard userId={user.id} realTimeData={realTimeData} />
          );
        } else if (user.role === 'gp') {
          return isMobile ? (
            <MobileResponsiveGPPrivateMarketsDashboard userId={user.id} realTimeData={realTimeData} />
          ) : (
            <GPPrivateMarketsDashboard userId={user.id} realTimeData={realTimeData} />
          );
        } else if (user.role === 'fof') {
          return isMobile ? (
            <MobileResponsiveFoFPrivateMarketsDashboard userId={user.id} realTimeData={realTimeData} />
          ) : (
            <LPPrivateMarketsDashboard userId={user.id} realTimeData={realTimeData} />
          );
        }
        break;

      case 'review':
        if (user.role === 'steward') {
          return <TemplateReviewDashboard domain="private_markets" />;
        }
        break;

      case 'analytics':
        return (
          <Box sx={{ p: 3 }}>
            <Typography variant="h4">Advanced Analytics</Typography>
            <Typography variant="body1" sx={{ mt: 2 }}>
              Advanced analytics features would be implemented here based on the current bundle.
            </Typography>
          </Box>
        );
    }

    return (
      <Box sx={{ p: 3, textAlign: 'center' }}>
        <Typography variant="h6" color="text.secondary">
          No dashboard available for your role
        </Typography>
      </Box>
    );
  };

  if (isLoading) {
    return (
      <Box display="flex" justifyContent="center" alignItems="center" minHeight="100vh">
        <CircularProgress />
      </Box>
    );
  }

  if (error) {
    return (
      <Alert severity="error" sx={{ m: 2 }}>
        {error}
      </Alert>
    );
  }

  return (
    <Box sx={{ display: 'flex', minHeight: '100vh' }}>
      {/* Navigation Drawer */}
      <Drawer
        variant="permanent"
        sx={{
          width: 280,
          flexShrink: 0,
          '& .MuiDrawer-paper': {
            width: 280,
            boxSizing: 'border-box',
          },
        }}
      >
        <Box sx={{ p: 2, borderBottom: 1, borderColor: 'divider' }}>
          <Typography variant="h6" sx={{ mb: 1 }}>
            Private Markets Explorer
          </Typography>
          {user && (
            <Box display="flex" alignItems="center" gap={1}>
              <Avatar sx={{ width: 32, height: 32 }}>
                {getRoleIcon(user.role)}
              </Avatar>
              <Box>
                <Typography variant="body2" fontWeight="bold">
                  {user.name}
                </Typography>
                <Typography variant="caption" color="text.secondary">
                  {getRoleDisplayName(user.role)}
                </Typography>
              </Box>
            </Box>
          )}

          {/* WebSocket Connection Status */}
          <Box sx={{ mt: 2, display: 'flex', alignItems: 'center', gap: 1 }}>
            <Tooltip title={`Connection: ${connectionStatus}`}>
              <IconButton
                size="small"
                onClick={reconnect}
                color={isConnected ? 'success' : 'error'}
              >
                {isConnected ? <Wifi /> : <WifiOff />}
              </IconButton>
            </Tooltip>
            <Box>
              <Typography variant="caption" color="text.secondary">
                Live Updates
              </Typography>
              <Typography
                variant="caption"
                color={isConnected ? 'success.main' : 'error.main'}
                sx={{ display: 'block', fontWeight: 'bold' }}
              >
                {isConnected ? 'Connected' : connectionStatus === 'connecting' ? 'Connecting...' : 'Disconnected'}
              </Typography>
            </Box>
            {!isConnected && (
              <IconButton size="small" onClick={reconnect} color="primary">
                <Refresh />
              </IconButton>
            )}
          </Box>

          {/* Real-time Data Summary */}
          {Object.keys(realTimeData).length > 0 && (
            <Box sx={{ mt: 1 }}>
              <Typography variant="caption" color="text.secondary">
                Live updates: {Object.keys(realTimeData).length} funds
              </Typography>
            </Box>
          )}
        </Box>

        <List>
          <ListItem
            button
            selected={currentView === 'dashboard'}
            onClick={() => setCurrentView('dashboard')}
          >
            <ListItemIcon>
              <Dashboard />
            </ListItemIcon>
            <ListItemText primary="Dashboard" />
          </ListItem>

          {user?.role === 'steward' && (
            <ListItem
              button
              selected={currentView === 'review'}
              onClick={() => setCurrentView('review')}
            >
              <ListItemIcon>
                <Assessment />
              </ListItemIcon>
              <ListItemText primary="Template Review" />
            </ListItem>
          )}

          <ListItem
            button
            selected={currentView === 'analytics'}
            onClick={() => setCurrentView('analytics')}
          >
            <ListItemIcon>
              <Compare />
            </ListItemIcon>
            <ListItemText primary="Analytics" />
          </ListItem>
        </List>

        <Divider />

        {/* Bundle Info */}
        <Box sx={{ p: 2 }}>
          <Typography variant="subtitle2" gutterBottom>
            Active Bundle
          </Typography>
          {bundle && (
            <Chip
              label={bundle.name}
              size="small"
              color="primary"
              sx={{ mb: 1 }}
            />
          )}

          <Typography variant="subtitle2" gutterBottom sx={{ mt: 2 }}>
            Bundle Version
          </Typography>
          {bundle && (
            <Typography variant="caption" color="text.secondary">
              v{bundle.version}
            </Typography>
          )}
        </Box>
      </Drawer>

      {/* Main Content */}
      <Box sx={{ flexGrow: 1, bgcolor: 'grey.50' }}>
        {/* Top Bar */}
        <Box
          sx={{
            display: 'flex',
            justifyContent: 'space-between',
            alignItems: 'center',
            p: 2,
            bgcolor: 'white',
            borderBottom: 1,
            borderColor: 'divider'
          }}
        >
          <Typography variant="h5">
            {bundle ? bundle.name : 'Private Markets'}
          </Typography>

          <Box display="flex" alignItems="center" gap={2}>
            <Button
              variant="outlined"
              startIcon={<Settings />}
              onClick={handleMenuClick}
            >
              Settings
            </Button>

            <Menu
              anchorEl={anchorEl}
              open={Boolean(anchorEl)}
              onClose={handleMenuClose}
            >
              <MenuItem onClick={handleMenuClose}>
                <ListItemIcon>
                  <AccountCircle fontSize="small" />
                </ListItemIcon>
                Profile
              </MenuItem>
              <MenuItem onClick={handleMenuClose}>
                <ListItemIcon>
                  <Settings fontSize="small" />
                </ListItemIcon>
                Preferences
              </MenuItem>
              <Divider />
              <MenuItem onClick={handleLogout}>
                <ListItemIcon>
                  <ExitToApp fontSize="small" />
                </ListItemIcon>
                  Logout
              </MenuItem>
            </Menu>
          </Box>
        </Box>

        {/* Main Content Area */}
        {renderMainContent()}
      </Box>

      {/* Real-time Notifications */}
      <RealTimeNotification
        realTimeData={realTimeData}
        isConnected={isConnected}
      />
      <Dialog open={logoutDialogOpen} onClose={cancelLogout}>
        <DialogTitle>Confirm Logout</DialogTitle>
        <DialogContent>
          <DialogContentText>
            Are you sure you want to log out? This will clear your local session.
          </DialogContentText>
        </DialogContent>
        <DialogActions>
          <Button onClick={cancelLogout}>Cancel</Button>
          <Button onClick={confirmLogout} color="primary" autoFocus>Logout</Button>
        </DialogActions>
      </Dialog>
    </Box>
  );
};

import React, { useState, useEffect, useCallback } from 'react';
import {
  Box,
  Typography,
  Paper,
  Grid,
  Card as _Card,
  CardContent as _CardContent,
  Button,
  Chip,
  Table as _Table,
  TableBody as _TableBody,
  TableCell as _TableCell,
  TableContainer as _TableContainer,
  TableHead as _TableHead,
  TableRow as _TableRow,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  List,
  Tabs,
  Tab,
  Accordion,
  AccordionSummary,
  AccordionDetails,
  TextField,
  FormControl,
  InputLabel,
  Select,
  MenuItem,
  SelectChangeEvent,
  Alert,
  CircularProgress,
  // ...existing code...
  ListItem,
  ListItemText,
  Divider
} from '@mui/material';
import {
  ExpandMore,
  CheckCircle,
  Pending,
  Error as ErrorIcon,
  Visibility,
  ThumbUp,
  Comment,
  History as _History
} from '@mui/icons-material';

interface Template {
  id: string;
  name: string;
  domain: string;
  category: string;
  subcategory: string;
  version: string;
  status: 'draft' | 'reviewed' | 'golden';
  owner: string;
  description: string;
  tags: string[];
  governance: {
    status: string;
    steward_group: string;
    schema_hash: string;
    sla: {
      refresh_frequency: string;
      max_latency: string;
    };
  };
  created_at: string;
  updated_at: string;
  review_comments: ReviewComment[];
}

interface ReviewComment {
  id: string;
  author: string;
  comment: string;
  type: 'comment' | 'approval' | 'rejection' | 'change_request';
  created_at: string;
}

interface TemplateReviewDashboardProps {
  domain?: string;
}

export const TemplateReviewDashboard: React.FC<TemplateReviewDashboardProps> = ({
  domain = 'private_markets'
}) => {
  const [templates, setTemplates] = useState<Template[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [selectedTemplate, setSelectedTemplate] = useState<Template | null>(null);
  const [reviewDialogOpen, setReviewDialogOpen] = useState(false);
  const [commentDialogOpen, setCommentDialogOpen] = useState(false);
  const [activeTab, setActiveTab] = useState(0);
  const [filterStatus, setFilterStatus] = useState<string>('all');
  const [filterCategory, setFilterCategory] = useState<string>('all');
  const [newComment, setNewComment] = useState('');
  const [commentType, setCommentType] = useState<'comment' | 'approval' | 'rejection' | 'change_request'>('comment');

  const loadTemplates = useCallback(async () => {
    try {
      setLoading(true);
      const response = await fetch(`/api/templates?domain=${domain}`);
      if (!response.ok) {
        throw new Error('Failed to load templates');
      }
      const data = await response.json();
      setTemplates(data);
    } catch (err: unknown) {
      setError(err instanceof Error ? err.message : 'Failed to load templates');
    } finally {
      setLoading(false);
    }
  }, [domain]);

  useEffect(() => {
    loadTemplates();
  }, [loadTemplates]);



  const handleStatusFilterChange = (event: SelectChangeEvent) => {
    setFilterStatus(event.target.value);
  };

  const handleCategoryFilterChange = (event: SelectChangeEvent) => {
    setFilterCategory(event.target.value);
  };

  const handleTabChange = (_event: React.SyntheticEvent, newValue: number) => {
    setActiveTab(newValue);
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'draft': return 'warning';
      case 'reviewed': return 'info';
      case 'golden': return 'success';
      default: return 'default';
    }
  };

  const getStatusIcon = (status: string) => {
    switch (status) {
  case 'draft': return <Pending />;
  case 'reviewed': return <CheckCircle />;
  case 'golden': return <CheckCircle />;
  default: return <ErrorIcon />;
    }
  };

  const filteredTemplates = templates.filter(template => {
    const statusMatch = filterStatus === 'all' || template.status === filterStatus;
    const categoryMatch = filterCategory === 'all' || template.category === filterCategory;
    return statusMatch && categoryMatch;
  });

  const handlePromoteTemplate = async (templateId: string, newStatus: 'reviewed' | 'golden') => {
    try {
      const response = await fetch(`/api/templates/${templateId}/promote`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ status: newStatus }),
      });

      if (!response.ok) {
        throw new Error('Failed to promote template');
      }

      // Refresh templates
      await loadTemplates();
    } catch (err: unknown) {
      setError(err instanceof Error ? err.message : 'Failed to promote template');
    }
  };

  const handleAddComment = async () => {
    if (!selectedTemplate || !newComment.trim()) return;

    try {
      const response = await fetch(`/api/templates/${selectedTemplate.id}/comments`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          comment: newComment,
          type: commentType,
        }),
      });

      if (!response.ok) {
        throw new Error('Failed to add comment');
      }

      setNewComment('');
      setCommentDialogOpen(false);
      await loadTemplates();
    } catch (err: unknown) {
      setError(err instanceof Error ? err.message : 'Failed to add comment');
    }
  };

  const categories = [...new Set(templates.map(t => t.category))];

  if (loading) {
    return (
      <Box display="flex" justifyContent="center" alignItems="center" minHeight="400px">
        <CircularProgress />
      </Box>
    );
  }

  if (error) {
    return (
      <Alert severity="error" sx={{ m: 2 }}>
        {error}
      </Alert>
    );
  }

  return (
    <Box sx={{ flexGrow: 1, p: 3 }}>
      <Typography variant="h4" component="h1" gutterBottom>
        Template Review Dashboard - {domain.replace('_', ' ').toUpperCase()}
      </Typography>

      {/* Filters */}
      <Paper sx={{ p: 2, mb: 3 }}>
        <Grid container spacing={2} alignItems="center">
          <Grid item xs={12} md={3}>
            <FormControl fullWidth>
              <InputLabel>Status</InputLabel>
              <Select value={filterStatus} label="Status" onChange={handleStatusFilterChange}>
                <MenuItem value="all">All Status</MenuItem>
                <MenuItem value="draft">Draft</MenuItem>
                <MenuItem value="reviewed">Reviewed</MenuItem>
                <MenuItem value="golden">Golden</MenuItem>
              </Select>
            </FormControl>
          </Grid>
          <Grid item xs={12} md={3}>
            <FormControl fullWidth>
              <InputLabel>Category</InputLabel>
              <Select value={filterCategory} label="Category" onChange={handleCategoryFilterChange}>
                <MenuItem value="all">All Categories</MenuItem>
                {categories.map(category => (
                  <MenuItem key={category} value={category}>
                    {category}
                  </MenuItem>
                ))}
              </Select>
            </FormControl>
          </Grid>
          <Grid item xs={12} md={6}>
            <Typography variant="body2" color="text.secondary">
              Showing {filteredTemplates.length} of {templates.length} templates
            </Typography>
          </Grid>
        </Grid>
      </Paper>

      {/* Main Content */}
      <Grid container spacing={3}>
        {/* Template List */}
        <Grid item xs={12} lg={4}>
          <Paper sx={{ p: 2, maxHeight: 600, overflow: 'auto' }}>
            <Typography variant="h6" gutterBottom>
              Templates ({filteredTemplates.length})
            </Typography>
            <List>
              {filteredTemplates.map((template) => (
                <ListItem
                  key={template.id}
                  button
                  onClick={() => setSelectedTemplate(template)}
                  selected={selectedTemplate?.id === template.id}
                >
                  <ListItemText
                    primary={
                      <Box display="flex" alignItems="center" gap={1}>
                        {getStatusIcon(template.status)}
                        <Typography variant="subtitle2">
                          {template.name}
                        </Typography>
                      </Box>
                    }
                    secondary={
                      <Box>
                        <Typography variant="caption" display="block">
                          {template.category} • v{template.version}
                        </Typography>
                        <Chip
                          label={template.status}
                          size="small"
                          color={getStatusColor(template.status) as any}
                          sx={{ mt: 0.5 }}
                        />
                      </Box>
                    }
                  />
                </ListItem>
              ))}
            </List>
          </Paper>
        </Grid>

        {/* Template Details */}
        <Grid item xs={12} lg={8}>
          {selectedTemplate ? (
            <Paper sx={{ p: 3 }}>
              <Box display="flex" justifyContent="space-between" alignItems="flex-start" mb={2}>
                <Box>
                  <Typography variant="h5" gutterBottom>
                    {selectedTemplate.name}
                  </Typography>
                  <Typography variant="body2" color="text.secondary" gutterBottom>
                    {selectedTemplate.description}
                  </Typography>
                </Box>
                <Box display="flex" gap={1}>
                  <Button
                    variant="outlined"
                    startIcon={<Visibility />}
                    onClick={() => setReviewDialogOpen(true)}
                  >
                    Review
                  </Button>
                  <Button
                    variant="outlined"
                    startIcon={<Comment />}
                    onClick={() => setCommentDialogOpen(true)}
                  >
                    Comment
                  </Button>
                  {selectedTemplate.status === 'draft' && (
                    <Button
                      variant="contained"
                      startIcon={<ThumbUp />}
                      onClick={() => handlePromoteTemplate(selectedTemplate.id, 'reviewed')}
                    >
                      Approve
                    </Button>
                  )}
                  {selectedTemplate.status === 'reviewed' && (
                    <Button
                      variant="contained"
                      startIcon={<CheckCircle />}
                      onClick={() => handlePromoteTemplate(selectedTemplate.id, 'golden')}
                    >
                      Make Golden
                    </Button>
                  )}
                </Box>
              </Box>

              <Tabs value={activeTab} onChange={handleTabChange} sx={{ mb: 2 }}>
                <Tab label="Details" />
                <Tab label="Governance" />
                <Tab label="Comments" />
                <Tab label="History" />
              </Tabs>

              {activeTab === 0 && (
                <Box>
                  <Grid container spacing={2}>
                    <Grid item xs={12} md={6}>
                      <Typography variant="subtitle2">Domain</Typography>
                      <Typography>{selectedTemplate.domain}</Typography>
                    </Grid>
                    <Grid item xs={12} md={6}>
                      <Typography variant="subtitle2">Category</Typography>
                      <Typography>{selectedTemplate.category}</Typography>
                    </Grid>
                    <Grid item xs={12} md={6}>
                      <Typography variant="subtitle2">Version</Typography>
                      <Typography>{selectedTemplate.version}</Typography>
                    </Grid>
                    <Grid item xs={12} md={6}>
                      <Typography variant="subtitle2">Owner</Typography>
                      <Typography>{selectedTemplate.owner}</Typography>
                    </Grid>
                    <Grid item xs={12}>
                      <Typography variant="subtitle2">Tags</Typography>
                      <Box display="flex" gap={1} flexWrap="wrap">
                        {selectedTemplate.tags.map(tag => (
                          <Chip key={tag} label={tag} size="small" variant="outlined" />
                        ))}
                      </Box>
                    </Grid>
                  </Grid>
                </Box>
              )}

              {activeTab === 1 && (
                <Box>
                  <Typography variant="h6" gutterBottom>
                    Governance Information
                  </Typography>
                  <Grid container spacing={2}>
                    <Grid item xs={12} md={6}>
                      <Typography variant="subtitle2">Status</Typography>
                      <Chip
                        label={selectedTemplate.governance.status}
                        color={getStatusColor(selectedTemplate.status) as any}
                        icon={getStatusIcon(selectedTemplate.status)}
                      />
                    </Grid>
                    <Grid item xs={12} md={6}>
                      <Typography variant="subtitle2">Steward Group</Typography>
                      <Typography>{selectedTemplate.governance.steward_group}</Typography>
                    </Grid>
                    <Grid item xs={12} md={6}>
                      <Typography variant="subtitle2">Refresh Frequency</Typography>
                      <Typography>{selectedTemplate.governance.sla.refresh_frequency}</Typography>
                    </Grid>
                    <Grid item xs={12} md={6}>
                      <Typography variant="subtitle2">Max Latency</Typography>
                      <Typography>{selectedTemplate.governance.sla.max_latency}</Typography>
                    </Grid>
                  </Grid>
                </Box>
              )}

              {activeTab === 2 && (
                <Box>
                  <Typography variant="h6" gutterBottom>
                    Review Comments ({selectedTemplate.review_comments.length})
                  </Typography>
                  {selectedTemplate.review_comments.length === 0 ? (
                    <Typography color="text.secondary">No comments yet</Typography>
                  ) : (
                    <List>
                      {selectedTemplate.review_comments.map((comment) => (
                        <ListItem key={comment.id}>
                          <ListItemText
                            primary={
                              <Box display="flex" alignItems="center" gap={1}>
                                <Typography variant="subtitle2">{comment.author}</Typography>
                                <Chip
                                  label={comment.type}
                                  size="small"
                                  color={
                                    comment.type === 'approval' ? 'success' :
                                    comment.type === 'rejection' ? 'error' :
                                    comment.type === 'change_request' ? 'warning' : 'default'
                                  }
                                />
                              </Box>
                            }
                            secondary={
                              <Box>
                                <Typography variant="body2">{comment.comment}</Typography>
                                <Typography variant="caption" color="text.secondary">
                                  {new Date(comment.created_at).toLocaleString()}
                                </Typography>
                              </Box>
                            }
                          />
                        </ListItem>
                      ))}
                    </List>
                  )}
                </Box>
              )}

              {activeTab === 3 && (
                <Box>
                  <Typography variant="h6" gutterBottom>
                    Version History
                  </Typography>
                  <Typography color="text.secondary">
                    Version history tracking would be implemented here
                  </Typography>
                </Box>
              )}
            </Paper>
          ) : (
            <Paper sx={{ p: 3, textAlign: 'center' }}>
              <Typography variant="h6" color="text.secondary">
                Select a template to view details
              </Typography>
            </Paper>
          )}
        </Grid>
      </Grid>

      {/* Review Dialog */}
      <Dialog open={reviewDialogOpen} onClose={() => setReviewDialogOpen(false)} maxWidth="md" fullWidth>
        <DialogTitle>Template Review</DialogTitle>
        <DialogContent>
          {selectedTemplate && (
            <Box>
              <Typography variant="h6" gutterBottom>
                {selectedTemplate.name}
              </Typography>
              <Typography variant="body2" color="text.secondary" paragraph>
                {selectedTemplate.description}
              </Typography>

              <Accordion>
                <AccordionSummary expandIcon={<ExpandMore />}>
                  <Typography>Template JSON</Typography>
                </AccordionSummary>
                <AccordionDetails>
                  <Box sx={{ fontSize: '12px', overflow: 'auto', fontFamily: 'monospace' }}>
                    {JSON.stringify(selectedTemplate, null, 2)}
                  </Box>
                </AccordionDetails>
              </Accordion>
            </Box>
          )}
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setReviewDialogOpen(false)}>Close</Button>
        </DialogActions>
      </Dialog>

      {/* Comment Dialog */}
      <Dialog open={commentDialogOpen} onClose={() => setCommentDialogOpen(false)} maxWidth="sm" fullWidth>
        <DialogTitle>Add Comment</DialogTitle>
        <DialogContent>
          <FormControl fullWidth sx={{ mt: 2, mb: 2 }}>
            <InputLabel>Comment Type</InputLabel>
            <Select
              value={commentType}
              label="Comment Type"
              onChange={(e) => setCommentType(e.target.value as any)}
            >
              <MenuItem value="comment">General Comment</MenuItem>
              <MenuItem value="approval">Approval</MenuItem>
              <MenuItem value="rejection">Rejection</MenuItem>
              <MenuItem value="change_request">Change Request</MenuItem>
            </Select>
          </FormControl>
          <TextField
            fullWidth
            multiline
            rows={4}
            label="Comment"
            value={newComment}
            onChange={(e) => setNewComment(e.target.value)}
          />
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setCommentDialogOpen(false)}>Cancel</Button>
          <Button onClick={handleAddComment} variant="contained">
            Add Comment
          </Button>
        </DialogActions>
      </Dialog>
    </Box>
  );
};

import React, { useState, useEffect } from 'react';
