// Advanced Export Options
const ExportDialog: React.FC<{
  query: Query;
  onClose: () => void;
}> = ({ query, onClose }) => {
  const [exportFormat, setExportFormat] = useState('json');
  const [includeMetadata, setIncludeMetadata] = useState(true);

  const handleExport = async () => {
    try {
      const response = await fetch(`/api/queries/${query.id}/export`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          format: exportFormat,
          includeMetadata,
          destination: 'download' // or 'powerbi', 'tableau', etc.
        })
      });

      const blob = await response.blob();
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `query-${query.name}.${exportFormat}`;
      document.body.appendChild(a);
      a.click();
      window.URL.revokeObjectURL(url);
      document.body.removeChild(a);

      onClose();
    } catch (error) {
      devError('Export failed:', error);
    }
  };

  return (
    <Dialog open={true} onClose={onClose} maxWidth="sm" fullWidth>
      <DialogTitle>Export Query</DialogTitle>
      <DialogContent>
        <FormControl fullWidth sx={{ mt: 2 }}>
          <InputLabel>Export Format</InputLabel>
          <Select
            value={exportFormat}
            onChange={(e) => setExportFormat(e.target.value)}
          >
            <MenuItem value="json">JSON</MenuItem>
            <MenuItem value="sql">SQL</MenuItem>
            <MenuItem value="yaml">YAML</MenuItem>
            <MenuItem value="powerbi">Power BI</MenuItem>
            <MenuItem value="tableau">Tableau</MenuItem>
            <MenuItem value="excel">Excel</MenuItem>
          </Select>
        </FormControl>

        <FormControlLabel
          control={
            <Switch
              checked={includeMetadata}
              onChange={(e) => setIncludeMetadata(e.target.checked)}
            />
          }
          label="Include metadata and comments"
          sx={{ mt: 2 }}
        />
      </DialogContent>
      <DialogActions>
        <Button onClick={onClose}>Cancel</Button>
        <Button onClick={handleExport} variant="contained">
          Export
        </Button>
      </DialogActions>
    </Dialog>
  );
};

interface Query {
  id: string;
  name: string;
  description: string;
  type: 'public' | 'private';
  createdBy: string;
  createdAt: string;
  updatedAt: string;
  isCore: boolean;
  config: QueryConfig;
  tags: string[];
  sharedWith: string[];
}

interface QueryConfig {
  dataSource: string;
  measures: Measure[];
  dimensions: Dimension[];
  filters: Filter[];
  joins: Join[];
  aggregations: Aggregation[];
  sorting: Sort[];
  limit?: number;
}

interface Measure {
  id: string;
  name: string;
  type: string;
  aggregation?: string;
}

interface Dimension {
  id: string;
  name: string;
  type: string;
}

interface Filter {
  id: string;
  field: string;
  operator: string;
  value: any;
}

interface Join {
  id: string;
  table: string;
  type: 'INNER' | 'LEFT' | 'RIGHT' | 'FULL';
  condition: string;
}

interface Aggregation {
  id: string;
  field: string;
  function: string;
}

interface Sort {
  field: string;
  direction: 'ASC' | 'DESC';
}

