  const handleLoadUpgradeOverview = async () => {
    try {
      // Use the first available version or default to '1.1.0'
      const targetVersion = rows.length > 0 ? rows[0].version : '1.1.0';
      const overview = await getUpgradeOverview(targetVersion);

