          </Card>

          {/* SLO Monitoring Card */}
          <Card variant="outlined" sx={{ mt: 2 }}>
            <CardContent>
              <Stack direction="row" alignItems="center" justifyContent="space-between" sx={{ mb: 1 }}>
                <Typography variant="h6">SLO Monitoring</Typography>
                <Button size="small" onClick={handleLoadSLOMetrics}>Monitor</Button>
              </Stack>
              {showSLOMonitoring && (
                <Stack spacing={1}>
                  {sloAlerts.length > 0 && (
                    <Typography variant="body2" color="warning.main">
                      {sloAlerts.length} active alert{sloAlerts.length !== 1 ? 's' : ''}
                    </Typography>
                  )}
                  {sloMetrics.length > 0 && (
                    <Stack spacing={0.5}>
                      <Typography variant="body2">
                        Error Rate: {(sloMetrics[sloMetrics.length - 1]?.error_rate * 100).toFixed(2)}%
                      </Typography>
                      <Typography variant="body2">
                        P95 Latency: {sloMetrics[sloMetrics.length - 1]?.p95_latency_ms}ms
                      </Typography>
                      <Typography variant="body2">
                        Cache Hit: {(sloMetrics[sloMetrics.length - 1]?.cache_hit_ratio * 100).toFixed(1)}%
                      </Typography>
                    </Stack>
                  )}
                </Stack>
              )}
            </CardContent>
          </Card>

          {/* New Feature Cards */}
          <Card variant="outlined" sx={{ mt: 2 }}>
            <CardContent>
              <Typography variant="h6" sx={{ mb: 1 }}>Workflow Tools</Typography>
              <Stack spacing={1}>
                <Button
                  size="small"
                  startIcon={<HistoryIcon />}
                  onClick={handleLoadAuditTrail}
                  variant="outlined"
                  fullWidth
                >
                  Audit Trail
                </Button>
                <Button
                  size="small"
                  startIcon={<HealthIcon />}
                  onClick={handleLoadHealthMetrics}
                  variant="outlined"
                  fullWidth
                >
                  Health Monitor
                </Button>
                <Button
                  size="small"
                  startIcon={<ScheduleIcon />}
                  onClick={handleLoadScheduledUpgrades}
                  variant="outlined"
                  fullWidth
                >
                  Scheduler
                </Button>
                <Button
                  size="small"
                  startIcon={<ApprovalIcon />}
                  onClick={handleLoadPendingApprovals}
                  variant="outlined"
                  fullWidth
                >
                  Approvals
                </Button>
              </Stack>
            </CardContent>
          </Card>

          {/* Diff Viewer */}
          <Accordion expanded={showDiffViewer} onChange={() => setShowDiffViewer(!showDiffViewer)} sx={{ mt: 2 }}>
            <AccordionSummary expandIcon={<ExpandMoreIcon />}>
              <Stack direction="row" alignItems="center" spacing={1}>
                <CompareIcon />
                <Typography variant="h6">Diff Viewer</Typography>
                {selectedVersions.from && selectedVersions.to && (
                  <Chip size="small" label={`${selectedVersions.from} → ${selectedVersions.to}`} />
                )}
              </Stack>
            </AccordionSummary>
            <AccordionDetails>
              {showDiffViewer && selectedVersions.from && selectedVersions.to && (
                <DiffViewer fromVersion={selectedVersions.from} toVersion={selectedVersions.to} />
              )}
            </AccordionDetails>
          </Accordion>

          {/* Extension Fixer */}
          <Accordion expanded={showExtensionFixer} onChange={() => setShowExtensionFixer(!showExtensionFixer)} sx={{ mt: 1 }}>
            <AccordionSummary expandIcon={<ExpandMoreIcon />}>
              <Stack direction="row" alignItems="center" spacing={1}>
                <BuildIcon />
                <Typography variant="h6">Extension Fixer</Typography>
                {selectedVersions.from && selectedVersions.to && (
                  <Chip size="small" label={`${selectedVersions.from} → ${selectedVersions.to}`} />
                )}
              </Stack>
            </AccordionSummary>
            <AccordionDetails>
              {showExtensionFixer && selectedVersions.from && selectedVersions.to && (
                <ExtensionFixer fromVersion={selectedVersions.from} toVersion={selectedVersions.to} />
              )}
            </AccordionDetails>
          </Accordion>

          {/* Golden Query Runner */}
          <Accordion expanded={showGoldenQueryRunner} onChange={() => setShowGoldenQueryRunner(!showGoldenQueryRunner)} sx={{ mt: 1 }}>
            <AccordionSummary expandIcon={<ExpandMoreIcon />}>
              <Stack direction="row" alignItems="center" spacing={1}>
                <QueryStatsIcon />
                <Typography variant="h6">Golden Query Runner</Typography>
                {selectedVersions.from && selectedVersions.to && (
                  <Chip size="small" label={`${selectedVersions.from} → ${selectedVersions.to}`} />
                )}
              </Stack>
            </AccordionSummary>
            <AccordionDetails>
              {showGoldenQueryRunner && selectedVersions.from && selectedVersions.to && (
                <GoldenQueryRunner fromVersion={selectedVersions.from} toVersion={selectedVersions.to} />
              )}
            </AccordionDetails>
          </Accordion>

          <Box sx={{ mt: 2 }}>
            <Button size="small" color="inherit" onClick={async ()=>{ 
              // For demo purposes, rollback the first active version
              const activeVersion = rows.find(r => r.status === 'active' || r.status === 'canary');
              if (activeVersion) {
                await rollbackVersion(activeVersion.version); 
                const { versions, canary } = await fetchVersions(); 
                setRows(versions.map((v,i)=>({id:i,...v}))); 
                setCanary(canary); 
              }
            }}>Rollback</Button>
          </Box>
        </Grid>
      </Grid>

      {/* New Feature Dialogs */}

      {/* Audit Trail Dialog */}
      <Dialog open={showAuditTrail} onClose={() => setShowAuditTrail(false)} maxWidth="lg" fullWidth>
        <DialogTitle>
          <Stack direction="row" alignItems="center" spacing={1}>
            <HistoryIcon />
            <Typography variant="h6">Audit Trail</Typography>
          </Stack>
        </DialogTitle>
        <DialogContent>
          <TableContainer component={Paper}>
            <Table>
              <TableHead>
                <TableRow>
                  <TableCell>Timestamp</TableCell>
                  <TableCell>Action</TableCell>
                  <TableCell>Version</TableCell>
                  <TableCell>User</TableCell>
                  <TableCell>Status</TableCell>
                  <TableCell>Duration</TableCell>
                </TableRow>
              </TableHead>
              <TableBody>
                {auditTrail.map((entry) => (
                  <TableRow key={entry.id}>
                    <TableCell>{new Date(entry.timestamp).toLocaleString()}</TableCell>
                    <TableCell>{entry.action}</TableCell>
                    <TableCell>{entry.version}</TableCell>
                    <TableCell>{entry.user}</TableCell>
                    <TableCell>
                      <Chip
                        size="small"
                        label={entry.status}
                        color={entry.status === 'SUCCESS' ? 'success' : entry.status === 'WARNING' ? 'warning' : 'error'}
                      />
                    </TableCell>
                    <TableCell>{entry.duration}ms</TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </TableContainer>
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setShowAuditTrail(false)}>Close</Button>
        </DialogActions>
      </Dialog>

      {/* Rollback Confirmation Dialog */}
      <Dialog open={showRollbackConfirm} onClose={() => setShowRollbackConfirm(false)} maxWidth="sm" fullWidth>
        <DialogTitle>
          <Stack direction="row" alignItems="center" spacing={1}>
            <WarningIcon />
            <Typography variant="h6">Confirm Rollback</Typography>
          </Stack>
        </DialogTitle>
        <DialogContent>
          <Typography variant="body1" sx={{ mb: 2 }}>
            Are you sure you want to rollback to version {rollbackTarget}?
          </Typography>
          <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
            This action will deactivate the current version and activate the selected version for all tenants.
          </Typography>
          <TextField
            fullWidth
            label="Reason for rollback"
            multiline
            rows={3}
            value={rollbackReason}
            onChange={(e) => setRollbackReason(e.target.value)}
            placeholder="Please provide a reason for this rollback..."
            required
          />
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setShowRollbackConfirm(false)}>Cancel</Button>
          <Button
            onClick={handleRollbackExecute}
            variant="contained"
            color="warning"
            disabled={!rollbackReason.trim()}
          >
            Confirm Rollback
          </Button>
        </DialogActions>
      </Dialog>

      {/* Health Monitor Dialog */}
      <Dialog open={showHealthMonitor} onClose={() => setShowHealthMonitor(false)} maxWidth="md" fullWidth>
        <DialogTitle>
          <Stack direction="row" alignItems="center" spacing={1}>
            <HealthIcon />
            <Typography variant="h6">Health Monitor</Typography>
          </Stack>
        </DialogTitle>
        <DialogContent>
          <Stack spacing={2}>
            <Box>
              <Typography variant="h6" sx={{ mb: 1 }}>Overall Status</Typography>
              <Chip
                label={healthMetrics.overall}
                color={healthMetrics.overall === 'HEALTHY' ? 'success' : 'warning'}
                size="medium"
              />
            </Box>

            <Box>
              <Typography variant="h6" sx={{ mb: 1 }}>Component Status</Typography>
              <Grid container spacing={2}>
                {Object.entries(healthMetrics.components).map(([component, status]: [string, any]) => (
                  <Grid item xs={12} sm={6} key={component}>
                    <Card variant="outlined">
                      <CardContent>
                        <Typography variant="subtitle1" sx={{ textTransform: 'capitalize' }}>
                          {component}
                        </Typography>
                        <Stack direction="row" alignItems="center" spacing={1} sx={{ mt: 1 }}>
                          <Chip
                            size="small"
                            label={status.status}
                            color={status.status === 'HEALTHY' ? 'success' : 'warning'}
                          />
                          {status.latency && (
                            <Typography variant="body2">Latency: {status.latency}ms</Typography>
                          )}
                          {status.uptime && (
                            <Typography variant="body2">Uptime: {status.uptime}%</Typography>
                          )}
                        </Stack>
                      </CardContent>
                    </Card>
                  </Grid>
                ))}
              </Grid>
            </Box>

            <Box>
              <Typography variant="h6" sx={{ mb: 1 }}>Recent Alerts</Typography>
              <List dense>
                {healthMetrics.alerts.map((alert, index) => (
                  <ListItem key={index}>
                    <ListItemText
                      primary={
                        <Stack direction="row" alignItems="center" spacing={1}>
                          {alert.level === 'WARNING' ? <WarningIcon color="warning" /> :
                           alert.level === 'ERROR' ? <ErrorIcon color="error" /> :
                           <InfoIcon color="info" />}
                          <Typography variant="body2">{alert.message}</Typography>
                        </Stack>
                      }
                      secondary={new Date(alert.time).toLocaleString()}
                    />
                  </ListItem>
                ))}
              </List>
            </Box>
          </Stack>
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setShowHealthMonitor(false)}>Close</Button>
        </DialogActions>
      </Dialog>

      {/* Scheduler Dialog */}
      <Dialog open={showScheduler} onClose={() => setShowScheduler(false)} maxWidth="lg" fullWidth>
        <DialogTitle>
          <Stack direction="row" alignItems="center" spacing={1}>
            <ScheduleIcon />
            <Typography variant="h6">Scheduled Upgrades</Typography>
          </Stack>
        </DialogTitle>
        <DialogContent>
          <TableContainer component={Paper}>
            <Table>
              <TableHead>
                <TableRow>
                  <TableCell>Version</TableCell>
                  <TableCell>Scheduled Time</TableCell>
                  <TableCell>Type</TableCell>
                  <TableCell>Tenants</TableCell>
                  <TableCell>Status</TableCell>
                  <TableCell>Created By</TableCell>
                  <TableCell>Actions</TableCell>
                </TableRow>
              </TableHead>
              <TableBody>
                {scheduledUpgrades.map((upgrade) => (
                  <TableRow key={upgrade.id}>
                    <TableCell>{upgrade.version}</TableCell>
                    <TableCell>{new Date(upgrade.scheduledTime).toLocaleString()}</TableCell>
                    <TableCell>{upgrade.type}</TableCell>
                    <TableCell>{upgrade.tenants.join(', ')}</TableCell>
                    <TableCell>
                      <Chip
                        size="small"
                        label={upgrade.status}
                        color={upgrade.status === 'APPROVED' ? 'success' : upgrade.status === 'PENDING' ? 'warning' : 'default'}
                      />
                    </TableCell>
                    <TableCell>{upgrade.createdBy}</TableCell>
                    <TableCell>
                      <Stack direction="row" spacing={1}>
                        <Button size="small" variant="outlined">Edit</Button>
                        <Button size="small" variant="outlined" color="error">Cancel</Button>
                      </Stack>
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </TableContainer>
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setShowScheduler(false)}>Close</Button>
          <Button variant="contained" startIcon={<ScheduleIcon />}>Schedule New Upgrade</Button>
        </DialogActions>
      </Dialog>

      {/* Approval Workflow Dialog */}
      <Dialog open={showApprovalWorkflow} onClose={() => setShowApprovalWorkflow(false)} maxWidth="lg" fullWidth>
        <DialogTitle>
          <Stack direction="row" alignItems="center" spacing={1}>
            <ApprovalIcon />
            <Typography variant="h6">Pending Approvals</Typography>
          </Stack>
        </DialogTitle>
        <DialogContent>
          <TableContainer component={Paper}>
            <Table>
              <TableHead>
                <TableRow>
                  <TableCell>Version</TableCell>
                  <TableCell>Type</TableCell>
                  <TableCell>Requested By</TableCell>
                  <TableCell>Requested At</TableCell>
                  <TableCell>Risk Level</TableCell>
                  <TableCell>Reviewers</TableCell>
                  <TableCell>Actions</TableCell>
                </TableRow>
              </TableHead>
              <TableBody>
                {pendingApprovals.map((approval) => (
                  <TableRow key={approval.id}>
                    <TableCell>{approval.version}</TableCell>
                    <TableCell>{approval.type}</TableCell>
                    <TableCell>{approval.requestedBy}</TableCell>
                    <TableCell>{new Date(approval.requestedAt).toLocaleString()}</TableCell>
                    <TableCell>
                      <Chip
                        size="small"
                        label={approval.riskLevel}
                        color={approval.riskLevel === 'HIGH' ? 'error' : approval.riskLevel === 'MEDIUM' ? 'warning' : 'success'}
                      />
                    </TableCell>
                    <TableCell>{approval.reviewers.join(', ')}</TableCell>
                    <TableCell>
                      <Stack direction="row" spacing={1}>
                        <Button size="small" variant="contained" color="success">Approve</Button>
                        <Button size="small" variant="outlined" color="error">Reject</Button>
                      </Stack>
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </TableContainer>
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setShowApprovalWorkflow(false)}>Close</Button>
        </DialogActions>
      </Dialog>

      {/* Progress Tracker Dialog */}
      <Dialog open={showProgressTracker} onClose={() => {}} maxWidth="sm" fullWidth>
        <DialogTitle>
          <Typography variant="h6">{currentOperation}</Typography>
        </DialogTitle>
        <DialogContent>
          <Stack spacing={2}>
            <LinearProgress variant="determinate" value={operationProgress} />
            <Typography variant="body2" color="text.secondary">
              {operationProgress}% complete
            </Typography>
          </Stack>
        </DialogContent>
      </Dialog>
    </Box>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Box,
  Grid,
  Card,
  CardContent,
  Typography,
  Chip,
  Button,
  Tabs,
  Tab,
  Paper,
  Alert,
  CircularProgress,
  IconButton,
  Tooltip
} from '@mui/material';
import {
  TrendingUp as TrendingUpIcon,
  Assessment as AssessmentIcon,
  AccountBalance as AccountBalanceIcon,
  PieChart as PieChartIcon,
  Timeline as TimelineIcon,
  ShowChart as ShowChartIcon,
  Calculate as CalculateIcon,
  Refresh as RefreshIcon,
  Info as InfoIcon,
  CheckCircle as CheckCircleIcon,
  Schedule as ScheduleIcon
} from '@mui/icons-material';
import { Divider } from '@mui/material';
import MetricDetailDialog from './components/MetricDetailDialog';
import { wealthManagementService, WealthManagementMetric } from '../../services/wealthManagementService';
import { devError } from '../../utils/devLogger';

interface WealthManagementDashboardProps {
  tenantId: string;
  clientId?: string;
}

const WealthManagementDashboard: React.FC<WealthManagementDashboardProps> = ({
  tenantId,
  clientId
}) => {
  const [activeTab, setActiveTab] = useState(0);
  const [metrics, setMetrics] = useState<WealthManagementMetric[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [lastRefresh, setLastRefresh] = useState<Date | null>(null);
  const [selectedMetric, setSelectedMetric] = useState<WealthManagementMetric | null>(null);
  const [detailDialogOpen, setDetailDialogOpen] = useState(false);

    const handleRefresh = () => {
    // Trigger refresh of metrics data
    const loadMetrics = async () => {
      try {
        setLoading(true);
        const data = await wealthManagementService.getMetrics(tenantId);
        setMetrics(data);
        setLastRefresh(new Date());
        setError(null);
      } catch (err) {
        setError('Failed to load wealth management metrics');
        devError('Error loading metrics:', err);
      } finally {
        setLoading(false);
      }
    };
    loadMetrics();
  };

  const handleViewDetails = (metric: WealthManagementMetric) => {
    setSelectedMetric(metric);
    setDetailDialogOpen(true);
  };

  const handleCloseDetailDialog = () => {
    setDetailDialogOpen(false);
    setSelectedMetric(null);
  };

  const getCategoryIcon = (category: string) => {
    switch (category) {
      case 'performance':
        return <TrendingUpIcon color="primary" />;
      case 'risk':
      case 'risk_adjusted_performance':
        return <AssessmentIcon color="warning" />;
      case 'composition':
        return <PieChartIcon color="success" />;
      case 'income':
        return <AccountBalanceIcon color="success" />;
      case 'client_kpi':
        return <TimelineIcon color="info" />;
      case 'business_efficiency':
        return <ShowChartIcon color="secondary" />;
      default:
        return <CalculateIcon />;
    }
  };

  const getCategoryColor = (category: string) => {
    switch (category) {
      case 'performance':
        return 'primary';
      case 'risk':
      case 'risk_adjusted_performance':
        return 'warning';
      case 'composition':
      case 'income':
        return 'success';
      case 'client_kpi':
        return 'info';
      case 'business_efficiency':
        return 'secondary';
      default:
        return 'default';
    }
  };

  const getGovernanceIcon = (status: string) => {
    return status === 'golden' ?
      <CheckCircleIcon color="success" fontSize="small" /> :
      <InfoIcon color="warning" fontSize="small" />;
  };

  const filteredMetrics = metrics.filter(metric => {
    if (activeTab === 0) return true; // All metrics
    if (activeTab === 1) return metric.governance_status === 'golden';
    if (activeTab === 2) return metric.category === 'performance' || metric.category === 'risk_adjusted_performance';
    if (activeTab === 3) return metric.category === 'client_kpi' || metric.category === 'business_efficiency';
    return false;
  });

  const categoryCounts = metrics.reduce((acc, metric) => {
    acc[metric.category] = (acc[metric.category] || 0) + 1;
    return acc;
  }, {} as Record<string, number>);

  if (loading) {
    return (
      <Box display="flex" justifyContent="center" alignItems="center" minHeight="400px">
        <CircularProgress />
        <Typography variant="h6" sx={{ ml: 2 }}>
          Loading Wealth Management Analytics...
        </Typography>
      </Box>
    );
  }

  if (error) {
    return (
      <Alert severity="error" sx={{ m: 2 }}>
        {error}
      </Alert>
    );
  }

  return (
    <Box sx={{ p: 3 }}>
      <Box display="flex" justifyContent="space-between" alignItems="center" mb={3}>
        <Box>
          <Typography variant="h4" component="h1" gutterBottom>
            Wealth Management Analytics
          </Typography>
          <Typography variant="body1" color="text.secondary">
            Advanced portfolio insights and business intelligence for wealth management
          </Typography>
          {lastRefresh && (
            <Typography variant="caption" color="text.secondary" sx={{ mt: 1, display: 'block' }}>
              Last updated: {lastRefresh.toLocaleString()}
            </Typography>
          )}
        </Box>
        <Button
          variant="outlined"
          startIcon={<RefreshIcon />}
          onClick={handleRefresh}
          size="small"
        >
          Refresh Data
        </Button>
      </Box>

      {/* Summary Cards */}
      <Grid container spacing={3} mb={3}>
        <Grid item xs={12} sm={6} md={3}>
          <Card>
            <CardContent>
              <Typography color="textSecondary" gutterBottom>
                Total Metrics
              </Typography>
              <Typography variant="h4">
                {metrics.length}
              </Typography>
            </CardContent>
          </Card>
        </Grid>
        <Grid item xs={12} sm={6} md={3}>
          <Card>
            <CardContent>
              <Typography color="textSecondary" gutterBottom>
                Golden Status
              </Typography>
              <Typography variant="h4" color="success.main">
                {metrics.filter(m => m.governance_status === 'golden').length}
              </Typography>
            </CardContent>
          </Card>
        </Grid>
        <Grid item xs={12} sm={6} md={3}>
          <Card>
            <CardContent>
              <Typography color="textSecondary" gutterBottom>
                Categories
              </Typography>
              <Typography variant="h4">
                {Object.keys(categoryCounts).length}
              </Typography>
            </CardContent>
          </Card>
        </Grid>
        <Grid item xs={12} sm={6} md={3}>
          <Card>
            <CardContent>
              <Typography color="textSecondary" gutterBottom>
                Auto-Refresh Enabled
              </Typography>
              <Typography variant="h4" color="primary.main">
                {metrics.filter(m => m.governance_status === 'golden').length}
              </Typography>
            </CardContent>
          </Card>
        </Grid>
      </Grid>

      {/* Tabs */}
      <Paper sx={{ mb: 3 }}>
        <Tabs
          value={activeTab}
          onChange={(_, newValue) => setActiveTab(newValue)}
          variant="fullWidth"
        >
          <Tab label={`All Metrics (${metrics.length})`} />
          <Tab label={`Golden (${metrics.filter(m => m.governance_status === 'golden').length})`} />
          <Tab label={`Performance & Risk (${metrics.filter(m => ['performance', 'risk', 'risk_adjusted_performance'].includes(m.category)).length})`} />
          <Tab label={`Business & Client (${metrics.filter(m => ['client_kpi', 'business_efficiency'].includes(m.category)).length})`} />
        </Tabs>
      </Paper>

      {/* Metrics List */}
      <Grid container spacing={3}>
        {filteredMetrics.map((metric) => (
          <Grid item xs={12} md={6} lg={4} key={metric.node_id}>
            <Card sx={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
              <CardContent sx={{ flexGrow: 1 }}>
                <Box display="flex" alignItems="center" mb={2}>
                  {getCategoryIcon(metric.category)}
                  <Typography variant="h6" sx={{ ml: 1, flexGrow: 1 }}>
                    {metric.node_id.replace(/_/g, ' ').replace(/\b\w/g, l => l.toUpperCase())}
                  </Typography>
                  <Box display="flex" alignItems="center">
                    {getGovernanceIcon(metric.governance_status)}
                    <Chip
                      label={metric.governance_status}
                      size="small"
                      color={metric.governance_status === 'golden' ? 'success' : 'warning'}
                      sx={{ ml: 1 }}
                    />
                  </Box>
                </Box>

                <Typography variant="body2" color="text.secondary" paragraph>
                  {metric.description}
                </Typography>

                <Box mb={2}>
                  <Chip
                    label={metric.category.replace(/_/g, ' ')}
                    size="small"
                    color={getCategoryColor(metric.category) as any}
                    sx={{ mr: 1, mb: 1 }}
                  />
                  <Chip
                    label={metric.formula_type}
                    size="small"
                    variant="outlined"
                    sx={{ mr: 1, mb: 1 }}
                  />
                </Box>

                <Box>
                  <Typography variant="caption" color="text.secondary">
                    Audience:
                  </Typography>
                  <Box sx={{ mt: 0.5 }}>
                    {metric.audience.map((audience) => (
                      <Chip
                        key={audience}
                        label={audience}
                        size="small"
                        variant="outlined"
                        sx={{ mr: 0.5, mb: 0.5 }}
                      />
                    ))}
                  </Box>
                </Box>
              </CardContent>

              <Divider />

              <Box p={2}>
                <Button
                  fullWidth
                  variant="outlined"
                  startIcon={<ShowChartIcon />}
                  onClick={() => handleViewDetails(metric)}
                  size="small"
                >
                  View Details
                </Button>
              </Box>
            </Card>
          </Grid>
        ))}
      </Grid>

      {filteredMetrics.length === 0 && (
        <Box textAlign="center" py={6}>
          <Typography variant="h6" color="text.secondary">
            No metrics found for the selected filter.
          </Typography>
        </Box>
      )}

      {/* Metric Detail Dialog */}
      <MetricDetailDialog
        open={detailDialogOpen}
        onClose={handleCloseDetailDialog}
        metric={selectedMetric}
      />
    </Box>
  );
};

export default WealthManagementDashboard;

import React, { useState } from 'react';
import {
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  Button,
  Typography,
  Box,
  Chip,
  Grid,
  Paper,
  List,
  ListItem,
  ListItemText,
  ListItemIcon,
  Divider,
  Alert,
  IconButton,
  Tooltip
} from '@mui/material';
import {
  TrendingUp as TrendingUpIcon,
  Assessment as AssessmentIcon,
  AccountBalance as AccountBalanceIcon,
  PieChart as PieChartIcon,
  Timeline as TimelineIcon,
  ShowChart as ShowChartIcon,
  Calculate as CalculateIcon,
  Schedule as ScheduleIcon,
  CheckCircle as CheckCircleIcon,
  Info as InfoIcon,
  Code as CodeIcon,
  Close as CloseIcon
} from '@mui/icons-material';

interface WealthManagementMetric {
  node_id: string;
  category: string;
  description: string;
  governance_status: 'golden' | 'draft';
  formula_type: string;
  formula?: string;
  arguments?: Record<string, string>;
  audience: string[];
  tags: string[];
  created_at?: string;
  updated_at?: string;
}

interface MetricDetailDialogProps {
  open: boolean;
  onClose: () => void;
  metric: WealthManagementMetric | null;
}

const MetricDetailDialog: React.FC<MetricDetailDialogProps> = ({
  open,
  onClose,
  metric
}) => {
  if (!metric) return null;

  const getCategoryIcon = (category: string) => {
    switch (category) {
      case 'performance':
        return <TrendingUpIcon color="primary" />;
      case 'risk':
      case 'risk_adjusted_performance':
        return <AssessmentIcon color="warning" />;
      case 'composition':
        return <PieChartIcon color="success" />;
      case 'income':
        return <AccountBalanceIcon color="success" />;
      case 'client_kpi':
        return <TimelineIcon color="info" />;
      case 'business_efficiency':
        return <ShowChartIcon color="secondary" />;
      default:
        return <CalculateIcon />;
    }
  };

  const getGovernanceIcon = (status: string) => {
    return status === 'golden' ?
      <CheckCircleIcon color="success" /> :
      <InfoIcon color="warning" />;
  };

  const getGovernanceDescription = (status: string) => {
    return status === 'golden'
      ? 'This metric has been reviewed and approved for production use. It follows governance standards and is actively monitored.'
      : 'This metric is in draft status and requires governance review before production use.';
  };

  return (
    <Dialog
      open={open}
      onClose={onClose}
      maxWidth="md"
      fullWidth
      PaperProps={{
        sx: { minHeight: '600px' }
      }}
    >
      <DialogTitle sx={{ pb: 1 }}>
        <Box display="flex" alignItems="center" justifyContent="space-between">
          <Box display="flex" alignItems="center">
            {getCategoryIcon(metric.category)}
            <Typography variant="h6" sx={{ ml: 1 }}>
              {metric.node_id.replace(/_/g, ' ').replace(/\b\w/g, l => l.toUpperCase())}
            </Typography>
          </Box>
          <IconButton onClick={onClose} size="small">
            <CloseIcon />
          </IconButton>
        </Box>
      </DialogTitle>

      <DialogContent dividers>
        <Grid container spacing={3}>
          {/* Basic Information */}
          <Grid item xs={12}>
            <Typography variant="body1" paragraph>
              {metric.description}
            </Typography>
          </Grid>

          {/* Status and Category */}
          <Grid item xs={12} md={6}>
            <Paper sx={{ p: 2 }}>
              <Typography variant="h6" gutterBottom>
                Status & Category
              </Typography>
              <Box display="flex" alignItems="center" mb={2}>
                {getGovernanceIcon(metric.governance_status)}
                <Chip
                  label={metric.governance_status.toUpperCase()}
                  color={metric.governance_status === 'golden' ? 'success' : 'warning'}
                  sx={{ ml: 1 }}
                />
              </Box>
              <Typography variant="body2" color="text.secondary" paragraph>
                {getGovernanceDescription(metric.governance_status)}
              </Typography>
              <Chip
                label={metric.category.replace(/_/g, ' ').toUpperCase()}
                color="primary"
                variant="outlined"
              />
            </Paper>
          </Grid>

          {/* Technical Details */}
          <Grid item xs={12} md={6}>
            <Paper sx={{ p: 2 }}>
              <Typography variant="h6" gutterBottom>
                Technical Details
              </Typography>
              <List dense>
                <ListItem>
                  <ListItemIcon>
                    <CodeIcon />
                  </ListItemIcon>
                  <ListItemText
                    primary="Formula Type"
                    secondary={metric.formula_type}
                  />
                </ListItem>
                <ListItem>
                  <ListItemIcon>
                    <ScheduleIcon />
                  </ListItemIcon>
                  <ListItemText
                    primary="Auto-Refresh"
                    secondary={metric.governance_status === 'golden' ? 'Enabled' : 'Pending Approval'}
                  />
                </ListItem>
              </List>
            </Paper>
          </Grid>

          {/* Formula (if available) */}
          {metric.formula && (
            <Grid item xs={12}>
              <Paper sx={{ p: 2 }}>
                <Typography variant="h6" gutterBottom>
                  Calculation Formula
                </Typography>
                <Box
                  sx={{
                    bgcolor: 'grey.100',
                    p: 2,
                    borderRadius: 1,
                    fontFamily: 'monospace',
                    fontSize: '0.875rem'
                  }}
                >
                  {metric.formula}
                </Box>
                {metric.arguments && Object.keys(metric.arguments).length > 0 && (
                  <Box mt={2}>
                    <Typography variant="subtitle2" gutterBottom>
                      Arguments:
                    </Typography>
                    <List dense>
                      {Object.entries(metric.arguments).map(([key, value]) => (
                        <ListItem key={key}>
                          <ListItemText
                            primary={key}
                            secondary={value}
                          />
                        </ListItem>
                      ))}
                    </List>
                  </Box>
                )}
              </Paper>
            </Grid>
          )}

          {/* Audience and Tags */}
          <Grid item xs={12} md={6}>
            <Paper sx={{ p: 2 }}>
              <Typography variant="h6" gutterBottom>
                Target Audience
              </Typography>
              <Box>
                {metric.audience.map((audience) => (
                  <Chip
                    key={audience}
                    label={audience.charAt(0).toUpperCase() + audience.slice(1)}
                    size="small"
                    color="primary"
                    sx={{ mr: 1, mb: 1 }}
                  />
                ))}
              </Box>
            </Paper>
          </Grid>

          <Grid item xs={12} md={6}>
            <Paper sx={{ p: 2 }}>
              <Typography variant="h6" gutterBottom>
                Tags
              </Typography>
              <Box>
                {metric.tags.map((tag) => (
                  <Chip
                    key={tag}
                    label={tag.replace(/_/g, ' ')}
                    size="small"
                    variant="outlined"
                    sx={{ mr: 1, mb: 1 }}
                  />
                ))}
              </Box>
            </Paper>
          </Grid>

          {/* Usage Information */}
          <Grid item xs={12}>
            <Alert severity="info">
              <Typography variant="body2">
                <strong>Usage:</strong> This metric is available in the semantic layer and can be used in dashboards,
                reports, and analytical queries. {metric.governance_status === 'golden'
                  ? 'It is automatically refreshed according to the configured schedule.'
                  : 'It requires governance approval before automated refresh can be enabled.'}
              </Typography>
            </Alert>
          </Grid>
        </Grid>
      </DialogContent>

      <DialogActions>
        <Button onClick={onClose}>Close</Button>
        <Button
          variant="contained"
          color="primary"
          disabled={metric.governance_status !== 'golden'}
        >
          Add to Dashboard
        </Button>
      </DialogActions>
    </Dialog>
  );
};

export default MetricDetailDialog;

import { useState, useCallback } from 'react';

interface Params {
  selectedModel: any | null;
  modelName: string;
  semanticModel: any;
  createCustomModel: (modelKey: string) => Promise<any>;
  updateModel: (id: string, payload: any) => Promise<any>;
  setSemanticModel: (m: any) => void;
  setModelName: (name: string) => void;
  showNotification: (msg: string, level?: 'success' | 'error') => void;
}
// align showNotification with unified hook signatures (level is 'success' | 'error')

const useModelSaver = ({ selectedModel, modelName, semanticModel, createCustomModel, updateModel, setSemanticModel, setModelName, showNotification }: Params) => {
  const [isSaving, setIsSaving] = useState(false);

  const handleSave = useCallback(async () => {
    if (!selectedModel) {
      showNotification('No Model Selected. Please select a model from the catalog before saving.', 'error');
      return;
    }
    setIsSaving(true);
    try {
      const resolvedConfig = semanticModel; // caller may pass precomputed resolved object

      const updatePayload = {
        title: modelName,
        description: (semanticModel as any).description || '',
        resolved_config: resolvedConfig,
      };

      if (selectedModel.is_custom) {
        await updateModel(selectedModel.id ?? '', updatePayload);
        showNotification('✅ Custom model saved successfully!', 'success');
      } else if (selectedModel.is_core) {
        try {
          const safeModelId = selectedModel?.id || '';
          const safeModelKey = selectedModel?.model_key || '';

          await updateModel(safeModelId, updatePayload);
          const customModel = await createCustomModel(safeModelKey) as any;
          if (customModel) {
            await updateModel(customModel.id, updatePayload);
            showNotification('✅ Custom model created and saved successfully!', 'success');
          }
        } catch (e) {
          showNotification('❌ Failed to create custom model', 'error');
        }
      }
    } catch (e) {
      showNotification(`❌ Save failed: ${e instanceof Error ? e.message : 'Unknown error'}`, 'error');
    } finally {
      setIsSaving(false);
    }
  }, [selectedModel, modelName, semanticModel, createCustomModel, updateModel, showNotification]);

  return { isSaving, handleSave };
};

export default useModelSaver;

// src/hooks/useUnifiedSemanticBuilder.tsx
import { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { useQuery, useMutation } from '@apollo/client';
import { Node as FlowNode } from 'reactflow';
import pako from 'pako';
import { 
  GET_ERD_CHART, 
  GET_ALL_BUSINESS_DATA 
} from '../graphql/queries/datasourceQueries.ts';
import { 
  CREATE_DRAFT, 
  UPDATE_DRAFT 
} from '../graphql/mutations/fabric_mutations.ts';
import { 
  ColumnMapping, 
  SemanticElement, 
  SemanticModel, 
  BusinessTerm, 
  CollapsedTables as _CollapsedTables, 
  ShowCode, 
  SelectedColumn,
  SemanticTerm as SemanticTermType, // Rename import to avoid conflict
  SemanticView,
  BusinessEdge
} from './../components/UnifiedSemanticBuilder/types.ts';
import { devLog } from '../utils/devLogger';

// Utility function to decompress hex string
function hexToUint8Array(hexString: string): Uint8Array {
  import('../utils/devLogger').then(m => m.devLog('hexString', hexString));
  if (hexString.startsWith('\\x')) {
    hexString = hexString.substring(2);
  }
  const bytes = new Uint8Array(hexString.length / 2);
  for (let i = 0; i < bytes.length; i++) {
    bytes[i] = parseInt(hexString.substr(i * 2, 2), 16);
  }
  return bytes;
}

export const useUnifiedSemanticBuilder = (datasourceId: string) => {
  const [nodes, setNodes] = useState<FlowNode[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedColumn, setSelectedColumn] = useState<SelectedColumn | null>(null);
  const [modelName, setModelName] = useState('semantic_model');
  // showCode controls the code panel format or hidden state (null).
  // Use a raw state setter and expose a normalized setter below so callers
  // that accidentally toggle a boolean (prev => !prev) or pass a boolean
  // still behave sensibly.
  const [showCode, rawSetShowCode] = useState<ShowCode>('json'); // Default to json
  // Track last non-null format so reopening preserves YAML if user selected it.
  const lastFormatRef = useRef<'json' | 'yaml'>('json');
  useEffect(() => {
    if (showCode === 'json' || showCode === 'yaml') {
      lastFormatRef.current = showCode;
    }
  }, [showCode]);

  // Normalized setter: accept ShowCode | boolean | updater and map to 'json' | 'yaml' | null
  const setShowCode = useCallback((value: ShowCode | boolean | ((prev: ShowCode) => ShowCode | boolean)) => {
    try {
      if (typeof value === 'function') {
        const res = (value as (prev: ShowCode) => ShowCode | boolean)(showCode);
        if (res === 'json' || res === 'yaml' || res === null) {
          rawSetShowCode(res as ShowCode);
        } else if (typeof res === 'boolean') {
          // boolean true => show (restore previous or default to json), false => hide (null)
          if (res) {
            rawSetShowCode(prev => (prev === null ? lastFormatRef.current : prev) as ShowCode);
          } else {
            rawSetShowCode(null);
          }
        } else {
          // fallback: set json
          rawSetShowCode('json');
        }
      } else {
        const res = value;
        if (res === 'json' || res === 'yaml' || res === null) {
          rawSetShowCode(res as ShowCode);
        } else if (typeof res === 'boolean') {
          if (res) {
            rawSetShowCode(prev => (prev === null ? lastFormatRef.current : prev) as ShowCode);
          } else {
            rawSetShowCode(null);
          }
        } else {
          rawSetShowCode('json');
        }
      }
    } catch (e) {
      // ensure we never leave showCode in an unexpected state
      rawSetShowCode('json');
    }
  }, [showCode]);


  // Business terms state
  const [businessTerms, setBusinessTerms] = useState<BusinessTerm[]>([]);
  const [semanticTerms, setSemanticTerms] = useState<SemanticTermType[]>([]);
  const [semanticViews, setSemanticViews] = useState<SemanticView[]>([]);
  const [columnToBusinessTerm, setColumnToBusinessTerm] = useState<Map<string, BusinessTerm>>(new Map());

  // Semantic model state
  const [semanticModel, setSemanticModel] = useState<SemanticModel>({
    name: 'semantic_model',
    dimensions: [],
    measures: [],
    filters: [],
    joins: []
  });

  // Debug log for semantic model changes
  useEffect(() => {
    devLog('Semantic model updated:', semanticModel);
  }, [semanticModel]);

  // Column mappings for visual indicators
  const [columnMappings, setColumnMappings] = useState<Map<string, ColumnMapping>>(new Map());

  // Query for ERD chart data
  const { loading: chartLoading, error: chartError, data: chartData } = useQuery(GET_ERD_CHART, {
    variables: { datasourceId },
  });

  // Query for business terms data
  const { loading: businessLoading, error: businessError, data: businessData } = useQuery(GET_ALL_BUSINESS_DATA, {
    variables: { datasourceId },
  });

  // Process business data
  useEffect(() => {
    if (businessData) {
      const { business_terms, semantic_terms, semantic_views, business_edges } = businessData;
      setBusinessTerms(business_terms || []);
      setSemanticTerms(semantic_terms || []);
      setSemanticViews(semantic_views || []);

      const newColumnToBusinessTerm = new Map<string, BusinessTerm>();
      if (business_edges && business_terms && semantic_terms && semantic_views) {
        const semanticTermMap = new Map<string, SemanticTermType>(semantic_terms.map((st: SemanticTermType) => [st.id, st]));
        const businessTermMap = new Map<string, BusinessTerm>(business_terms.map((bt: BusinessTerm) => [bt.id, bt]));

        business_edges.forEach((edge: BusinessEdge) => {
          if (edge.relationship_type === 'SemanticViewToColumn') {
            const semanticViewId = edge.source_node_id;

            const semanticToViewEdge = (business_edges as BusinessEdge[]).find(
              (e: BusinessEdge) => e.target_node_id === semanticViewId && e.relationship_type === 'SemanticToView'
            );

            if (semanticToViewEdge) {
              const semanticTermId = semanticToViewEdge.source_node_id;
              const semanticTerm = semanticTermMap.get(semanticTermId);

              if (semanticTerm && semanticTerm.parent_id) {
                const businessTerm = businessTermMap.get(semanticTerm.parent_id);
                if (businessTerm && edge.properties && edge.properties.schema && edge.properties.table && edge.properties.column) {
                  const columnKey = `${edge.properties.schema}.${edge.properties.table}.${edge.properties.column}`;
                  newColumnToBusinessTerm.set(columnKey, businessTerm);
                }
              }
            }
          }
        });
      }
      setColumnToBusinessTerm(newColumnToBusinessTerm);
    }
  }, [businessData]);

  // Update model name in semantic model when changed
  useEffect(() => {
    setSemanticModel(prev => ({ ...prev, name: modelName }));
  }, [modelName]);

  const getColumnKey = (nodeId: string, columnName: string) => `${nodeId}:${columnName}`;

  const getColumnMapping = (nodeId: string, columnName: string): ColumnMapping | null => {
    return columnMappings.get(getColumnKey(nodeId, columnName)) || null;
  };

  const getBusinessTermForColumn = (nodeId: string, columnName: string): BusinessTerm | undefined => {
    const node = nodes.find(n => n.id === nodeId);
    if (!node || !node.data || !node.data.label) return undefined;

    const tableName = node.data.label; // This is likely schema.table
    const key = `${tableName}.${columnName}`;
    return columnToBusinessTerm.get(key);
  };

  const getMappingColor = (mappingType: 'dimension' | 'measure' | 'filter' | null): string => {
    if (!mappingType) return 'transparent';
    const colors = {
      dimension: '#3b82f6', // blue-500
      measure: '#10b981',   // emerald-500
      filter: '#f97316',    // orange-500
    };
    return colors[mappingType] || 'transparent';
  };

  const getColumnSemanticType = (dbType: string) => {
    if (dbType.includes('int') || dbType.includes('serial')) return 'number';
    if (dbType.includes('float') || dbType.includes('decimal') || dbType.includes('numeric')) return 'number';
    if (dbType.includes('date') || dbType.includes('timestamp')) return 'time';
    if (dbType.includes('bool')) return 'boolean';
    return 'string';
  };

  const formatTitle = (text: string) => {
    return text.replace(/_/g, ' ').replace(/\b\w/g, l => l.toUpperCase());
  };

  // Mutations for semantic layer
  const [createDraft] = useMutation(CREATE_DRAFT);
  const [updateDraft] = useMutation(UPDATE_DRAFT);

  useEffect(() => {
    if (chartData && chartData.tenant_chart && chartData.tenant_chart.length > 0) {
      const compressedChartAsHex = chartData.tenant_chart[0].chart;
      const bytes = hexToUint8Array(compressedChartAsHex);
      try {
        const decompressed = pako.ungzip(bytes, { to: 'string' });
        const parsedChartData = JSON.parse(decompressed);
        setNodes(parsedChartData.nodes || []);
      } catch (error) {
        import('../utils/devLogger').then(m => m.devError('Failed to decompress or parse chart data:', error)).catch(() => {});
      }
    }
  }, [chartData]);

  // Helper functions
  const isNumericType = (type: string) => {
    return type.includes('int') || type.includes('float') || type.includes('decimal') || type.includes('numeric');
  };

  const showNotification = (message: string, type: 'success' | 'error' = 'success') => {
    // This function is now correctly handled by the toast in the component.
  };

  // Add semantic element functions
  const addDimension = (tableName: string, column: any) => {
    const businessTerm = getBusinessTermForColumn(selectedColumn!.nodeId, column.name);
    const semanticTerm = businessTerm ? semanticTerms.find(st => st.parent_id === businessTerm.id) : undefined;
    const semanticView = semanticTerm ? semanticViews.find(sv => sv.parent_id === semanticTerm.id) : undefined;

    const newDimension: SemanticElement = {
      id: `dim_${tableName}_${column.name}_${Date.now()}`,
      name: semanticTerm?.node_name || businessTerm?.node_name || `${tableName}_${column.name}`,
      type: getColumnSemanticType(column.type),
      sql: `{CUBE}.${column.name}`,
      title: formatTitle(semanticView?.node_name || semanticTerm?.node_name || businessTerm?.node_name || `${tableName} ${column.name}`),
      description: semanticView?.description || semanticTerm?.description || businessTerm?.description || column.description || `Dimension for ${column.name}`,
      sourceTable: tableName,
      sourceColumn: column.name,
    };

    setSemanticModel(prev => ({
      ...prev,
      dimensions: [...prev.dimensions, newDimension]
    }));

    // Update column mapping
    const key = getColumnKey(selectedColumn!.nodeId, column.name);
    setColumnMappings(prev => new Map(prev.set(key, {
      nodeId: selectedColumn!.nodeId,
      tableName,
      columnName: column.name,
      columnType: column.type,
      mappingType: 'dimension',
      mappingId: newDimension.id
    })));

    showNotification(`Added dimension: ${newDimension.title}`);
  };

  const addMeasure = (tableName: string, column: any) => {
    if (!isNumericType(column.type)) {
      showNotification('Measures can only be created from numeric columns', 'error');
      return;
    }

    const businessTerm = getBusinessTermForColumn(selectedColumn!.nodeId, column.name);
    const semanticTerm = businessTerm ? semanticTerms.find(st => st.parent_id === businessTerm.id) : undefined;
    const semanticView = semanticTerm ? semanticViews.find(sv => sv.parent_id === semanticTerm.id) : undefined;

    const newMeasure: SemanticElement = {
      id: `measure_${tableName}_${column.name}_${Date.now()}`,
      name: `${semanticTerm?.node_name || businessTerm?.node_name || `${tableName}_${column.name}`}_sum`,
      type: 'sum',
      sql: `{CUBE}.${column.name}`,
      title: formatTitle(`Total ${semanticView?.node_name || semanticTerm?.node_name || businessTerm?.node_name || `${tableName} ${column.name}`}`),
      description: semanticView?.description || semanticTerm?.description || businessTerm?.description || column.description || `Sum of ${column.name}`,
      sourceTable: tableName,
      sourceColumn: column.name,
    };

    setSemanticModel(prev => ({
      ...prev,
      measures: [...prev.measures, newMeasure]
    }));

    // Update column mapping
    const key = getColumnKey(selectedColumn!.nodeId, column.name);
    setColumnMappings(prev => new Map(prev.set(key, {
      nodeId: selectedColumn!.nodeId,
      tableName,
      columnName: column.name,
      columnType: column.type,
      mappingType: 'measure',
      mappingId: newMeasure.id
    })));

    showNotification(`Added measure: ${newMeasure.title}`);
  };

  const addFilter = (tableName: string, column: any) => {
    const businessTerm = getBusinessTermForColumn(selectedColumn!.nodeId, column.name);
    const semanticTerm = businessTerm ? semanticTerms.find(st => st.parent_id === businessTerm.id) : undefined;
    const semanticView = semanticTerm ? semanticViews.find(sv => sv.parent_id === semanticTerm.id) : undefined;

    const newFilter: SemanticElement = {
      id: `filter_${tableName}_${column.name}_${Date.now()}`,
      name: `${semanticTerm?.node_name || businessTerm?.node_name || `${tableName}_${column.name}`}_filter`,
      type: 'string',
      sql: `{CUBE}.${column.name}`,
      title: formatTitle(`${semanticView?.node_name || semanticTerm?.node_name || businessTerm?.node_name || `${tableName} ${column.name}`} Filter`),
      description: semanticView?.description || semanticTerm?.description || businessTerm?.description || column.description || `Filter for ${column.name}`,
      sourceTable: tableName,
      sourceColumn: column.name,
    };

    setSemanticModel(prev => ({
      ...prev,
      filters: [...prev.filters, newFilter]
    }));

    // Update column mapping
    const key = getColumnKey(selectedColumn!.nodeId, column.name);
    setColumnMappings(prev => new Map(prev.set(key, {
      nodeId: selectedColumn!.nodeId,
      tableName,
      columnName: column.name,
      columnType: column.type,
      mappingType: 'filter',
      mappingId: newFilter.id
    })));

    showNotification(`Added filter: ${newFilter.title}`);
  };

  const removeSemanticElement = (type: 'dimensions' | 'measures' | 'filters' | 'joins', id: string) => {
    setSemanticModel(prev => ({
      ...prev,
      [type]: prev[type].filter(item => item.id !== id)
    }));

    // Remove column mapping (only for dimensions/measures/filters, not joins)
    if (type !== 'joins') {
      const mappingToRemove = Array.from(columnMappings.entries())
        .find(([_, mapping]) => mapping.mappingId === id);

      if (mappingToRemove) {
        setColumnMappings(prev => {
          const newMap = new Map(prev);
          newMap.delete(mappingToRemove[0]);
          return newMap;
        });
      }
    }

    showNotification('Removed semantic element');
  };

  const toggleElementEdit = (type: 'dimensions' | 'measures' | 'filters' | 'joins', id: string) => {
    setSemanticModel(prev => ({
      ...prev,
      [type]: prev[type].map(item => 
        item.id === id ? { ...item, isEditing: !item.isEditing } : item
      )
    }));
  };

  const updateSemanticElement = (type: 'dimensions' | 'measures' | 'filters' | 'joins', id: string, updates: any) => {
    setSemanticModel(prev => ({
      ...prev,
      [type]: prev[type].map(item => 
        item.id === id ? { ...item, ...updates } : item // Removed isEditing: false to keep edit open
      )
    }));
    // Do not close edit mode automatically
  };

  const saveSemanticModel = async () => {
    try {
      const modelData = {
        model_key: modelName,
        version: 1,
        title: `${modelName} Semantic Model`,
        description: `Semantic model for ${modelName}`,
        source_config: semanticModel,
        resolved_config: {
          ...semanticModel,
          generatedAt: new Date().toISOString(),
          datasourceId
        }
      };

      if (semanticModel.id) {
        // Update existing
        await updateDraft({
          variables: {
            id: semanticModel.id,
            patch: {
              title: modelData.title,
              description: modelData.description,
              source_config: modelData.source_config,
              resolved_config: modelData.resolved_config
            }
          }
        });
        showNotification('Semantic model updated successfully!');
      } else {
        // Create new
        const result = await createDraft({
          variables: {
            input: modelData
          }
        });

        const insertDefn = result.data?.insert_fabric_defn_one;
        if (insertDefn && insertDefn.id) {
          setSemanticModel(prev => ({
            ...prev,
            id: insertDefn.id
          }));
          showNotification('Semantic model saved successfully!');
        }
      }
    } catch (error) {
  import('../utils/devLogger').then(m => m.devError('Error saving semantic model:', error)).catch(() => {});
      showNotification('Error saving semantic model', 'error');
    }
  };

  // Generate JSON/YAML
  const generateJSON = useCallback(() => {
    return JSON.stringify(semanticModel, null, 2);
  }, [semanticModel]);

  const generateYAML = useCallback(() => {
    let yamlContent = `cube: ${semanticModel.name}
sql: |
  SELECT * FROM public.${semanticModel.name.toLowerCase()}

dimensions:
${semanticModel.dimensions.map(dim => `  ${dim.name}:
    sql: ${dim.sql}
    type: ${dim.type}
    title: "${dim.title}"
    description: "${dim.description}"${dim.format ? `
    format: "${dim.format}"` : ''}
`).join('\n')}

measures:
${semanticModel.measures.map(meas => `  ${meas.name}:
    sql: ${meas.sql}
    type: ${meas.type}
    title: "${meas.title}"
    description: "${meas.description}"
`).join('\n')}

segments:
${semanticModel.filters.map(fil => `  ${fil.name}:
    sql: ${fil.sql}
`).join('\n')}
`;
    return yamlContent;
  }, [semanticModel]);

  // Filter nodes based on search
  const filteredNodes = useMemo(() => {
    if (!searchTerm.trim()) return nodes;
    return nodes.filter(node =>
      node.data?.label?.toLowerCase().includes(searchTerm.toLowerCase()) ||
      node.data?.columns?.some((col: any) =>
        col.name.toLowerCase().includes(searchTerm.toLowerCase())
      )
    );
  }, [nodes, searchTerm]);

  return {
    nodes,
    searchTerm,
    setSearchTerm,
    selectedColumn,
    setSelectedColumn,
    modelName,
    setModelName,
    showCode,
    setShowCode,
    // collapsedTables,
    // toggleTableCollapse,
    businessTerms,
    semanticTerms,
    semanticViews,
    semanticModel,
    setSemanticModel,
    columnMappings,
    setColumnMappings,
    chartLoading,
    chartError,
    businessLoading,
    businessError,
    isNumericType,
    getColumnMapping,
    getMappingColor,
    getBusinessTermForColumn,
    addDimension,
    addMeasure,
    addFilter,
    removeSemanticElement,
    toggleElementEdit,
    updateSemanticElement,
    saveSemanticModel,
    generateJSON,
    generateYAML,
    filteredNodes,
    showNotification
  };
};

import React, { useEffect, useMemo, useState, useCallback } from 'react';
import usePaletteDrop from '../../hooks/usePaletteDrop';
import CatalogSidebarWrapper from '../../components/UnifiedSemanticBuilder/CatalogSidebarWrapper';
